SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ----------------------------
-- Table structure for config_info
-- ----------------------------
DROP TABLE IF EXISTS `config_info`;
CREATE TABLE `config_info`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `data_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'data_id',
  `group_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `content` longtext CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'content',
  `md5` varchar(32) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'md5',
  `gmt_create` datetime NOT NULL DEFAULT '2010-05-05 00:00:00' COMMENT '创建时间',
  `gmt_modified` datetime NOT NULL DEFAULT '2010-05-05 00:00:00' COMMENT '修改时间',
  `src_user` text CHARACTER SET utf8 COLLATE utf8_bin NULL COMMENT 'source user',
  `src_ip` varchar(20) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'source ip',
  `app_name` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `tenant_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT '' COMMENT '租户字段',
  `c_desc` varchar(256) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `c_use` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `effect` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `type` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `c_schema` text CHARACTER SET utf8 COLLATE utf8_bin NULL,
  `encrypted_data_key` text CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT '秘钥',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_configinfo_datagrouptenant`(`data_id` ASC, `group_id` ASC, `tenant_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 272 CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = 'config_info' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of config_info
-- ----------------------------
INSERT INTO `config_info` VALUES (1, 'aioveu-auth.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_oauth2_server?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n \nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\n# 微信小程序\nwx:\n  miniapp:\n    # appId: wx977b2949b7095b11\n    # appSecret: 4bf78af93a8ce49f2de5384ede86be63\n    appId: wxe510ad6d4d60bfa8\n    appSecret: 1839111563bcf001bae776543c31829f\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.auth.controller\n  # Api文档信息\n  info:\n    title: 认证服务\n    version: 3.0.0\n    description: 认证、登出、验证码接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n# 验证码配置\ncaptcha:\n  # 验证码类型 circle-圆圈干扰验证码|gif-Gif验证码|line-干扰线验证码|shear-扭曲干扰验证码\n  type: circle\n  # 验证码宽度\n  width: 120\n  # 验证码高度\n  height: 40\n  # 验证码干扰元素个数\n  interfere-count: 2\n  # 文本透明度(0.0-1.0)\n  text-alpha: 0.8\n  # 验证码字符配置\n  code:\n    # 验证码字符类型 math-算术|random-随机字符\n    type: math\n    # 验证码字符长度，type=算术时，表示运算位数(1:个位数运算 2:十位数运算)；type=随机字符时，表示字符个数\n    length: 1\n  # 验证码字体\n  font:\n    # 字体名称 Dialog|DialogInput|Monospaced|Serif|SansSerif\n    name: SansSerif\n    # 字体样式 0-普通|1-粗体|2-斜体\n    weight: 1\n    # 字体大小\n    size: 24\n  # 验证码有效期(秒)\n  expire-seconds: 120\n\nsecurity:\n  whitelist-paths:\n    - /api/v1/auth/captcha\n    - /api/v1/auth/sms_code', '73239b216fa2f743da4795d3c4aec1e9', '2025-06-09 23:21:33', '2026-03-08 10:41:46', 'nacos', '172.18.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (2, 'aioveu-common.yaml', 'AIOVEU_GROUP', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n          \n  data:\n    redis:\n      # database: ${redis.database}\n      # host: ${redis.host}\n      # port: ${redis.port}\n      # password: ${redis.password}\n      lettuce:\n        pool:\n          max-active: 8\n          max-idle: 5\n          min-idle: 2\n          max-wait: 1000ms\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: http://localhost:8848\n  namespace: public\n  group: SEATA_GROUP\n  application: aioveu-seata-server\n  data-id: seataServer.properties  # 使用短横线\n  username: aioveu\n  password: 775825\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n\nlogging:\n  level:\n    io.seata: DEBUG\n    com.alibaba.nacos: DEBUG\n    \n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000\n\n', '60d2e16738b4795f6af797fe8490b5db', '2025-06-09 23:21:33', '2026-03-09 14:31:01', 'aioveu', '172.18.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (3, 'aioveu-gateway.yaml', 'AIOVEU_GROUP', 'spring:\n  data:\n    redis:\n      timeout: PT30S\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      \n  cloud:\n    gateway:\n      discovery:\n        locator:\n          enabled: true # 启用服务发现\n          lower-case-service-id: true\n      default-filters:\n        # 令牌中继\n        - TokenRelay= \n      routes:\n        - id: 认证中心\n          uri: lb://aioveu-auth\n          predicates:\n            - Path=/aioveu-auth/**\n          filters:\n            - StripPrefix=1            \n        - id: 系统服务\n          uri: lb://aioveu-system\n          predicates:\n            - Path=/aioveu-system/**\n          filters:\n            - StripPrefix=1            \n      globalcors:\n        corsConfigurations:\n          \'[/**]\': # 对所有路由应用CORS配置\n            # 允许所有域名的请求\n            allowedOriginPatterns: \"*\"\n            # 允许所有请求方法，如GET、POST、PUT、DELETE等\n            allowedMethods: \"*\"\n             # 允许所有请求头\n            allowedHeaders: \"*\" \n            # 允许凭证，如Cookies和HTTP认证\n            allowCredentials: true   \n            maxAge: 3600\n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n\n# 安全配置\nsecurity:\n  # 访问黑名单\n  blacklist-paths:\n      # 获取用户认证信息\n      - /aioveu-system/api/v1/users/{username}/authInfo\n      - /aioveu-lss/api/v1/users/{username}/UserAuthCredentials\n\n# knife4j 网关聚合  \n# https://doc.xiaominfo.com/docs/middleware-sources/spring-cloud-gateway/spring-gateway-introduction\nknife4j:\n  gateway:\n    enabled: true\n    # 指定服务发现的模式聚合微服务文档，并且是默认`default`分组\n    strategy: discover\n    discover:\n      enabled: true\n      # 聚合所有子服务(swagger2规范)，子服务是3规范则替换为openapi3\n      version: openapi3\n      # 需要排除的微服务(eg:网关服务) \n      excluded-services:\n          - aioveu-gateway\n\n', '9d64bc91598f0d36e243c50a72345edb', '2025-06-09 23:21:33', '2026-03-08 10:42:28', 'nacos', '172.18.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (4, 'aioveu-oms.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource: \n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_oms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: oms-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  # ✅ 只需要这个，告诉客户端属于哪个事务组\n  tx-service-group: default_tx_group\n  # ❌ 这个是 Seata SERVER 的配置，不是 Client 的！\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n  #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n\n  # 添加网络超时参数\n  client:\n    tm:\n      queryTimeout: 3000\n      connectTimeout: 5000\n    rm:\n      asynCommitBufferLimit: 5000\n# 不配置grouplist，使用注册中心获取\n#Seata服务器容器IP是172.19.0.4，但OMS运行在宿主机上，宿主机无法直接访问容器的私有IP（172.19.0.4）\n#应该使用宿主机IP或host.docker.internal进行连接\n#OMS服务尝试直接连接Docker内部IP 172.19.0.4:8091，而OMS在宿主机运行，无法访问Docker网络。同时出现连接超时异常\n\n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false\n\n# 安全配置\nsecurity:\n  # 白名单路径\n  whitelist-path:\n      - /app-api/v1/carts\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.oms.controller\n  # Api文档信息\n  info:\n    title: 订单服务\n    version: 3.0.0\n    description: 订单、购物车等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true\n\n# 模拟支付配置\npay:\n  mock:\n    enabled: true           # 启用模拟支付\n    auto-success: true      # 自动成功\n    delay: 1000             # 模拟延迟1秒\n    success-rate: 100       # 成功率100%\n\nwx:\n  pay:\n    # 必需配置\n    app-id: wxe510ad6d4d60bfa8      # 你的微信小程序AppId\n    mch-id: 1107195457               # 你的商户号\n    mch-key: dCzmYhzYcCEyRyiHp9Z9MTVMRYoSYwVj   # API密钥，32位\n    notify-url: https://aioveu.com/api/wxpay/notify\n    \n    # 可选配置\n    sign-type: MD5                   # 签名类型：MD5 或 RSA\n    sandbox-enabled: false           # 是否使用沙箱环境\n    \n    # 以下为可选证书配置（如果需要）\n    # key-path: classpath:/cert/apiclient_cert.p12\n    # private-key-path: classpath:/cert/apiclient_key.pem\n    # private-cert-path: classpath:/cert/apiclient_cert.pem\n    # api-v3-key: your-api-v3-key\n    # cert-serial-no: your-cert-serial-no\n    \n    # 兼容字段\n    # pay-notify-url: https://your-domain.com/api/wxpay/notify', 'bb95b9f6832ec38c2b4b6c9521ad8b82', '2025-06-09 23:21:33', '2026-03-08 18:33:32', 'aioveu', '172.18.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (5, 'aioveu-pms.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: pms-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群  方式2：配置在客户端本地\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n      # 可选：如果不需要自动发现，可以直接指定地址\n    # grouplist:\n    #   default: 127.0.0.1:8091\n# \n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application:aioveu-seata-server}\n      server-addr: ${nacos.server-addr}\n      namespace: public   #你的实际namespaceID  # ← 明确指定，不要用变量\n      group: SEATA_GROUP \n      username: nacos\n      password: nacos\n            # 可选，添加集群配置\n      cluster: default\n\n  #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: public   #你的实际namespaceID  # ← 明确指定，不要用变量\n      group: SEATA_GROUP\n      data-id: seataServer.properties\n      username: nacos\n      password: nacos\n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 商品服务\n    version: 3.0.0\n    description: 库存、分类、品牌、规格、参数等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', '2973fcf8ab09e430c871f7779d9ff27c', '2025-06-09 23:21:33', '2026-03-09 14:46:42', 'aioveu', '172.18.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (6, 'aioveu-sms.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_sms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\nmybatis-plus:\n  type-enums-package: com.aioveu.sms.common.enums\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: sms-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n  #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n      \n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n      - /app-api/v1/adverts/**\n      - /app-api/v1/sms-home-category/page\n      - /app-api/v1/sms-home-advert/page\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.sms.controller\n  # Api文档信息\n  info:\n    title: 营销服务\n    version: 3.0.0\n    description: 广告、优惠券等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', '1fd88f84d10252c1409eb1397a3e7a4f', '2025-06-09 23:21:33', '2026-03-08 11:50:15', 'aioveu', '172.18.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (7, 'aioveu-system.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_system?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: true\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: aliyun\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint\n    endpoint: http://localhost:9001\n    # 访问凭据\n    access-key: minioadmin\n    # 凭据密钥\n    secret-key: minioadmin\n    # 存储桶名称\n    bucket-name: default\n    # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    custom-domain:\n  # 阿里云OSS对象存储服务\n  aliyun:\n    # 服务Endpoint\n    endpoint: oss-cn-hangzhou.aliyuncs.com\n    # 访问凭据\n    access-key-id: your-access-key-id\n    # 凭据密钥\n    access-key-secret: your-access-key-secret\n    # 存储桶名称\n    bucket-name: default\n', '739151593ed4192513eacf21a01117a7', '2025-06-09 23:21:33', '2025-12-23 20:43:01', NULL, '172.18.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (8, 'aioveu-ums.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_ums?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: ums-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n    #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false\n\n# 安全配置\nsecurity:\n  # 白名单路径\n  whitelist-paths:\n      - /app-api/v1/members/openid/{openid}\n      - /app-api/v1/members/mobile/{mobile}\n      - /app-api/v1/members\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.ums.controller\n  # Api文档信息\n  info:\n    title: 会员服务\n    version: 3.0.0\n    description: 会员、地址等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能 # 设置为 true 表示开启增强功能\n  enable: true \n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', '3f65081de44c06baac9533b0b0e7380c', '2025-06-09 23:21:33', '2026-03-08 11:55:14', 'aioveu', '172.18.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (165, 'aioveu-lss', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_lss?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: aliyun\n  # MinIO 对象存储服务\n  # minio:\n  #   # 服务Endpoint  #minio:9000 \n  #   endpoint:  minio:9000\n  #   # 访问凭据\n  #   access-key: minioadminlss\n  #   # 凭据密钥\n  #   secret-key: minioadminlss\n  #   # 存储桶名称\n  #   bucket-name: aioveu\n  #   # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n  #   custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    tenant-id: 1001  # 添加到这里\n    # 服务Endpoint   # ❌ 错误：内网地址（只能在阿里云ECS内访问） oss-cn-shanghai-internal.aliyuncs.com\n    # ✅ 正确：公网地址\n    endpoint:  oss-cn-shanghai.aliyuncs.com\n    # 访问凭据\n    access-key-id: LTAI5tDVP4BURrY9VtAE66K2\n    # 凭据密钥\n    access-key-secret: cOpi8YlxjJKmxoPG7D8j2592fC2iSD\n    # 存储桶名称\n    bucket-name: aioveu\n    # 新增：加速域名配置  # 替换为您的实际加速域名\n    cdn-domain: cdn.aioveu.com \n    cdn-region: cn-shanghai \n', '7a5c8b8e5e9a5af408680b3908b30937', '2025-12-30 22:06:29', '2026-03-02 19:01:05', 'nacos', '172.18.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (186, 'aioveu-refund', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_refund?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: refund-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n  registry:\n    type: nacos\n    nacos:\n      application: aioveu-seata-server\n      server-addr: ${nacos.server-addr}\n      namespace:\n      group: SEATA_GROUP \n\n\n\n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 退款服务\n    version: 3.0.0\n    description: 退款等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: minio\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint\n    endpoint: http://localhost:9002 \n    # 访问凭据\n    access-key: minioadminlss\n    # 凭据密钥\n    secret-key: minioadminlss\n    # 存储桶名称\n    bucket-name: aioveu\n    # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    custom-domain:  http://localhost:9002\n  # 阿里云OSS对象存储服务\n  aliyun:\n    # 服务Endpoint\n    endpoint: oss-cn-hangzhou.aliyuncs.com\n    # 访问凭据\n    access-key-id: your-access-key-id\n    # 凭据密钥\n    access-key-secret: your-access-key-secret\n    # 存储桶名称\n    bucket-name: default\n', '1fdedd25e24c12ae22e9a47828346132', '2026-01-31 13:18:58', '2026-01-31 13:29:17', NULL, '172.18.0.1', '', '', '退款配置', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (191, 'aioveu-pay', 'AIOVEU_GROUP', 'spring:\r\n  datasource:\r\n    type: com.alibaba.druid.pool.DruidDataSource\r\n    driver-class-name: com.mysql.cj.jdbc.Driver \r\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pay?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\r\n    username: ${mysql.username}\r\n    password: ${mysql.password}\r\n  data:\r\n    redis:\r\n      database: ${redis.database}\r\n      host: ${redis.host}\r\n      port: ${redis.port}\r\n      password: ${redis.password}\r\n      lettuce:\r\n        pool:\r\n          min-idle: 1\r\n  # RabbitMQ 配置\r\n  rabbitmq:\r\n    host: ${rabbitmq.host}\r\n    port: ${rabbitmq.port}\r\n    username: ${rabbitmq.username}\r\n    password: ${rabbitmq.password}\r\n    virtual-host: /\r\n    listener:\r\n      simple:\r\n        acknowledge-mode: manual   \r\n  cache:\r\n    # 缓存类型 redis、none(不使用缓存) \r\n    type: redis\r\n    # 缓存时间(单位：ms)\r\n    redis:\r\n      time-to-live: 3600000\r\n      # 缓存null值，防止缓存穿透\r\n      cache-null-values: true\r\n  cloud:\r\n    sentinel:\r\n      enabled: false\r\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\r\n      transport:\r\n        client-ip: localhost\r\n        dashboard: localhost:8080\r\n      datasource:\r\n        # 限流规则，flow为key，随便定义\r\n        flow:\r\n          nacos:\r\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\r\n            dataId: ${spring.application.name}-flow-rules\r\n            groupId: SENTINEL_GROUP\r\n            data-type: json\r\n            rule-type: flow\r\n        # 降级规则\r\n        degrade:\r\n          nacos:\r\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\r\n            dataId: ${spring.application.name}-degrade-rules\r\n            groupId: SENTINEL_GROUP\r\n            data-type: json\r\n            rule-type: degrade\r\n                \r\nmybatis-plus:\r\n  configuration:\r\n    # 驼峰下划线转换\r\n    map-underscore-to-camel-case: true\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\r\n\r\n\r\n# Seata 配置\r\nseata: \r\n  # 开启 Seata\r\n  enabled: true\r\n  application-id: refund-service\r\n  # 事务分组名称\r\n  tx-service-group: default_tx_group\r\n  service:\r\n    # 事务分组映射，根据分组名称匹配到集群\r\n    vgroup-mapping:\r\n      # 事务分组名称：集群名称\r\n      default_tx_group: default\r\n  registry:\r\n    type: nacos\r\n    nacos:\r\n      application: aioveu-seata-server\r\n      server-addr: ${nacos.server-addr}\r\n      namespace:\r\n      group: SEATA_GROUP \r\n\r\n\r\n\r\n# feign 配置\r\nfeign:\r\n  httpclient:\r\n    enabled: true\r\n  okhttp:\r\n    enabled: false\r\n  sentinel:  # 开启feign对sentinel的支持\r\n    enabled: false \r\n\r\n# 安全配置\r\nsecurity:\r\n  # 允许无需认证的路径列表\r\n  whitelist-paths:\r\n    # 获取系统用户的认证信息用于账号密码判读\r\n    - /api/v1/users/{username}/authInfo\r\n    - /api/v1/users/{username}/UserAuthCredentials\r\n\r\n# springdoc-openapi项目配置\r\nspringdoc:\r\n  swagger-ui:\r\n    path: /swagger-ui.html\r\n    tags-sorter: alpha\r\n    operations-sorter: alpha\r\n  api-docs:\r\n    path: /v3/api-docs\r\n  group-configs:\r\n    - group: \'default\'\r\n      paths-to-match: \'/**\'\r\n      packages-to-scan: \r\n        - com.aioveu.system.controller\r\n        - com.aioveu.common.file.controller\r\n  # Api文档信息\r\n  info:\r\n    title: 支付服务\r\n    version: 3.0.0\r\n    description: 支付等接口\r\n    contact:\r\n      name: aioveu\r\n      url: https://www.aioveu.com\r\n      email: ambitiouschild@qq.com\r\n    license:\r\n      name: Apache 2.0\r\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\r\n\r\n# knife4j的增强配置，不需要增强可以不配\r\nknife4j:\r\n  enable: false\r\n  setting:\r\n    language: zh_cn\r\n\r\n\r\n\r\n# 文件存储\r\noss:\r\n  # OSS 类型 (目前支持aliyun、minio)\r\n  type: minio\r\n  # MinIO 对象存储服务\r\n  minio:\r\n    # 服务Endpoint\r\n    endpoint: http://localhost:9002 \r\n    # 访问凭据\r\n    access-key: minioadminlss\r\n    # 凭据密钥\r\n    secret-key: minioadminlss\r\n    # 存储桶名称\r\n    bucket-name: aioveu\r\n    # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\r\n    custom-domain:  http://localhost:9002\r\n  # 阿里云OSS对象存储服务\r\n  aliyun:\r\n    # 服务Endpoint\r\n    endpoint: oss-cn-hangzhou.aliyuncs.com\r\n    # 访问凭据\r\n    access-key-id: your-access-key-id\r\n    # 凭据密钥\r\n    access-key-secret: your-access-key-secret\r\n    # 存储桶名称\r\n    bucket-name: default\r\n', '3a0e14e492b752cee4de6db33f2845c2', '2026-02-02 17:50:18', '2026-02-02 17:50:18', NULL, '172.18.0.1', '', '', '支付微服务配置', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (208, 'aioveu-auth.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_oauth2_server?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n \nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\n# 微信小程序\nwx:\n  miniapp:\n    # appId: wx977b2949b7095b11\n    # appSecret: 4bf78af93a8ce49f2de5384ede86be63\n    appId: wxe510ad6d4d60bfa8\n    appSecret: 1839111563bcf001bae776543c31829f\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.auth.controller\n  # Api文档信息\n  info:\n    title: 认证服务\n    version: 3.0.0\n    description: 认证、登出、验证码接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n# 验证码配置\ncaptcha:\n  # 验证码类型 circle-圆圈干扰验证码|gif-Gif验证码|line-干扰线验证码|shear-扭曲干扰验证码\n  type: circle\n  # 验证码宽度\n  width: 120\n  # 验证码高度\n  height: 40\n  # 验证码干扰元素个数\n  interfere-count: 2\n  # 文本透明度(0.0-1.0)\n  text-alpha: 0.8\n  # 验证码字符配置\n  code:\n    # 验证码字符类型 math-算术|random-随机字符\n    type: math\n    # 验证码字符长度，type=算术时，表示运算位数(1:个位数运算 2:十位数运算)；type=随机字符时，表示字符个数\n    length: 1\n  # 验证码字体\n  font:\n    # 字体名称 Dialog|DialogInput|Monospaced|Serif|SansSerif\n    name: SansSerif\n    # 字体样式 0-普通|1-粗体|2-斜体\n    weight: 1\n    # 字体大小\n    size: 24\n  # 验证码有效期(秒)\n  expire-seconds: 120\n\nsecurity:\n  whitelist-paths:\n    - /api/v1/auth/captcha\n    - /api/v1/auth/sms_code\n# 安全配置\n  session:\n    type: jwt # 会话方式 jwt/redis-token\n    access-token-time-to-live: 7200 # 访问令牌 有效期(单位：秒)，默认 2 小时，-1 表示永不过期\n    refresh-token-time-to-live: 604800 # 刷新令牌有效期(单位：秒)，默认 7 天，-1 表示永不过期\n    jwt:\n      secret-key: SecretKey012345678901234567890123456789012345678901234567890123456789 # JWT密钥(HS256算法至少32字符)\n    redis-token:\n      allow-multi-login: true # 是否允许多设备登录', '2eaec28a4da384a273c9dd85acaa0ed1', '2026-02-03 21:05:30', '2026-03-15 16:56:47', 'nacos', '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (210, 'aioveu-gateway.yaml', 'AIOVEU_GROUP', 'spring:\n  data:\n    redis:\n      timeout: PT30S\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          # 连接池最小空闲连接数\n          min-idle: 1\n  cloud:\n    gateway:\n      discovery:\n        locator:\n          enabled: true # 启用服务发现\n          lower-case-service-id: true\n      default-filters:\n        # 令牌中继\n        - TokenRelay= \n      routes:\n        - id: 认证中心\n          uri: lb://aioveu-auth\n          predicates:\n            - Path=/aioveu-auth/**\n          filters:\n            - StripPrefix=1            \n        - id: 系统服务\n          uri: lb://aioveu-system\n          predicates:\n            - Path=/aioveu-system/**\n          filters:\n            - StripPrefix=1            \n      globalcors:\n        corsConfigurations:\n          \'[/**]\': # 对所有路由应用CORS配置\n            # 允许所有域名的请求\n            allowedOriginPatterns: \"*\"\n            # 允许所有请求方法，如GET、POST、PUT、DELETE等\n            allowedMethods: \"*\"\n             # 允许所有请求头\n            allowedHeaders: \"*\" \n            # 允许凭证，如Cookies和HTTP认证\n            allowCredentials: true   \n            maxAge: 3600\n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n\n# 安全配置\nsecurity:\n  # 访问黑名单\n  blacklist-paths:\n      # 获取用户认证信息\n      - /aioveu-system/api/v1/users/{username}/authInfo\n      - /aioveu-lss/api/v1/users/{username}/UserAuthCredentials\n\n# knife4j 网关聚合  \n# https://doc.xiaominfo.com/docs/middleware-sources/spring-cloud-gateway/spring-gateway-introduction\nknife4j:\n  gateway:\n    enabled: true\n    # 指定服务发现的模式聚合微服务文档，并且是默认`default`分组\n    strategy: discover\n    discover:\n      enabled: true\n      # 聚合所有子服务(swagger2规范)，子服务是3规范则替换为openapi3\n      version: openapi3\n      # 需要排除的微服务(eg:网关服务) \n      excluded-services:\n          - aioveu-gateway\n\n', 'aafcb9387d3ee7714c20fe3de5d17001', '2026-02-03 21:05:30', '2026-02-03 21:05:30', NULL, '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', NULL, NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (211, 'aioveu-lss.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_lss?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: aliyun\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint  #minio:9000 \n    # endpoint:  minio.aioveu.com \n    # # 访问凭据\n    # access-key: minioadminlss\n    # # 凭据密钥\n    # secret-key: minioadminlss\n    # # 存储桶名称\n    # bucket-name: aioveu\n    # # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    # custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    tenant-id: 1001  # 添加到这里\n    # 服务Endpoint\n    endpoint: oss-cn-shanghai.aliyuncs.com\n    # 访问凭据\n    access-key-id: LTAI5tDVP4BURrY9VtAE66K2\n    # 凭据密钥\n    access-key-secret: cOpi8YlxjJKmxoPG7D8j2592fC2iSD\n    # 存储桶名称\n    bucket-name: aioveu\n    # 新增：加速域名配置  # 替换为您的实际加速域名\n    cdn-domain: cdn.aioveu.com \n    cdn-region: cn-shanghai \n\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\nmail:\n  host: smtp.qq.com\n  port: 587  #465 # 或587\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\n  properties:\n    mail:\n      smtp:\n        auth: true\n        ssl: true   # 465端口必开\n        starttls:\n          enable: true    # 587端口必开\n  # 邮件发送者\n  from: ambitiouschild@qq.com', 'f16c060899410897013280437b197095', '2026-02-03 21:05:30', '2026-03-09 17:30:20', 'aioveu', '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (212, 'aioveu-oms.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource: \n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_oms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: oms-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n #   grouplist:\n #     default: host.docker.internal:8091  \n      # 使用特殊主机名  #理论上Seata客户端应该通过Nacos获取服务端地址。但是，\n      #如果配置了service.grouplist，则会直接使用该地址，而忽略注册中心。如果希望使用注册中心，可以不配置service.grouplist，而是让客户端从注册中心获取服务端地址。\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n    #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n\n  # 添加网络超时参数\n  client:\n    tm:\n      queryTimeout: 3000\n      connectTimeout: 5000\n    rm:\n      asynCommitBufferLimit: 5000\n# 不配置grouplist，使用注册中心获取\n#Seata服务器容器IP是172.19.0.4，但OMS运行在宿主机上，宿主机无法直接访问容器的私有IP（172.19.0.4）\n#应该使用宿主机IP或host.docker.internal进行连接\n#OMS服务尝试直接连接Docker内部IP 172.19.0.4:8091，而OMS在宿主机运行，无法访问Docker网络。同时出现连接超时异常\n\n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false\n\n# 安全配置\nsecurity:\n  # 白名单路径\n  whitelist-path:\n      - /app-api/v1/carts\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.oms.controller\n  # Api文档信息\n  info:\n    title: 订单服务\n    version: 3.0.0\n    description: 订单、购物车等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true\n\n# 模拟支付配置\npay:\n  mock:\n    enabled: true           # 启用模拟支付\n    auto-success: true      # 自动成功\n    delay: 1000             # 模拟延迟1秒\n    success-rate: 100       # 成功率100%\n\nwx:\n  pay:\n    # 必需配置\n    app-id: wx1234567890abcdef      # 你的微信小程序AppId\n    mch-id: 1230000109               # 你的商户号\n    mch-key: your-mch-key-32-chars   # API密钥，32位\n    notify-url: https://your-domain.com/api/wxpay/notify\n    \n    # 可选配置\n    sign-type: MD5                   # 签名类型：MD5 或 RSA\n    sandbox-enabled: false           # 是否使用沙箱环境\n    \n    # 以下为可选证书配置（如果需要）\n    # key-path: classpath:/cert/apiclient_cert.p12\n    # private-key-path: classpath:/cert/apiclient_key.pem\n    # private-cert-path: classpath:/cert/apiclient_cert.pem\n    # api-v3-key: your-api-v3-key\n    # cert-serial-no: your-cert-serial-no\n    \n    # 兼容字段\n    # pay-notify-url: https://your-domain.com/api/wxpay/notify', '079061e637841198d5db741e1dd88563', '2026-02-03 21:05:30', '2026-03-09 18:06:19', 'nacos', '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (213, 'aioveu-pay.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pay?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: refund-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n  #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n\n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 支付服务\n    version: 3.0.0\n    description: 支付等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: minio\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint\n    endpoint: http://localhost:9002 \n    # 访问凭据\n    access-key: minioadminlss\n    # 凭据密钥\n    secret-key: minioadminlss\n    # 存储桶名称\n    bucket-name: aioveu\n    # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    custom-domain:  http://localhost:9002\n  # 阿里云OSS对象存储服务\n  aliyun:\n    # 服务Endpoint\n    endpoint: oss-cn-hangzhou.aliyuncs.com\n    # 访问凭据\n    access-key-id: your-access-key-id\n    # 凭据密钥\n    access-key-secret: your-access-key-secret\n    # 存储桶名称\n    bucket-name: default\n', 'b9a4ab9270fa5760998fe7d66f0a2a36', '2026-02-03 21:05:30', '2026-03-09 22:39:55', 'nacos', '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (214, 'aioveu-pms.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: pms-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n\n    #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n  \n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 商品服务\n    version: 3.0.0\n    description: 库存、分类、品牌、规格、参数等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', '0e2114c7471cc0f6ff2ffe8f5b1e464d', '2026-02-03 21:05:30', '2026-03-09 22:40:39', 'nacos', '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (215, 'aioveu-refund.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_refund?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: refund-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n  registry:\n    type: nacos\n    nacos:\n      application: aioveu-seata-server\n      server-addr: ${nacos.server-addr}\n      namespace:\n      group: SEATA_GROUP \n\n\n\n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 退款服务\n    version: 3.0.0\n    description: 退款等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: minio\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint\n    endpoint: http://localhost:9002 \n    # 访问凭据\n    access-key: minioadminlss\n    # 凭据密钥\n    secret-key: minioadminlss\n    # 存储桶名称\n    bucket-name: aioveu\n    # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    custom-domain:  http://localhost:9002\n  # 阿里云OSS对象存储服务\n  aliyun:\n    # 服务Endpoint\n    endpoint: oss-cn-hangzhou.aliyuncs.com\n    # 访问凭据\n    access-key-id: your-access-key-id\n    # 凭据密钥\n    access-key-secret: your-access-key-secret\n    # 存储桶名称\n    bucket-name: default\n', '1fdedd25e24c12ae22e9a47828346132', '2026-02-03 21:05:30', '2026-02-03 21:05:30', NULL, '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', NULL, NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (216, 'aioveu-sms.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_sms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\nmybatis-plus:\n  type-enums-package: com.aioveu.sms.common.enums\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: sms-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n #   grouplist:\n #     default: host.docker.internal:8091  \n      # 使用特殊主机名  #理论上Seata客户端应该通过Nacos获取服务端地址。但是，\n      #如果配置了service.grouplist，则会直接使用该地址，而忽略注册中心。如果希望使用注册中心，可以不配置service.grouplist，而是让客户端从注册中心获取服务端地址。\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n    #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n      \n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n      - /app-api/v1/adverts/**\n      - /app-api/v1/sms-home-category/page\n      - /app-api/v1/sms-home-advert/page\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.sms.controller\n  # Api文档信息\n  info:\n    title: 营销服务\n    version: 3.0.0\n    description: 广告、优惠券等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', 'ff5a338c1f7bf045b1d36f68f012cb59', '2026-02-03 21:05:30', '2026-03-09 17:40:33', 'aioveu', '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (217, 'aioveu-system.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_system?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: true\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: aliyun\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint\n    endpoint: http://localhost:9001\n    # 访问凭据\n    access-key: minioadmin\n    # 凭据密钥\n    secret-key: minioadmin\n    # 存储桶名称\n    bucket-name: default\n    # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    custom-domain:\n  # 阿里云OSS对象存储服务\n  aliyun:\n    # 服务Endpoint\n    endpoint: oss-cn-hangzhou.aliyuncs.com\n    # 访问凭据\n    access-key-id: your-access-key-id\n    # 凭据密钥\n    access-key-secret: your-access-key-secret\n    # 存储桶名称\n    bucket-name: default\n', '739151593ed4192513eacf21a01117a7', '2026-02-03 21:05:30', '2026-02-03 21:05:30', NULL, '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', NULL, NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (218, 'aioveu-ums.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_ums?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: ums-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n    #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false\n\n# 安全配置\nsecurity:\n  # 白名单路径\n  whitelist-paths:\n      - /app-api/v1/members/openid/{openid}\n      - /app-api/v1/members/mobile/{mobile}\n      - /app-api/v1/members\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.ums.controller\n  # Api文档信息\n  info:\n    title: 会员服务\n    version: 3.0.0\n    description: 会员、地址等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能 # 设置为 true 表示开启增强功能\n  enable: true \n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', 'de865ae992cf3522f3e74a142059b66f', '2026-02-03 21:05:30', '2026-03-09 18:08:17', 'nacos', '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (219, 'seataServer.properties', 'SEATA_GROUP', '# 注册配置\n#seata.ip=192.168.1.5\n#seata.port=8091\n\n\n#For details about configuration items, see https://seata.io/zh-cn/docs/user/configurations.html\n#Transport configuration, for client and server\ntransport.type=TCP\ntransport.server=NIO\ntransport.heartbeat=true\ntransport.enableTmClientBatchSendRequest=false\ntransport.enableRmClientBatchSendRequest=true\ntransport.enableTcServerBatchSendResponse=false\ntransport.rpcRmRequestTimeout=30000\ntransport.rpcTmRequestTimeout=30000\ntransport.rpcTcRequestTimeout=30000\ntransport.threadFactory.bossThreadPrefix=NettyBoss\ntransport.threadFactory.workerThreadPrefix=NettyServerNIOWorker\ntransport.threadFactory.serverExecutorThreadPrefix=NettyServerBizHandler\ntransport.threadFactory.shareBossWorker=false\ntransport.threadFactory.clientSelectorThreadPrefix=NettyClientSelector\ntransport.threadFactory.clientSelectorThreadSize=1\ntransport.threadFactory.clientWorkerThreadPrefix=NettyClientWorkerThread\ntransport.threadFactory.bossThreadSize=1\ntransport.threadFactory.workerThreadSize=default\ntransport.shutdown.wait=3\ntransport.serialization=seata\ntransport.compressor=none\n\n#Transaction routing rules configuration, only for the client\nservice.vgroupMapping.default_tx_group=default\n#If you use a registry, you can ignore it\n#service.default.grouplist=aioveu-seata-server:8091\n#service.enableDegrade=false\n#service.disableGlobalTransaction=false\n\n#Transaction rule configuration, only for the client\nclient.rm.asyncCommitBufferLimit=10000\nclient.rm.lock.retryInterval=10\nclient.rm.lock.retryTimes=30\nclient.rm.lock.retryPolicyBranchRollbackOnConflict=true\nclient.rm.reportRetryCount=5\nclient.rm.tableMetaCheckEnable=true\nclient.rm.tableMetaCheckerInterval=60000\nclient.rm.sqlParserType=druid\nclient.rm.reportSuccessEnable=false\nclient.rm.sagaBranchRegisterEnable=false\nclient.rm.sagaJsonParser=fastjson\nclient.rm.tccActionInterceptorOrder=-2147482648\nclient.tm.commitRetryCount=5\nclient.tm.rollbackRetryCount=5\nclient.tm.defaultGlobalTransactionTimeout=60000\nclient.tm.degradeCheck=false\nclient.tm.degradeCheckAllowTimes=10\nclient.tm.degradeCheckPeriod=2000\nclient.tm.interceptorOrder=-2147482648\nclient.undo.dataValidation=true\nclient.undo.logSerialization=jackson\nclient.undo.onlyCareUpdateColumns=true\nserver.undo.logSaveDays=7\nserver.undo.logDeletePeriod=86400000\nclient.undo.logTable=undo_log\nclient.undo.compress.enable=true\nclient.undo.compress.type=zip\nclient.undo.compress.threshold=64k\n#For TCC transaction mode\ntcc.fence.logTableName=tcc_fence_log\ntcc.fence.cleanPeriod=1h\n\n#Log rule configuration, for client and server\nlog.exceptionRate=100\n\n#Transaction storage configuration, only for the server. The file, db, and redis configuration values are optional.\nstore.mode=db\nstore.lock.mode=db\nstore.session.mode=db\n#Used for password encryption\n#store.publicKey=\n\n#If `store.mode,store.lock.mode,store.session.mode` are not equal to `file`, you can remove the configuration block.\nstore.file.dir=file_store/data\nstore.file.maxBranchSessionSize=16384\nstore.file.maxGlobalSessionSize=512\nstore.file.fileWriteBufferCacheSize=16384\nstore.file.flushDiskMode=async\nstore.file.sessionReloadReadSize=100\n\nlock.db.lockValueMaxLength=256\nlock.db.rowKeyMaxLength=256\n\n#These configurations are required if the `store mode` is `db`. If `store.mode,store.lock.mode,store.session.mode` are not equal to `db`, you can remove the configuration block.\nstore.db.datasource=druid\nstore.db.dbType=mysql\nstore.db.driverClassName=com.mysql.cj.jdbc.Driver\nstore.db.url=jdbc:mysql://mysql:3306/aioveu_seata?useUnicode=true&rewriteBatchedStatements=true\nstore.db.user=root\nstore.db.password=775825\nstore.db.minConn=5\nstore.db.maxConn=30\nstore.db.globalTable=global_table\nstore.db.branchTable=branch_table\nstore.db.distributedLockTable=distributed_lock\nstore.db.queryLimit=100\nstore.db.lockTable=lock_table\nstore.db.maxWait=5000\n\n#These configurations are required if the `store mode` is `redis`. If `store.mode,store.lock.mode,store.session.mode` are not equal to `redis`, you can remove the configuration block.\n#store.redis.mode=single\n#store.redis.single.host=127.0.0.1\n#store.redis.single.port=6379\n#store.redis.sentinel.masterName=\n#store.redis.sentinel.sentinelHosts=\n#store.redis.maxConn=10\n#store.redis.minConn=1\n#store.redis.maxTotal=100\n#store.redis.database=0\n#store.redis.password=\n#store.redis.queryLimit=100\n\n#Transaction rule configuration, only for the server\nserver.recovery.committingRetryPeriod=1000\nserver.recovery.asynCommittingRetryPeriod=1000\nserver.recovery.rollbackingRetryPeriod=1000\nserver.recovery.timeoutRetryPeriod=1000\nserver.maxCommitRetryTimeout=-1\nserver.maxRollbackRetryTimeout=-1\nserver.rollbackRetryTimeoutUnlockEnable=false\nserver.distributedLockExpireTime=10000\nserver.xaerNotaRetryTimeout=60000\nserver.session.branchAsyncQueueSize=5000\nserver.session.enableBranchAsyncRemove=false\nserver.enableParallelRequestHandle=false\n\n#Metrics configuration, only for the server\nmetrics.enabled=false\nmetrics.registryType=compact\nmetrics.exporterList=prometheus\nmetrics.exporterPrometheusPort=9898\n\n\n', '2f01ddfe7f47c6ff6790ac716739eb4a', '2026-02-03 21:05:52', '2026-02-04 13:57:51', NULL, '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '', '', '', 'properties', '', '');
INSERT INTO `config_info` VALUES (225, 'aioveu-common.yaml', 'AIOVEU_GROUP', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n\n  datasource:    \n    # 以下是新增的 Druid 连接池配置\n    druid:\n      # 1. 连接池基础配置  # 临时调大，缓解问题\n      initial-size: 20\n      min-idle: 20\n      max-active: 100\n      max-wait: 3000  # 3秒超时，避免请求堆积\n      \n      # 2. 连接有效性检测\n      validation-query: SELECT 1\n      test-while-idle: true\n      test-on-borrow: false\n      test-on-return: false\n      time-between-eviction-runs-millis: 60000\n      min-evictable-idle-time-millis: 300000\n      \n      # 3. 连接泄漏检测\n      remove-abandoned: true\n      remove-abandoned-timeout: 180\n      log-abandoned: true\n      \n      # 4. 监控统计\n      # 访问监控页面 ,如果配置了 stat-view-servlet，可以访问 http://你的IP:端口/druid/index.html\n      filters: stat,wall,slf4j\n      stat-view-servlet:\n        enabled: true\n        login-username: aioveu\n        login-password: 775825\n        url-pattern: /druid/*\n        reset-enable: false\n      \n      # 5. Web监控\n      web-stat-filter:\n        enabled: true\n        url-pattern: /*\n        exclusions: \"*.js,*.gif,*.jpg,*.png,*.css,*.ico,/druid/*\"\n      \n      # 6. Filter配置（关键修正点！）\n      # Druid 的 filter 配置是独立的，不是 spring 的子项\n      # 6. 慢SQL记录  开启慢SQL监控\n      filter:\n        stat:\n          enabled: true\n          log-slow-sql: true\n          slow-sql-millis: 2000   # 超过2秒的SQL记录\n          merge-sql: true\n        # SQL防火墙\n        wall:\n          enabled: true\n          config:\n            multi-statement-allow: true\n            none-base-statement-allow: false\n\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          max-active: 8\n          max-idle: 5\n          min-idle: 2\n          max-wait: 1000ms\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: localhost:8848\n  namespace: a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef\n  group: SEATA_GROUP\n  application: aioveu-seata-server\n  data-id: seataServer.properties\n  username: nacos\n  password: 775825\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000', '6f7a94696bfffe8af1988307cae0cdbb', '2026-02-03 21:53:00', '2026-03-15 16:57:59', 'nacos', '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (249, 'aioveu-WeChatPay.yaml', 'AIOVEU_PAY_GROUP', '# application-WeChatPay.yml\n\n# ======================\n# 支付渠道通用配置\n# ======================\npayment:\n  channels:\n    # 微信支付渠道配置\n    wechat:\n      jsapi: WECHAT_JSAPI       # 微信公众号/小程序支付标识\n      app: WECHAT_APP           # APP支付标识\n      native: WECHAT_NATIVE     # 扫码支付标识\n      h5: WECHAT_H5             # H5支付标识\n    \n    # 支付宝支付渠道配置  \n    alipay:\n      app: ALIPAY_APP           # 支付宝APP支付标识\n      wap: ALIPAY_WAP           # 手机网站支付标识\n      page: ALIPAY_PAGE         # 电脑网站支付标识\n\n# ======================\n# 微信支付专用配置\n# ======================\npay:\n  wechat:\n    # 基础开关配置\n    enabled: false               # 是否启用微信支付功能\n    \n    # ================\n    # 基础认证信息\n    # ================\n    app-id: wx1234567890abcdef  # 微信应用ID(公众号/小程序/APP等)\n    mch-id: 1230000109          # 微信商户号(10位数字)\n    mch-key: ABCDEFGHIJKLMNOPQRSTUVWXYZ123456  # 商户API密钥(V2版API使用)\n    api-v3-key: ABCDEFGHIJKLMNOPQRSTUVWXYZ123456  # APIv3密钥(32位字符)\n    mch-serial-no: 1DDE55AD98ED7196  # 商户证书序列号\n    \n    # ================\n    # 私钥配置(二选一)\n    # ================\n    private-key-path: classpath:certs/apiclient_key.pem  # 私钥文件路径(classpath:表示从resources加载)\n    # 或者直接配置私钥内容(推荐用于生产环境)\n    private-key: |\n      -----BEGIN PRIVATE KEY-----\n      MIIEvQIBADANBgkqhkiG9w0BAQEFAASCBKcwggSjAgEAAoIBAQC3wN7c...\n      -----END PRIVATE KEY-----\n\n    # ================\n    # 回调地址配置\n    # ================\n    notify-url: https://your-domain.com/api/payment/wechat/notify          # 支付结果通知地址\n    refund-notify-url: https://your-domain.com/api/payment/wechat/refund/notify  # 退款结果通知地址\n\n    # ================\n    # 证书配置\n    # ================\n    platform-cert-path: classpath:certs/wechatpay_cert.pem  # 微信支付平台证书路径\n    cert-path: classpath:certs/apiclient_cert.p12           # PKCS12格式商户证书路径(V2接口使用)\n    cert-password: 123456                                  # PKCS12证书密码\n\n    # ================\n    # 网络连接配置\n    # ================\n    api-domain: https://api.mch.weixin.qq.com  # 微信支付API域名\n    connect-timeout: 10                        # 连接超时时间(秒)\n    read-timeout: 10                           # 读取超时时间(秒)\n\n    # ================\n    # 高级配置\n    # ================\n    sandbox: false              # 是否使用沙箱环境(测试环境)\n    sign-type: RSA               # 签名算法类型(RSA/RSA2)\n    cert-store-type: FILE        # 证书存储方式(FILE/CLASSPATH)\n    auto-download-cert: true     # 是否自动下载平台证书\n\n    # ================\n    # 支付方式详细配置\n    # ================\n    payment-methods:\n      # JSAPI支付(公众号/小程序)\n      jsapi:\n        app-id: wx1234567890abcdef  # 专用AppID(可覆盖全局配置)\n        enabled: true               # 是否启用该支付方式\n        \n      # APP支付\n      app:\n        app-id: wxd678efh567hg6787  # APP专用AppID\n        enabled: true\n        \n      # Native支付(扫码支付)\n      native:\n        app-id: wx1234567890abcdef\n        enabled: true\n        \n      # H5支付\n      h5:\n        app-id: wx1234567890abcdef\n        enabled: true', '607b0b62bc3fe4232980a8649d47807b', '2026-02-11 14:21:50', '2026-02-11 23:06:14', NULL, '172.18.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (250, 'aioveu-AliPay.yaml', 'AIOVEU_PAY_GROUP', '# application.yml\n\npay:\n  alipay:\n    # 基础配置\n    app-id: 2021000116699999\n    app-private-key: \"MIIEvQIBADANBgkqhkiG9w0BAQEFAASCBKcwggSjAgEAAoIBAQC3wN7c...\"\n    alipay-public-key: \"MIIBIjANBgkqhkiG9w0BAQEFAAOCAQ8AMIIBCgKCAQEAuZ7K...\"\n    server-url: https://openapi.alipay.com/gateway.do\n\n    # 证书模式配置（二选一）\n    use-cert: false\n    app-cert-path: /path/to/appCertPublicKey.crt\n    alipay-cert-path: /path/to/alipayCertPublicKey.crt\n    alipay-root-cert-path: /path/to/alipayRootCert.crt\n\n    # 回调地址\n    notify-url: https://your-domain.com/api/payment/alipay/notify\n    return-url: https://your-domain.com/payment/return\n\n    # 其他配置\n    sign-type: RSA2\n    charset: UTF-8\n    format: json\n    timeout: 10\n\n    # 沙箱环境配置\n    # server-url: https://openapi.alipaydev.com/gateway.do\n    # app-id: 2016092700609999', 'c531d6f0066018df3895d56a6241e795', '2026-02-11 14:23:07', '2026-02-11 23:05:48', NULL, '172.18.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (255, 'aioveu-MockPay.yaml', 'AIOVEU_PAY_GROUP', '# 模拟支付配置\npay:\n  mock:\n    # 基本配置\n    enabled: true                     # 是否启用模拟支付\n    auto-success: true                # 是否自动成功\n    delay: 1000                       # 模拟延迟(ms)\n    success-rate: 100                 # 成功率(0-100)\n    \n    # 微信支付模拟配置\n    wechat:\n      enabled: true                   # 是否启用微信模拟支付\n      app-id: \"wx1234567890abcdef\"    # 模拟微信AppId\n      mch-id: \"1230000109\"            # 模拟商户号\n      notify-url: \"http://localhost:8888/api/payment/callback/wechat\"\n      \n    # 支付宝支付模拟配置\n    alipay:\n      enabled: true                   # 是否启用支付宝模拟支付\n      app-id: \"2021000118691234\"      # 模拟支付宝AppId\n      notify-url: \"http://localhost:8888/api/payment/callback/alipay\"\n    \n    # 余额支付模拟配置\n    balance:\n      enabled: true                   # 是否启用余额模拟支付\n      default-balance: 1000000        # 默认余额(分)\n    \n    # 调试配置\n    debug: true                       # 调试模式\n    log-request: true                 # 记录请求日志\n    log-response: true                # 记录响应日志', '024b50a72a0d484f5c6e493f68d2d157', '2026-02-11 18:18:33', '2026-02-11 18:34:46', NULL, '172.18.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (259, 'aioveu-tenant.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_tenant?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  # 这两个配置必须要有！\n  #问题的核心是：MyBatis-Plus 配置了 mapper-locations，它会尝试为每个 Mapper 接口查找对应的 XML 文件。如果找不到，可能会忽略这个 Mapper。\n  mapper-locations: classpath*:/mapper/**/*.xml\n  type-aliases-package: com.aioveu.**.entity\n  global-config:\n    # 或者更直接：不检查 XML\n    # enable-sql-runner: false\n    db-config:\n      # 主键ID类型\n      id-type: none\n      # 逻辑删除对应的全局属性名（注意：须是对象属性名，不能是表字段名，如 isDeleted 而非 is_deleted，否则逻辑删除失效）\n      logic-delete-field: isDeleted\n      # 逻辑删除-删除值\n      logic-delete-value: 1\n      # 逻辑删除-未删除值\n      logic-not-delete-value: 0\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n    # 允许 Mapper 接口没有对应的 XML 映射文件\n    aggressive-lazy-loading: false\n\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    #一次查询获取用户名在所有租户中的可访问租户\n    - /api/v1/users/{username}/{tenantId}/authInfo\n    - /api/v1/users/tenants/{username}   \n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: aliyun\n  # MinIO 对象存储服务\n  # minio:\n  #   # 服务Endpoint  #minio:9000 \n  #   endpoint:  minio:9000\n  #   # 访问凭据\n  #   access-key: minioadminlss\n  #   # 凭据密钥\n  #   secret-key: minioadminlss\n  #   # 存储桶名称\n  #   bucket-name: aioveu\n  #   # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n  #   custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    tenant-id: 1001  # 添加到这里\n    # 服务Endpoint\n    endpoint: oss-cn-shanghai-internal.aliyuncs.com\n    # 访问凭据\n    access-key-id: LTAI5tDVP4BURrY9VtAE66K2\n    # 凭据密钥\n    access-key-secret: cOpi8YlxjJKmxoPG7D8j2592fC2iSD\n    # 存储桶名称\n    bucket-name: aioveu\n    # 新增：加速域名配置  # 替换为您的实际加速域名\n    cdn-domain: minio.aioveu.com  \n\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\nmail:\n  host: smtp.qq.com\n  port: 587  #465 # 或587\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\n  properties:\n    mail:\n      smtp:\n        auth: true\n        ssl: true   # 465端口必开\n        starttls:\n          enable: true    # 587端口必开\n  # 邮件发送者\n  from: ambitiouschild@qq.com', '08cd9da95acedd8374fdd667de3d5684', '2026-02-21 17:00:52', '2026-03-01 17:37:34', NULL, '172.18.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (265, 'seataServer.properties', 'SEATA_GROUP', '\n#seata.ip=192.168.1.5\n#seata.port=8091\n\n\n#For details about configuration items, see https://seata.io/zh-cn/docs/user/configurations.html\n#Transport configuration, for client and server\ntransport.type=TCP\ntransport.server=NIO\ntransport.heartbeat=true\ntransport.enableTmClientBatchSendRequest=false\ntransport.enableRmClientBatchSendRequest=true\ntransport.enableTcServerBatchSendResponse=false\ntransport.rpcRmRequestTimeout=30000\ntransport.rpcTmRequestTimeout=30000\ntransport.rpcTcRequestTimeout=30000\ntransport.threadFactory.bossThreadPrefix=NettyBoss\ntransport.threadFactory.workerThreadPrefix=NettyServerNIOWorker\ntransport.threadFactory.serverExecutorThreadPrefix=NettyServerBizHandler\ntransport.threadFactory.shareBossWorker=false\ntransport.threadFactory.clientSelectorThreadPrefix=NettyClientSelector\ntransport.threadFactory.clientSelectorThreadSize=1\ntransport.threadFactory.clientWorkerThreadPrefix=NettyClientWorkerThread\ntransport.threadFactory.bossThreadSize=1\ntransport.threadFactory.workerThreadSize=default\ntransport.shutdown.wait=3\ntransport.serialization=seata\ntransport.compressor=none\n\n#Transaction routing rules configuration, only for the client\nservice.vgroupMapping.default_tx_group=default\n#If you use a registry, you can ignore it\n#service.default.grouplist=aioveu-seata-server:8091\n#service.enableDegrade=false\n#service.disableGlobalTransaction=false\n\n#Transaction rule configuration, only for the client\nclient.rm.asyncCommitBufferLimit=10000\nclient.rm.lock.retryInterval=10\nclient.rm.lock.retryTimes=30\nclient.rm.lock.retryPolicyBranchRollbackOnConflict=true\nclient.rm.reportRetryCount=5\nclient.rm.tableMetaCheckEnable=true\nclient.rm.tableMetaCheckerInterval=60000\nclient.rm.sqlParserType=druid\nclient.rm.reportSuccessEnable=false\nclient.rm.sagaBranchRegisterEnable=false\nclient.rm.sagaJsonParser=fastjson\nclient.rm.tccActionInterceptorOrder=-2147482648\nclient.tm.commitRetryCount=5\nclient.tm.rollbackRetryCount=5\nclient.tm.defaultGlobalTransactionTimeout=60000\nclient.tm.degradeCheck=false\nclient.tm.degradeCheckAllowTimes=10\nclient.tm.degradeCheckPeriod=2000\nclient.tm.interceptorOrder=-2147482648\nclient.undo.dataValidation=true\nclient.undo.logSerialization=jackson\nclient.undo.onlyCareUpdateColumns=true\nserver.undo.logSaveDays=7\nserver.undo.logDeletePeriod=86400000\nclient.undo.logTable=undo_log\nclient.undo.compress.enable=true\nclient.undo.compress.type=zip\nclient.undo.compress.threshold=64k\n#For TCC transaction mode\ntcc.fence.logTableName=tcc_fence_log\ntcc.fence.cleanPeriod=1h\n\n#Log rule configuration, for client and server\nlog.exceptionRate=100\n\n#Transaction storage configuration, only for the server. The file, db, and redis configuration values are optional.\nstore.mode=db\nstore.lock.mode=db\nstore.session.mode=db\n#Used for password encryption\n#store.publicKey=\n\n#If `store.mode,store.lock.mode,store.session.mode` are not equal to `file`, you can remove the configuration block.\nstore.file.dir=file_store/data\nstore.file.maxBranchSessionSize=16384\nstore.file.maxGlobalSessionSize=512\nstore.file.fileWriteBufferCacheSize=16384\nstore.file.flushDiskMode=async\nstore.file.sessionReloadReadSize=100\n\nlock.db.lockValueMaxLength=256\nlock.db.rowKeyMaxLength=256\n\n#These configurations are required if the `store mode` is `db`. If `store.mode,store.lock.mode,store.session.mode` are not equal to `db`, you can remove the configuration block.\nstore.db.datasource=druid\nstore.db.dbType=mysql\nstore.db.driverClassName=com.mysql.cj.jdbc.Driver\nstore.db.url=jdbc:mysql://mysql:3306/aioveu_seata?useUnicode=true&rewriteBatchedStatements=true\nstore.db.user=root\nstore.db.password=775825\nstore.db.minConn=5\nstore.db.maxConn=30\nstore.db.globalTable=global_table\nstore.db.branchTable=branch_table\nstore.db.distributedLockTable=distributed_lock\nstore.db.queryLimit=100\nstore.db.lockTable=lock_table\nstore.db.maxWait=5000\n\n#These configurations are required if the `store mode` is `redis`. If `store.mode,store.lock.mode,store.session.mode` are not equal to `redis`, you can remove the configuration block.\n#store.redis.mode=single\n#store.redis.single.host=127.0.0.1\n#store.redis.single.port=6379\n#store.redis.sentinel.masterName=\n#store.redis.sentinel.sentinelHosts=\n#store.redis.maxConn=10\n#store.redis.minConn=1\n#store.redis.maxTotal=100\n#store.redis.database=0\n#store.redis.password=\n#store.redis.queryLimit=100\n\n#Transaction rule configuration, only for the server\nserver.recovery.committingRetryPeriod=1000\nserver.recovery.asynCommittingRetryPeriod=1000\nserver.recovery.rollbackingRetryPeriod=1000\nserver.recovery.timeoutRetryPeriod=1000\nserver.maxCommitRetryTimeout=-1\nserver.maxRollbackRetryTimeout=-1\nserver.rollbackRetryTimeoutUnlockEnable=false\nserver.distributedLockExpireTime=10000\nserver.xaerNotaRetryTimeout=60000\nserver.session.branchAsyncQueueSize=5000\nserver.session.enableBranchAsyncRemove=false\nserver.enableParallelRequestHandle=false\n\n#Metrics configuration, only for the server\nmetrics.enabled=false\nmetrics.registryType=compact\nmetrics.exporterList=prometheus\nmetrics.exporterPrometheusPort=9898', 'fd25288361998f7499fd2da0b4e84499', '2026-03-09 13:40:23', '2026-03-09 13:43:17', 'aioveu', '172.18.0.1', '', '', '', '', '', 'properties', '', '');
INSERT INTO `config_info` VALUES (266, 'service.vgroupMapping.default_tx_group', 'SEATA_GROUP', 'default', 'c21f969b5f03d33d43e04f8f136e7682', '2026-03-09 13:41:09', '2026-03-09 13:45:59', 'aioveu', '172.18.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (268, 'aioveu-WeChatPay.yaml', 'AIOVEU_PAY_GROUP', '# application-WeChatPay.yml\n\n# ======================\n# 支付渠道通用配置\n# ======================\npayment:\n  channels:\n    # 微信支付渠道配置\n    wechat:\n      jsapi: WECHAT_JSAPI       # 微信公众号/小程序支付标识\n      app: WECHAT_APP           # APP支付标识\n      native: WECHAT_NATIVE     # 扫码支付标识\n      h5: WECHAT_H5             # H5支付标识\n    \n    # 支付宝支付渠道配置  \n    alipay:\n      app: ALIPAY_APP           # 支付宝APP支付标识\n      wap: ALIPAY_WAP           # 手机网站支付标识\n      page: ALIPAY_PAGE         # 电脑网站支付标识\n\n# ======================\n# 微信支付专用配置\n# ======================\npay:\n  wechat:\n    # 基础开关配置 false\n    enabled: true               # 是否启用微信支付功能\n    \n    # ================\n    # 基础认证信息\n    # ================\n    # 微信应用ID(公众号/小程序/APP等)\n    app-id: wxe510ad6d4d60bfa8  \n    # 微信商户号(10位数字)\n    mch-id: 1107195457          \n    # 商户API密钥(V2版API使用)\n    # mch-key: ABCDEFGHIJKLMNOPQRSTUVWXYZ123456  \n    # APIv3密钥(32位字符)\n    api-v3-key: dCzmYhzYcCEyRyiHp9Z9MTVMRYoSYwVj  \n    # 商户证书序列号   3E9ED7E808B24BAB9E74C1414B57FEDB9D063DB1\n    mch-serial-no: 239431EB597A2C00B8356D7C3043E0FC8D04CEE8\n    \n        # 新增：微信支付公钥配置\n        # 从商户平台复制的公钥ID\n    wechatpay-public-key-id: PUB_KEY_ID_0111071954572026030800292321000401 \n    # wechatpay-public-key-path: classpath:certs/wechatpay_public_key.pem\n    wechatpay-public-key: |\n        -----BEGIN PUBLIC KEY-----\n        MIIBIjANBgkqhkiG9w0BAQEFAAOCAQ8AMIIBCgKCAQEAwzm4THV3l2aUkyl/dQln\n        vzs07PMP6iopZmcWXDvY2hu/N5iAlRwF5iYsKQQw0gRDeRMWlui+HkS7B7udE5T3\n        quK6i2XablINSRMSNVLtSbBebfvdj2JzmYmV4Z5D2t9DQrsYs22nwQTrojA61lYr\n        rdpukp0YH3p0IDxzRDzGIkmWT4/DhZ7eL87rB7o9Kvt0tzmg/ybdEsp80tv0h57R\n        5PGpbPyS28vGyNnqTK/3IgDMkf2AyiQxNqahjAj97pS8WI2uc1lTb076eEmJA4l+\n        VKmSHVGDOfQE8jReTE/jvjpTP5SxoFyvG/sp+tcLbk8BGjpVZnc6ynzO3AyHbFDp\n        LQIDAQAB\n        -----END PUBLIC KEY-----\n\n    # ================\n    # 私钥配置(二选一)\n    # ================\n    # 私钥文件路径(classpath:表示从resources加载)\n    # private-key-path: classpath:certs/apiclient_key.pem  \n    # 或者直接配置私钥内容(推荐用于生产环境)\n    private-key: |\n      -----BEGIN PRIVATE KEY-----\n      MIIEvgIBADANBgkqhkiG9w0BAQEFAASCBKgwggSkAgEAAoIBAQC31Edi9nwLNMwL\n      BibV+d3lypSXUqnA3S4jC3f75SyvyVmFu1EPS5H0lGfSg2rE8yriLdt25PKEseax\n      wOz7ARIkqo+pBVtyIaLfvrftUpRFUvxG/8AxQZ2rmeVm9RVRZtGzVdRuNXBwOnnV\n      /fOf0zRB168dE1K+jJa47wx39TB6f8AqDpm/bzfCnwMqUwFihxUoU5Od4QK1Y6cb\n      ZugB5VSpxOp2RDLXovj92Du9c/MwfipD/ZvObEfbPXcdpKQ5yBtzNmEjC4o5PrFK\n      LK2QMPw1JwCotj004TVxaoXSannAKG6ZtXahb1I4rx/DTZ3m12KqcDQQRn0wY5U9\n      5TqZSmEbAgMBAAECggEAbDleWaXRO2u24JqbjIfRGnLcbgYtiCzu95TN649tcoQw\n      3yl7PGz6HaqtQOM7nX2ndocW2HVLTdHKhkWVfuSPgOSlNRXBU3z3/Y+zitV+Ex4b\n      BdWVmaoOoDM3Ohj5lvXYaSMTsFpnurrCdbhPkH1wG39WSeDRavsr1O5vQcQo6USB\n      669iYR5LLhIRPELxQjSLPfDDKllu48rcS3j365inQPc2QTvbZ63LVKHAs1MQvPvA\n      dBohlxbvUMIB/5YlYnkgJwwVBONmBfbj6u+f/5Os2W5Z6A3L3+LuvhApNPlUTolo\n      1jvVpJkHAklowZ8q8AsOm36pfMnH5M+2pjGIRDoP+QKBgQDv8TwKQS/87MDDgmOt\n      BTzZKPZ2lGsfn+/3Ql7Z/ob6yfMrvOt6EhyG5tTa4TSpBdq9Ar2EphilaYszoKHv\n      PTBWL8xWA1Tfn0E/vc6j+Hxri6Fd76vJPP8U61KmH+s7/x/HpWEzVV2PYLkkk3k+\n      gA2P0RmkwvrcZ6bgOSjXNyvgBwKBgQDEIbKE+tr3NWeQx9CqYVNNL4pvzUG6NCrM\n      4x1v19okYpRowDF1PIzJ6JZURDoB/zBYe0UbzPO1gIRS/ZBK3JT+MpD4iF2IIv2z\n      /ilSjNv0XBVDIrnPpZcRNcvrr5ZbGgt56VSWvJNObfuuL9mY7QxvZ+dRE1K/5FW8\n      GUUo9ppJTQKBgQC2V1EVSey5/QGQkipFdlGDhkmmW6v84IJwGRQT/gV92LLfbjZV\n      EiZzrj/cBoEKYdSVBtwXTlI0gjyzA0OMl6eAF9rlEqsRNelUE15R5ahH4ljDFjwq\n      NhxzPVIVxPPzKDJyeg+f/yOWrh6E2T2ubYng3TrrpvEVRf/fLhEHXHoPSQKBgEXr\n      CVv0nYiRJjlrsgx7I5oZf415q5u4qyVdNYpAdciQx/1LvpXfnwT/gE/L/q3ljhOM\n      5kcR2jNy/DkloYG+fvLbjei7nDRC3RSEX7DI/ERxazcCsyC+FEuTVP3RG5WghETS\n      lFAkK5NDC/y9nCGzJ8KzVLgHXnF/8bxbedcvijLlAoGBANtrk99k2X1ZVxh3WLUM\n      i7+6d5dGTed6mYzD7qjC1yCgu6ATrLF/L1qgfVkdpEcwqOB5dZzZX3eAjvXytCtV\n      xR9s+OqECoujURHY1QlmD0wGuNKDkusmlAqqV1xDCZzsoCdtKgjk+Rytee9BVW6t\n      Kdi+4BE0vnA+MDgHdUflDtbF\n      -----END PRIVATE KEY-----\n\n\n\n\n    # ================\n    # 回调地址配置\n    # ================\n    # notify-url: https://aioveu.com/api/payment/wechat/notify          # 支付结果通知地址\n    # 支付结果通知地址\n    notify-url: https://192.168.1.5:6699/api/v1/pay-order/callback/wechat       \n    refund-notify-url: https://aioveu.com/api/payment/wechat/refund/notify  # 退款结果通知地址\n\n    # ================\n    # 证书配置\n    # ================\n    platform-cert-path: classpath:certs/wechatpay_cert.pem  # 微信支付平台证书路径\n    cert-path: classpath:certs/apiclient_cert.p12           # PKCS12格式商户证书路径(V2接口使用)\n    cert-password: 123456                                  # PKCS12证书密码\n\n    # ================\n    # 网络连接配置\n    # ================\n    api-domain: https://api.mch.weixin.qq.com  # 微信支付API域名\n    connect-timeout: 10                        # 连接超时时间(秒)\n    read-timeout: 10                           # 读取超时时间(秒)\n\n    # ================\n    # 高级配置\n    # ================\n    sandbox: false              # 是否使用沙箱环境(测试环境)\n    sign-type: RSA               # 签名算法类型(RSA/RSA2)\n    cert-store-type: FILE        # 证书存储方式(FILE/CLASSPATH)\n    auto-download-cert: true     # 是否自动下载平台证书\n\n    # ================\n    # 支付方式详细配置\n    # ================\n    payment-methods:\n      # JSAPI支付(公众号/小程序)\n      jsapi:\n      # 专用AppID(可覆盖全局配置)\n        app-id: wxe510ad6d4d60bfa8  \n        # 是否启用该支付方式\n        enabled: true               \n        \n      # APP支付\n      app:\n       # APP专用AppID\n        app-id: wxe510ad6d4d60bfa8 \n        enabled: true\n        \n      # Native支付(扫码支付)\n      native:\n        app-id: wxe510ad6d4d60bfa8\n        enabled: true\n        \n      # H5支付\n      h5:\n        app-id: wxe510ad6d4d60bfa8\n        enabled: true', '2ba8272477e31bd4d0e6368826a54831', '2026-03-09 19:29:05', '2026-03-10 15:35:23', 'aioveu', '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (269, 'aioveu-AliPay.yaml', 'AIOVEU_PAY_GROUP', '# application.yml\n\npay:\n  alipay:\n    # 基础配置\n    app-id: 2021000116699999\n    app-private-key: \"MIIEvQIBADANBgkqhkiG9w0BAQEFAASCBKcwggSjAgEAAoIBAQC3wN7c...\"\n    alipay-public-key: \"MIIBIjANBgkqhkiG9w0BAQEFAAOCAQ8AMIIBCgKCAQEAuZ7K...\"\n    server-url: https://openapi.alipay.com/gateway.do\n\n    # 证书模式配置（二选一）\n    use-cert: false\n    app-cert-path: /path/to/appCertPublicKey.crt\n    alipay-cert-path: /path/to/alipayCertPublicKey.crt\n    alipay-root-cert-path: /path/to/alipayRootCert.crt\n\n    # 回调地址\n    notify-url: https://your-domain.com/api/payment/alipay/notify\n    return-url: https://your-domain.com/payment/return\n\n    # 其他配置\n    sign-type: RSA2\n    charset: UTF-8\n    format: json\n    timeout: 10\n\n    # 沙箱环境配置\n    # server-url: https://openapi.alipaydev.com/gateway.do\n    # app-id: 2016092700609999', 'c531d6f0066018df3895d56a6241e795', '2026-03-09 19:29:29', '2026-03-09 19:30:34', 'nacos', '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (270, 'aioveu-MockPay.yaml', 'AIOVEU_PAY_GROUP', '# 模拟支付配置\npay:\n  mock:\n    # 基本配置\n    enabled: true                     # 是否启用模拟支付\n    auto-success: true                # 是否自动成功\n    delay: 1000                       # 模拟延迟(ms)\n    success-rate: 100                 # 成功率(0-100)\n    \n    # 微信支付模拟配置\n    wechat:\n      enabled: true                   # 是否启用微信模拟支付\n      app-id: \"wx1234567890abcdef\"    # 模拟微信AppId\n      mch-id: \"1230000109\"            # 模拟商户号\n      notify-url: \"http://localhost:8888/api/payment/callback/wechat\"\n      \n    # 支付宝支付模拟配置\n    alipay:\n      enabled: true                   # 是否启用支付宝模拟支付\n      app-id: \"2021000118691234\"      # 模拟支付宝AppId\n      notify-url: \"http://localhost:8888/api/payment/callback/alipay\"\n    \n    # 余额支付模拟配置\n    balance:\n      enabled: true                   # 是否启用余额模拟支付\n      default-balance: 1000000        # 默认余额(分)\n    \n    # 调试配置\n    debug: true                       # 调试模式\n    log-request: true                 # 记录请求日志\n    log-response: true                # 记录响应日志', '024b50a72a0d484f5c6e493f68d2d157', '2026-03-09 19:29:42', '2026-03-09 19:30:58', 'nacos', '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (271, 'aioveu-tenant.yaml', 'AIOVEU_GROUP', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_tenant?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  mapper-locations: classpath*:/mapper/**/*.xml\n  global-config:\n    db-config:\n      # 主键ID类型\n      id-type: none\n      # 逻辑删除对应的全局属性名（注意：须是对象属性名，不能是表字段名，如 isDeleted 而非 is_deleted，否则逻辑删除失效）\n      logic-delete-field: isDeleted\n      # 逻辑删除-删除值\n      logic-delete-value: 1\n      # 逻辑删除-未删除值\n      logic-not-delete-value: 0\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n    # 这是给 MyBatis 的 databaseId 属性用的\n    database-id: mysql  \n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n    #根据用户名获取可登录的租户列表\n    - /api/v1/users/tenants/{username}\n\n    #根据用户名和租户ID获取认证信息（用于多租户登录）\n    - /api/v1/users/{username}/{tenantId}/authInfo\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: aliyun\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint  #minio:9000 \n    # endpoint:  minio.aioveu.com \n    # # 访问凭据\n    # access-key: minioadminlss\n    # # 凭据密钥\n    # secret-key: minioadminlss\n    # # 存储桶名称\n    # bucket-name: aioveu\n    # # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    # custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    tenant-id: 1001  # 添加到这里\n    # 服务Endpoint\n    endpoint: oss-cn-shanghai.aliyuncs.com\n    # 访问凭据\n    access-key-id: LTAI5tDVP4BURrY9VtAE66K2\n    # 凭据密钥\n    access-key-secret: cOpi8YlxjJKmxoPG7D8j2592fC2iSD\n    # 存储桶名称\n    bucket-name: aioveu\n    # 新增：加速域名配置  # 替换为您的实际加速域名\n    cdn-domain: cdn.aioveu.com \n    cdn-region: cn-shanghai \n\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\nmail:\n  host: smtp.qq.com\n  port: 587  #465 # 或587\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\n  properties:\n    mail:\n      smtp:\n        auth: true\n        ssl: true   # 465端口必开\n        starttls:\n          enable: true    # 587端口必开\n  # 邮件发送者\n  from: ambitiouschild@qq.com', '83704f53ad2689f22cc5c47e41446651', '2026-03-10 19:21:47', '2026-03-12 17:09:06', 'aioveu', '172.18.0.1', '', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '', '', '', 'yaml', '', '');

-- ----------------------------
-- Table structure for config_info_aggr
-- ----------------------------
DROP TABLE IF EXISTS `config_info_aggr`;
CREATE TABLE `config_info_aggr`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `data_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'data_id',
  `group_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'group_id',
  `datum_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'datum_id',
  `content` longtext CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT '内容',
  `gmt_modified` datetime NOT NULL COMMENT '修改时间',
  `app_name` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `tenant_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT '' COMMENT '租户字段',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_configinfoaggr_datagrouptenantdatum`(`data_id` ASC, `group_id` ASC, `tenant_id` ASC, `datum_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = '增加租户字段' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of config_info_aggr
-- ----------------------------

-- ----------------------------
-- Table structure for config_info_beta
-- ----------------------------
DROP TABLE IF EXISTS `config_info_beta`;
CREATE TABLE `config_info_beta`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `data_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'data_id',
  `group_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'group_id',
  `app_name` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'app_name',
  `content` longtext CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'content',
  `beta_ips` varchar(1024) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'betaIps',
  `md5` varchar(32) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'md5',
  `gmt_create` datetime NOT NULL DEFAULT '2010-05-05 00:00:00' COMMENT '创建时间',
  `gmt_modified` datetime NOT NULL DEFAULT '2010-05-05 00:00:00' COMMENT '修改时间',
  `src_user` text CHARACTER SET utf8 COLLATE utf8_bin NULL COMMENT 'source user',
  `src_ip` varchar(20) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'source ip',
  `tenant_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT '' COMMENT '租户字段',
  `encrypted_data_key` text CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT '秘钥',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_configinfobeta_datagrouptenant`(`data_id` ASC, `group_id` ASC, `tenant_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = 'config_info_beta' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of config_info_beta
-- ----------------------------

-- ----------------------------
-- Table structure for config_info_tag
-- ----------------------------
DROP TABLE IF EXISTS `config_info_tag`;
CREATE TABLE `config_info_tag`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `data_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'data_id',
  `group_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'group_id',
  `tenant_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT '' COMMENT 'tenant_id',
  `tag_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'tag_id',
  `app_name` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'app_name',
  `content` longtext CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'content',
  `md5` varchar(32) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'md5',
  `gmt_create` datetime NOT NULL DEFAULT '2010-05-05 00:00:00' COMMENT '创建时间',
  `gmt_modified` datetime NOT NULL DEFAULT '2010-05-05 00:00:00' COMMENT '修改时间',
  `src_user` text CHARACTER SET utf8 COLLATE utf8_bin NULL COMMENT 'source user',
  `src_ip` varchar(20) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'source ip',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_configinfotag_datagrouptenanttag`(`data_id` ASC, `group_id` ASC, `tenant_id` ASC, `tag_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = 'config_info_tag' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of config_info_tag
-- ----------------------------

-- ----------------------------
-- Table structure for config_tags_relation
-- ----------------------------
DROP TABLE IF EXISTS `config_tags_relation`;
CREATE TABLE `config_tags_relation`  (
  `id` bigint NOT NULL COMMENT 'id',
  `tag_name` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'tag_name',
  `tag_type` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'tag_type',
  `data_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'data_id',
  `group_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'group_id',
  `tenant_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT '' COMMENT 'tenant_id',
  `nid` bigint NOT NULL AUTO_INCREMENT,
  PRIMARY KEY (`nid`) USING BTREE,
  UNIQUE INDEX `uk_configtagrelation_configidtag`(`id` ASC, `tag_name` ASC, `tag_type` ASC) USING BTREE,
  INDEX `idx_tenant_id`(`tenant_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = 'config_tag_relation' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of config_tags_relation
-- ----------------------------

-- ----------------------------
-- Table structure for group_capacity
-- ----------------------------
DROP TABLE IF EXISTS `group_capacity`;
CREATE TABLE `group_capacity`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `group_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL DEFAULT '' COMMENT 'Group ID，空字符表示整个集群',
  `quota` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '配额，0表示使用默认值',
  `usage` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '使用量',
  `max_size` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '单个配置大小上限，单位为字节，0表示使用默认值',
  `max_aggr_count` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '聚合子配置最大个数，，0表示使用默认值',
  `max_aggr_size` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '单个聚合数据的子配置大小上限，单位为字节，0表示使用默认值',
  `max_history_count` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '最大变更历史数量',
  `gmt_create` datetime NOT NULL DEFAULT '2010-05-05 00:00:00' COMMENT '创建时间',
  `gmt_modified` datetime NOT NULL DEFAULT '2010-05-05 00:00:00' COMMENT '修改时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_group_id`(`group_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = '集群、各Group容量信息表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of group_capacity
-- ----------------------------

-- ----------------------------
-- Table structure for his_config_info
-- ----------------------------
DROP TABLE IF EXISTS `his_config_info`;
CREATE TABLE `his_config_info`  (
  `id` bigint UNSIGNED NOT NULL,
  `nid` bigint UNSIGNED NOT NULL AUTO_INCREMENT,
  `data_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL,
  `group_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL,
  `app_name` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'app_name',
  `content` longtext CHARACTER SET utf8 COLLATE utf8_bin NOT NULL,
  `md5` varchar(32) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `gmt_create` datetime NOT NULL DEFAULT '2010-05-05 00:00:00',
  `gmt_modified` datetime NOT NULL DEFAULT '2010-05-05 00:00:00',
  `src_user` text CHARACTER SET utf8 COLLATE utf8_bin NULL,
  `src_ip` varchar(20) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `op_type` char(10) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `tenant_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT '' COMMENT '租户字段',
  `encrypted_data_key` text CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT '秘钥',
  PRIMARY KEY (`nid`) USING BTREE,
  INDEX `idx_gmt_create`(`gmt_create` ASC) USING BTREE,
  INDEX `idx_gmt_modified`(`gmt_modified` ASC) USING BTREE,
  INDEX `idx_did`(`data_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 427 CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = '多租户改造' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of his_config_info
-- ----------------------------
INSERT INTO `his_config_info` VALUES (0, 273, 'aioveu-tenant.yaml', 'AIOVEU_GROUP', '', 'spring:\r\n  datasource:\r\n    type: com.alibaba.druid.pool.DruidDataSource\r\n    driver-class-name: com.mysql.cj.jdbc.Driver \r\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_tenant?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\r\n    username: ${mysql.username}\r\n    password: ${mysql.password}\r\n  data:\r\n    redis:\r\n      database: ${redis.database}\r\n      host: ${redis.host}\r\n      port: ${redis.port}\r\n      password: ${redis.password}\r\n      lettuce:\r\n        pool:\r\n          min-idle: 1\r\n  # RabbitMQ 配置\r\n  rabbitmq:\r\n    host: ${rabbitmq.host}\r\n    port: ${rabbitmq.port}\r\n    username: ${rabbitmq.username}\r\n    password: ${rabbitmq.password}\r\n    virtual-host: /\r\n    listener:\r\n      simple:\r\n        acknowledge-mode: manual   \r\n  cache:\r\n    # 缓存类型 redis、none(不使用缓存) \r\n    type: redis\r\n    # 缓存时间(单位：ms)\r\n    redis:\r\n      time-to-live: 3600000\r\n      # 缓存null值，防止缓存穿透\r\n      cache-null-values: true\r\n  cloud:\r\n    sentinel:\r\n      enabled: false\r\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\r\n      transport:\r\n        client-ip: localhost\r\n        dashboard: localhost:8080\r\n      datasource:\r\n        # 限流规则，flow为key，随便定义\r\n        flow:\r\n          nacos:\r\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\r\n            dataId: ${spring.application.name}-flow-rules\r\n            groupId: SENTINEL_GROUP\r\n            data-type: json\r\n            rule-type: flow\r\n        # 降级规则\r\n        degrade:\r\n          nacos:\r\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\r\n            dataId: ${spring.application.name}-degrade-rules\r\n            groupId: SENTINEL_GROUP\r\n            data-type: json\r\n            rule-type: degrade\r\n                \r\nmybatis-plus:\r\n  configuration:\r\n    # 驼峰下划线转换\r\n    map-underscore-to-camel-case: true\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\r\n\r\nfeign:\r\n  httpclient:\r\n    enabled: true\r\n  okhttp:\r\n    enabled: false\r\n  sentinel:  # 开启feign对sentinel的支持\r\n    enabled: false \r\n\r\n# 安全配置\r\nsecurity:\r\n  # 允许无需认证的路径列表\r\n  whitelist-paths:\r\n    # 获取系统用户的认证信息用于账号密码判读\r\n    - /api/v1/users/{username}/authInfo\r\n    - /api/v1/users/{username}/UserAuthCredentials\r\n\r\n# springdoc-openapi项目配置\r\nspringdoc:\r\n  swagger-ui:\r\n    path: /swagger-ui.html\r\n    tags-sorter: alpha\r\n    operations-sorter: alpha\r\n  api-docs:\r\n    path: /v3/api-docs\r\n  group-configs:\r\n    - group: \'default\'\r\n      paths-to-match: \'/**\'\r\n      packages-to-scan: \r\n        - com.aioveu.system.controller\r\n        - com.aioveu.common.file.controller\r\n  # Api文档信息\r\n  info:\r\n    title: 系统服务\r\n    version: 3.0.0\r\n    description: 用户、部门、角色、菜单、字典等接口\r\n    contact:\r\n      name: aioveu\r\n      url: https://www.aioveu.com\r\n      email: ambitiouschild@qq.com\r\n    license:\r\n      name: Apache 2.0\r\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\r\n\r\n# knife4j的增强配置，不需要增强可以不配\r\nknife4j:\r\n  enable: false\r\n  setting:\r\n    language: zh_cn\r\n\r\n\r\n\r\n# 文件存储\r\noss:\r\n  # OSS 类型 (目前支持aliyun、minio)\r\n  type: minio\r\n  # MinIO 对象存储服务\r\n  minio:\r\n    # 服务Endpoint  #minio:9000 \r\n    endpoint:  minio:9000\r\n    # 访问凭据\r\n    access-key: minioadminlss\r\n    # 凭据密钥\r\n    secret-key: minioadminlss\r\n    # 存储桶名称\r\n    bucket-name: aioveu\r\n    # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\r\n    custom-domain:  https://minio.aioveu.com\r\n  # 阿里云OSS对象存储服务\r\n  aliyun:\r\n    # 服务Endpoint\r\n    endpoint: oss-cn-hangzhou.aliyuncs.com\r\n    # 访问凭据\r\n    access-key-id: your-access-key-id\r\n    # 凭据密钥\r\n    access-key-secret: your-access-key-secret\r\n    # 存储桶名称\r\n    bucket-name: default\r\n\r\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\r\nmail:\r\n  host: smtp.qq.com\r\n  port: 587  #465 # 或587\r\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\r\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\r\n  properties:\r\n    mail:\r\n      smtp:\r\n        auth: true\r\n        ssl: true   # 465端口必开\r\n        starttls:\r\n          enable: true    # 587端口必开\r\n  # 邮件发送者\r\n  from: ambitiouschild@qq.com', '87a0c21a6f4e471a9d167bb875d1ecd3', '2010-05-05 00:00:00', '2026-02-21 17:00:52', NULL, '172.18.0.1', 'I', '', '');
INSERT INTO `his_config_info` VALUES (259, 274, 'aioveu-tenant.yaml', 'AIOVEU_GROUP', '', 'spring:\r\n  datasource:\r\n    type: com.alibaba.druid.pool.DruidDataSource\r\n    driver-class-name: com.mysql.cj.jdbc.Driver \r\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_tenant?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\r\n    username: ${mysql.username}\r\n    password: ${mysql.password}\r\n  data:\r\n    redis:\r\n      database: ${redis.database}\r\n      host: ${redis.host}\r\n      port: ${redis.port}\r\n      password: ${redis.password}\r\n      lettuce:\r\n        pool:\r\n          min-idle: 1\r\n  # RabbitMQ 配置\r\n  rabbitmq:\r\n    host: ${rabbitmq.host}\r\n    port: ${rabbitmq.port}\r\n    username: ${rabbitmq.username}\r\n    password: ${rabbitmq.password}\r\n    virtual-host: /\r\n    listener:\r\n      simple:\r\n        acknowledge-mode: manual   \r\n  cache:\r\n    # 缓存类型 redis、none(不使用缓存) \r\n    type: redis\r\n    # 缓存时间(单位：ms)\r\n    redis:\r\n      time-to-live: 3600000\r\n      # 缓存null值，防止缓存穿透\r\n      cache-null-values: true\r\n  cloud:\r\n    sentinel:\r\n      enabled: false\r\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\r\n      transport:\r\n        client-ip: localhost\r\n        dashboard: localhost:8080\r\n      datasource:\r\n        # 限流规则，flow为key，随便定义\r\n        flow:\r\n          nacos:\r\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\r\n            dataId: ${spring.application.name}-flow-rules\r\n            groupId: SENTINEL_GROUP\r\n            data-type: json\r\n            rule-type: flow\r\n        # 降级规则\r\n        degrade:\r\n          nacos:\r\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\r\n            dataId: ${spring.application.name}-degrade-rules\r\n            groupId: SENTINEL_GROUP\r\n            data-type: json\r\n            rule-type: degrade\r\n                \r\nmybatis-plus:\r\n  configuration:\r\n    # 驼峰下划线转换\r\n    map-underscore-to-camel-case: true\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\r\n\r\nfeign:\r\n  httpclient:\r\n    enabled: true\r\n  okhttp:\r\n    enabled: false\r\n  sentinel:  # 开启feign对sentinel的支持\r\n    enabled: false \r\n\r\n# 安全配置\r\nsecurity:\r\n  # 允许无需认证的路径列表\r\n  whitelist-paths:\r\n    # 获取系统用户的认证信息用于账号密码判读\r\n    - /api/v1/users/{username}/authInfo\r\n    - /api/v1/users/{username}/UserAuthCredentials\r\n\r\n# springdoc-openapi项目配置\r\nspringdoc:\r\n  swagger-ui:\r\n    path: /swagger-ui.html\r\n    tags-sorter: alpha\r\n    operations-sorter: alpha\r\n  api-docs:\r\n    path: /v3/api-docs\r\n  group-configs:\r\n    - group: \'default\'\r\n      paths-to-match: \'/**\'\r\n      packages-to-scan: \r\n        - com.aioveu.system.controller\r\n        - com.aioveu.common.file.controller\r\n  # Api文档信息\r\n  info:\r\n    title: 系统服务\r\n    version: 3.0.0\r\n    description: 用户、部门、角色、菜单、字典等接口\r\n    contact:\r\n      name: aioveu\r\n      url: https://www.aioveu.com\r\n      email: ambitiouschild@qq.com\r\n    license:\r\n      name: Apache 2.0\r\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\r\n\r\n# knife4j的增强配置，不需要增强可以不配\r\nknife4j:\r\n  enable: false\r\n  setting:\r\n    language: zh_cn\r\n\r\n\r\n\r\n# 文件存储\r\noss:\r\n  # OSS 类型 (目前支持aliyun、minio)\r\n  type: minio\r\n  # MinIO 对象存储服务\r\n  minio:\r\n    # 服务Endpoint  #minio:9000 \r\n    endpoint:  minio:9000\r\n    # 访问凭据\r\n    access-key: minioadminlss\r\n    # 凭据密钥\r\n    secret-key: minioadminlss\r\n    # 存储桶名称\r\n    bucket-name: aioveu\r\n    # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\r\n    custom-domain:  https://minio.aioveu.com\r\n  # 阿里云OSS对象存储服务\r\n  aliyun:\r\n    # 服务Endpoint\r\n    endpoint: oss-cn-hangzhou.aliyuncs.com\r\n    # 访问凭据\r\n    access-key-id: your-access-key-id\r\n    # 凭据密钥\r\n    access-key-secret: your-access-key-secret\r\n    # 存储桶名称\r\n    bucket-name: default\r\n\r\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\r\nmail:\r\n  host: smtp.qq.com\r\n  port: 587  #465 # 或587\r\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\r\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\r\n  properties:\r\n    mail:\r\n      smtp:\r\n        auth: true\r\n        ssl: true   # 465端口必开\r\n        starttls:\r\n          enable: true    # 587端口必开\r\n  # 邮件发送者\r\n  from: ambitiouschild@qq.com', '87a0c21a6f4e471a9d167bb875d1ecd3', '2010-05-05 00:00:00', '2026-02-23 16:02:38', NULL, '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (259, 275, 'aioveu-tenant.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_tenant?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: minio\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint  #minio:9000 \n    endpoint:  minio:9000\n    # 访问凭据\n    access-key: minioadminlss\n    # 凭据密钥\n    secret-key: minioadminlss\n    # 存储桶名称\n    bucket-name: aioveu\n    # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    # 服务Endpoint\n    endpoint: oss-cn-hangzhou.aliyuncs.com\n    # 访问凭据\n    access-key-id: your-access-key-id\n    # 凭据密钥\n    access-key-secret: your-access-key-secret\n    # 存储桶名称\n    bucket-name: default\n\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\nmail:\n  host: smtp.qq.com\n  port: 587  #465 # 或587\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\n  properties:\n    mail:\n      smtp:\n        auth: true\n        ssl: true   # 465端口必开\n        starttls:\n          enable: true    # 587端口必开\n  # 邮件发送者\n  from: ambitiouschild@qq.com', '7918171b286b68f6afb6cf017119fbcb', '2010-05-05 00:00:00', '2026-02-23 16:10:48', NULL, '172.18.0.1', 'U', '', '');
