INSERT INTO `his_config_info` VALUES (259, 278, 'aioveu-tenant.yaml', 'AIOVEU_GROUP', '', 'spring:\n\n  # datasource:\n  #   type: com.alibaba.druid.pool.DruidDataSource\n  #   driver-class-name: com.mysql.cj.jdbc.Driver \n  #   url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_tenant?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n  #   username: ${mysql.username}\n  #   password: ${mysql.password}\n  # data:\n  #   redis:\n  #     database: ${redis.database}\n  #     host: ${redis.host}\n  #     port: ${redis.port}\n  #     password: ${redis.password}\n  #     lettuce:\n  #       pool:\n  #         min-idle: 1\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://localhost:3308/aioveu_tenant?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: root\n    password: 7758258\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  # 这两个配置必须要有！\n  mapper-locations: classpath*:/mapper/**/*.xml\n  type-aliases-package: com.aioveu.**.entity\n\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: minio\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint  #minio:9000 \n    endpoint:  minio:9000\n    # 访问凭据\n    access-key: minioadminlss\n    # 凭据密钥\n    secret-key: minioadminlss\n    # 存储桶名称\n    bucket-name: aioveu\n    # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    # 服务Endpoint\n    endpoint: oss-cn-hangzhou.aliyuncs.com\n    # 访问凭据\n    access-key-id: your-access-key-id\n    # 凭据密钥\n    access-key-secret: your-access-key-secret\n    # 存储桶名称\n    bucket-name: default\n\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\nmail:\n  host: smtp.qq.com\n  port: 587  #465 # 或587\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\n  properties:\n    mail:\n      smtp:\n        auth: true\n        ssl: true   # 465端口必开\n        starttls:\n          enable: true    # 587端口必开\n  # 邮件发送者\n  from: ambitiouschild@qq.com', 'd329fa255bef490c19100a7f0d77f16c', '2010-05-05 00:00:00', '2026-02-23 16:29:02', NULL, '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (259, 279, 'aioveu-tenant.yaml', 'AIOVEU_GROUP', '', 'spring:\n\n  # datasource:\n  #   type: com.alibaba.druid.pool.DruidDataSource\n  #   driver-class-name: com.mysql.cj.jdbc.Driver \n  #   url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_tenant?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n  #   username: ${mysql.username}\n  #   password: ${mysql.password}\n  # data:\n  #   redis:\n  #     database: ${redis.database}\n  #     host: ${redis.host}\n  #     port: ${redis.port}\n  #     password: ${redis.password}\n  #     lettuce:\n  #       pool:\n  #         min-idle: 1\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://localhost:3308/aioveu_tenant?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: root\n    password: 7758258\n  data:\n    redis:\n      database: 0\n      host: localhost\n      port: 6379\n      password: 775825\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  # rabbitmq:\n  #   host: ${rabbitmq.host}\n  #   port: ${rabbitmq.port}\n  #   username: ${rabbitmq.username}\n  #   password: ${rabbitmq.password}\n  #   virtual-host: /\n  #   listener:\n  #     simple:\n  #       acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  # 这两个配置必须要有！\n  mapper-locations: classpath*:/mapper/**/*.xml\n  type-aliases-package: com.aioveu.**.entity\n\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: minio\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint  #minio:9000 \n    endpoint:  minio:9000\n    # 访问凭据\n    access-key: minioadminlss\n    # 凭据密钥\n    secret-key: minioadminlss\n    # 存储桶名称\n    bucket-name: aioveu\n    # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    # 服务Endpoint\n    endpoint: oss-cn-hangzhou.aliyuncs.com\n    # 访问凭据\n    access-key-id: your-access-key-id\n    # 凭据密钥\n    access-key-secret: your-access-key-secret\n    # 存储桶名称\n    bucket-name: default\n\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\nmail:\n  host: smtp.qq.com\n  port: 587  #465 # 或587\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\n  properties:\n    mail:\n      smtp:\n        auth: true\n        ssl: true   # 465端口必开\n        starttls:\n          enable: true    # 587端口必开\n  # 邮件发送者\n  from: ambitiouschild@qq.com', '0fcdf2194beaf5bbbfeafcef6f04677e', '2010-05-05 00:00:00', '2026-02-23 16:29:48', NULL, '172.18.0.1', 'U', '', '');
