域名\n    cdn-domain: minio.aioveu.com  \n', 'acaa7a9b533d21587bed5cb7981f05f2', '2010-05-05 00:00:00', '2026-03-01 18:09:46', NULL, '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (165, 302, 'aioveu-lss', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_lss?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: aliyun\n  # MinIO 对象存储服务\n  # minio:\n  #   # 服务Endpoint  #minio:9000 \n  #   endpoint:  minio:9000\n  #   # 访问凭据\n  #   access-key: minioadminlss\n  #   # 凭据密钥\n  #   secret-key: minioadminlss\n  #   # 存储桶名称\n  #   bucket-name: aioveu\n  #   # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n  #   custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    tenant-id: 1001  # 添加到这里\n    # 服务Endpoint   # ❌ 错误：内网地址（只能在阿里云ECS内访问） oss-cn-shanghai-internal.aliyuncs.com\n    # ✅ 正确：公网地址\n    endpoint:  oss-cn-shanghai.aliyuncs.com\n    # 访问凭据\n    access-key-id: LTAI5tDVP4BURrY9VtAE66K2\n    # 凭据密钥\n    access-key-secret: cOpi8YlxjJKmxoPG7D8j2592fC2iSD\n    # 存储桶名称\n    bucket-name: aioveu\n    # 新增：加速域名配置  # 替换为您的实际加速域名\n    cdn-domain: minio.aioveu.com  \n', 'acaa7a9b533d21587bed5cb7981f05f2', '2010-05-05 00:00:00', '2026-03-01 19:39:45', NULL, '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (165, 303, 'aioveu-lss', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_lss?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: aliyun\n  # MinIO 对象存储服务\n  # minio:\n  #   # 服务Endpoint  #minio:9000 \n  #   endpoint:  minio:9000\n  #   # 访问凭据\n  #   access-key: minioadminlss\n  #   # 凭据密钥\n  #   secret-key: minioadminlss\n  #   # 存储桶名称\n  #   bucket-name: aioveu\n  #   # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n  #   custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    tenant-id: 1001  # 添加到这里\n    # 服务Endpoint   # ❌ 错误：内网地址（只能在阿里云ECS内访问） oss-cn-shanghai-internal.aliyuncs.com\n    # ✅ 正确：公网地址\n    endpoint:  oss-cn-shanghai.aliyuncs.com\n    # 访问凭据\n    access-key-id: LTAI5tDVP4BURrY9VtAE66K2\n    # 凭据密钥\n    access-key-secret: cOpi8YlxjJKmxoPG7D8j2592fC2iSD\n    # 存储桶名称\n    bucket-name: aioveu\n    # 新增：加速域名配置  # 替换为您的实际加速域名\n    cdn-domain: minio.aioveu.com \n    cdn-region: cn-shanghai \n', 'da80e1d128e22a443c55642b7567c344', '2010-05-05 00:00:00', '2026-03-02 19:01:05', 'nacos', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (2, 304, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: http://localhost:8848\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n\n', '7bdff21d9f0cc2e7b642d9a1da0d5469', '2010-05-05 00:00:00', '2026-03-08 10:39:49', 'nacos', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (2, 305, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: http://localhost:8848\n  namespace: public\n  group: SEATA_GROUP\n  application: seata-server\n  data-id: seataServer.properties\n  username: nacos\n  password: nacos\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000\n\n', 'fc732162ef9d42eebf0c8e01427e1499', '2010-05-05 00:00:00', '2026-03-08 10:40:52', 'nacos', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (1, 306, 'aioveu-auth.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_oauth2_server?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n \nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\n# 微信小程序\nwx:\n  miniapp:\n    appId: wx977b2949b7095b11\n    appSecret: 4bf78af93a8ce49f2de5384ede86be63\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.auth.controller\n  # Api文档信息\n  info:\n    title: 认证服务\n    version: 3.0.0\n    description: 认证、登出、验证码接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n# 验证码配置\ncaptcha:\n  # 验证码类型 circle-圆圈干扰验证码|gif-Gif验证码|line-干扰线验证码|shear-扭曲干扰验证码\n  type: circle\n  # 验证码宽度\n  width: 120\n  # 验证码高度\n  height: 40\n  # 验证码干扰元素个数\n  interfere-count: 2\n  # 文本透明度(0.0-1.0)\n  text-alpha: 0.8\n  # 验证码字符配置\n  code:\n    # 验证码字符类型 math-算术|random-随机字符\n    type: math\n    # 验证码字符长度，type=算术时，表示运算位数(1:个位数运算 2:十位数运算)；type=随机字符时，表示字符个数\n    length: 1\n  # 验证码字体\n  font:\n    # 字体名称 Dialog|DialogInput|Monospaced|Serif|SansSerif\n    name: SansSerif\n    # 字体样式 0-普通|1-粗体|2-斜体\n    weight: 1\n    # 字体大小\n    size: 24\n  # 验证码有效期(秒)\n  expire-seconds: 120\n\nsecurity:\n  whitelist-paths:\n    - /api/v1/auth/captcha\n    - /api/v1/auth/sms_code', '4fcbe5a5f5ab9d931c4911d50c76a152', '2010-05-05 00:00:00', '2026-03-08 10:41:46', 'nacos', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (3, 307, 'aioveu-gateway.yaml', 'AIOVEU_GROUP', '', 'spring:\n  data:\n    redis:\n      timeout: PT30S\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          # 连接池最小空闲连接数\n          min-idle: 1\n  cloud:\n    gateway:\n      discovery:\n        locator:\n          enabled: true # 启用服务发现\n          lower-case-service-id: true\n      default-filters:\n        # 令牌中继\n        - TokenRelay= \n      routes:\n        - id: 认证中心\n          uri: lb://aioveu-auth\n          predicates:\n            - Path=/aioveu-auth/**\n          filters:\n            - StripPrefix=1            \n        - id: 系统服务\n          uri: lb://aioveu-system\n          predicates:\n            - Path=/aioveu-system/**\n          filters:\n            - StripPrefix=1            \n      globalcors:\n        corsConfigurations:\n          \'[/**]\': # 对所有路由应用CORS配置\n            # 允许所有域名的请求\n            allowedOriginPatterns: \"*\"\n            # 允许所有请求方法，如GET、POST、PUT、DELETE等\n            allowedMethods: \"*\"\n             # 允许所有请求头\n            allowedHeaders: \"*\" \n            # 允许凭证，如Cookies和HTTP认证\n            allowCredentials: true   \n            maxAge: 3600\n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n\n# 安全配置\nsecurity:\n  # 访问黑名单\n  blacklist-paths:\n      # 获取用户认证信息\n      - /aioveu-system/api/v1/users/{username}/authInfo\n      - /aioveu-lss/api/v1/users/{username}/UserAuthCredentials\n\n# knife4j 网关聚合  \n# https://doc.xiaominfo.com/docs/middleware-sources/spring-cloud-gateway/spring-gateway-introduction\nknife4j:\n  gateway:\n    enabled: true\n    # 指定服务发现的模式聚合微服务文档，并且是默认`default`分组\n    strategy: discover\n    discover:\n      enabled: true\n      # 聚合所有子服务(swagger2规范)，子服务是3规范则替换为openapi3\n      version: openapi3\n      # 需要排除的微服务(eg:网关服务) \n      excluded-services:\n          - aioveu-gateway\n\n', 'aafcb9387d3ee7714c20fe3de5d17001', '2010-05-05 00:00:00', '2026-03-08 10:42:28', 'nacos', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (214, 308, 'aioveu-pms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: pms-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n  registry:\n    type: nacos\n    nacos:\n      application: aioveu-seata-server\n      server-addr: ${nacos.server-addr}\n      namespace: a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef \n      group: SEATA_GROUP \n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 商品服务\n    version: 3.0.0\n    description: 库存、分类、品牌、规格、参数等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', '2fd3239cc682381713d776305c0f21d7', '2010-05-05 00:00:00', '2026-03-08 11:10:38', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (214, 309, 'aioveu-pms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: pms-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n    #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n  \n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 商品服务\n    version: 3.0.0\n    description: 库存、分类、品牌、规格、参数等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', 'f8bf904f0c32119674f6972bb2e53ea1', '2010-05-05 00:00:00', '2026-03-08 11:10:52', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (2, 310, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n          \n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          max-active: 8\n          max-idle: 5\n          min-idle: 2\n          max-wait: 1000ms\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: http://localhost:8848\n  namespace: public\n  group: SEATA_GROUP\n  application: seata-server\n  data-id: seataServer.properties\n  username: nacos\n  password: nacos\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000\n\n', '155bbbb513280c6243fd4e641eeb14a3', '2010-05-05 00:00:00', '2026-03-08 11:13:34', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (5, 311, 'aioveu-pms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: pms-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n  registry:\n    type: nacos\n    nacos:\n      application: aioveu-seata-server\n      server-addr: ${nacos.server-addr}\n      namespace:\n      group: SEATA_GROUP \n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 商品服务\n    version: 3.0.0\n    description: 库存、分类、品牌、规格、参数等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', '43b8312825d5afe62db32e6b8390e3e7', '2010-05-05 00:00:00', '2026-03-08 11:16:52', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (5, 312, 'aioveu-pms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: pms-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n  registry:\n    type: nacos\n    nacos:\n      application: aioveu-seata-server\n      server-addr: ${nacos.server-addr}\n      namespace:\n      group: SEATA_GROUP \n  \n    #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 商品服务\n    version: 3.0.0\n    description: 库存、分类、品牌、规格、参数等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', '0bc4f75d89ba3cc553a080bd75825601', '2010-05-05 00:00:00', '2026-03-08 11:17:40', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (4, 313, 'aioveu-oms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource: \n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_oms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: oms-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n #   grouplist:\n #     default: host.docker.internal:8091  \n      # 使用特殊主机名  #理论上Seata客户端应该通过Nacos获取服务端地址。但是，\n      #如果配置了service.grouplist，则会直接使用该地址，而忽略注册中心。如果希望使用注册中心，可以不配置service.grouplist，而是让客户端从注册中心获取服务端地址。\n  registry:\n    type: nacos\n    nacos:\n      application: aioveu-seata-server\n      server-addr: ${nacos.server-addr}\n      namespace:\n      group: SEATA_GROUP \n\n\n  # 添加网络超时参数\n  client:\n    tm:\n      queryTimeout: 3000\n      connectTimeout: 5000\n    rm:\n      asynCommitBufferLimit: 5000\n# 不配置grouplist，使用注册中心获取\n#Seata服务器容器IP是172.19.0.4，但OMS运行在宿主机上，宿主机无法直接访问容器的私有IP（172.19.0.4）\n#应该使用宿主机IP或host.docker.internal进行连接\n#OMS服务尝试直接连接Docker内部IP 172.19.0.4:8091，而OMS在宿主机运行，无法访问Docker网络。同时出现连接超时异常\n\n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false\n\n# 安全配置\nsecurity:\n  # 白名单路径\n  whitelist-path:\n      - /app-api/v1/carts\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.oms.controller\n  # Api文档信息\n  info:\n    title: 订单服务\n    version: 3.0.0\n    description: 订单、购物车等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true\n\n# 模拟支付配置\npay:\n  mock:\n    enabled: true           # 启用模拟支付\n    auto-success: true      # 自动成功\n    delay: 1000             # 模拟延迟1秒\n    success-rate: 100       # 成功率100%\n\nwx:\n  pay:\n    # 必需配置\n    app-id: wx1234567890abcdef      # 你的微信小程序AppId\n    mch-id: 1230000109               # 你的商户号\n    mch-key: your-mch-key-32-chars   # API密钥，32位\n    notify-url: https://your-domain.com/api/wxpay/notify\n    \n    # 可选配置\n    sign-type: MD5                   # 签名类型：MD5 或 RSA\n    sandbox-enabled: false           # 是否使用沙箱环境\n    \n    # 以下为可选证书配置（如果需要）\n    # key-path: classpath:/cert/apiclient_cert.p12\n    # private-key-path: classpath:/cert/apiclient_key.pem\n    # private-cert-path: classpath:/cert/apiclient_cert.pem\n    # api-v3-key: your-api-v3-key\n    # cert-serial-no: your-cert-serial-no\n    \n    # 兼容字段\n    # pay-notify-url: https://your-domain.com/api/wxpay/notify', '62b9417024320415827d4cdf1225702b', '2010-05-05 00:00:00', '2026-03-08 11:26:57', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (4, 314, 'aioveu-oms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource: \n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_oms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: oms-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n  #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n\n  # 添加网络超时参数\n  client:\n    tm:\n      queryTimeout: 3000\n      connectTimeout: 5000\n    rm:\n      asynCommitBufferLimit: 5000\n# 不配置grouplist，使用注册中心获取\n#Seata服务器容器IP是172.19.0.4，但OMS运行在宿主机上，宿主机无法直接访问容器的私有IP（172.19.0.4）\n#应该使用宿主机IP或host.docker.internal进行连接\n#OMS服务尝试直接连接Docker内部IP 172.19.0.4:8091，而OMS在宿主机运行，无法访问Docker网络。同时出现连接超时异常\n\n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false\n\n# 安全配置\nsecurity:\n  # 白名单路径\n  whitelist-path:\n      - /app-api/v1/carts\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.oms.controller\n  # Api文档信息\n  info:\n    title: 订单服务\n    version: 3.0.0\n    description: 订单、购物车等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true\n\n# 模拟支付配置\npay:\n  mock:\n    enabled: true           # 启用模拟支付\n    auto-success: true      # 自动成功\n    delay: 1000             # 模拟延迟1秒\n    success-rate: 100       # 成功率100%\n\nwx:\n  pay:\n    # 必需配置\n    app-id: wxe510ad6d4d60bfa8      # 你的微信小程序AppId\n    mch-id: 1107195457               # 你的商户号\n    mch-key: dCzmYhzYcCEyRyiHp9Z9MTVMRYoSYwVj   # API密钥，32位\n    notify-url: https://aioveu.com/api/wxpay/notify\n    \n    # 可选配置\n    sign-type: MD5                   # 签名类型：MD5 或 RSA\n    sandbox-enabled: false           # 是否使用沙箱环境\n    \n    # 以下为可选证书配置（如果需要）\n    # key-path: classpath:/cert/apiclient_cert.p12\n    # private-key-path: classpath:/cert/apiclient_key.pem\n    # private-cert-path: classpath:/cert/apiclient_cert.pem\n    # api-v3-key: your-api-v3-key\n    # cert-serial-no: your-cert-serial-no\n    \n    # 兼容字段\n    # pay-notify-url: https://your-domain.com/api/wxpay/notify', 'bfba6998fcca1b4d656bd1fec261b0f0', '2010-05-05 00:00:00', '2026-03-08 11:27:03', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (6, 315, 'aioveu-sms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_sms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\nmybatis-plus:\n  type-enums-package: com.aioveu.sms.common.enums\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: sms-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n #   grouplist:\n #     default: host.docker.internal:8091  \n      # 使用特殊主机名  #理论上Seata客户端应该通过Nacos获取服务端地址。但是，\n      #如果配置了service.grouplist，则会直接使用该地址，而忽略注册中心。如果希望使用注册中心，可以不配置service.grouplist，而是让客户端从注册中心获取服务端地址。\n  registry:\n    type: nacos\n    nacos:\n      application: aioveu-seata-server\n      server-addr: ${nacos.server-addr}\n      namespace:\n      group: SEATA_GROUP \n      \n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n      - /app-api/v1/adverts/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.sms.controller\n  # Api文档信息\n  info:\n    title: 营销服务\n    version: 3.0.0\n    description: 广告、优惠券等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', '6856972bee34364e90b7f62ac9127e3d', '2010-05-05 00:00:00', '2026-03-08 11:50:15', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (8, 316, 'aioveu-ums.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_ums?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: ums-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n  registry:\n    type: nacos\n    nacos:\n      application: aioveu-seata-server\n      server-addr: ${nacos.server-addr}\n      namespace:\n      group: SEATA_GROUP \n\n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false\n\n# 安全配置\nsecurity:\n  # 白名单路径\n  whitelist-paths:\n      - /app-api/v1/members/openid/{openid}\n      - /app-api/v1/members/mobile/{mobile}\n      - /app-api/v1/members\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.ums.controller\n  # Api文档信息\n  info:\n    title: 会员服务\n    version: 3.0.0\n    description: 会员、地址等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能 # 设置为 true 表示开启增强功能\n  enable: true \n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', '50aa76313d3a64a373a830b15ed4ab53', '2010-05-05 00:00:00', '2026-03-08 11:55:14', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (4, 317, 'aioveu-oms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource: \n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_oms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: oms-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n  #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n\n  # 添加网络超时参数\n  client:\n    tm:\n      queryTimeout: 3000\n      connectTimeout: 5000\n    rm:\n      asynCommitBufferLimit: 5000\n# 不配置grouplist，使用注册中心获取\n#Seata服务器容器IP是172.19.0.4，但OMS运行在宿主机上，宿主机无法直接访问容器的私有IP（172.19.0.4）\n#应该使用宿主机IP或host.docker.internal进行连接\n#OMS服务尝试直接连接Docker内部IP 172.19.0.4:8091，而OMS在宿主机运行，无法访问Docker网络。同时出现连接超时异常\n\n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false\n\n# 安全配置\nsecurity:\n  # 白名单路径\n  whitelist-path:\n      - /app-api/v1/carts\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.oms.controller\n  # Api文档信息\n  info:\n    title: 订单服务\n    version: 3.0.0\n    description: 订单、购物车等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true\n\n# 模拟支付配置\npay:\n  mock:\n    enabled: true           # 启用模拟支付\n    auto-success: true      # 自动成功\n    delay: 1000             # 模拟延迟1秒\n    success-rate: 100       # 成功率100%\n\nwx:\n  pay:\n    # 必需配置\n    app-id: wxe510ad6d4d60bfa8      # 你的微信小程序AppId\n    mch-id: 1107195457               # 你的商户号\n    mch-key: dCzmYhzYcCEyRyiHp9Z9MTVMRYoSYwVj   # API密钥，32位\n    notify-url: https://aioveu.com/api/wxpay/notify\n    \n    # 可选配置\n    sign-type: MD5                   # 签名类型：MD5 或 RSA\n    sandbox-enabled: false           # 是否使用沙箱环境\n    \n    # 以下为可选证书配置（如果需要）\n    # key-path: classpath:/cert/apiclient_cert.p12\n    # private-key-path: classpath:/cert/apiclient_key.pem\n    # private-cert-path: classpath:/cert/apiclient_cert.pem\n    # api-v3-key: your-api-v3-key\n    # cert-serial-no: your-cert-serial-no\n    \n    # 兼容字段\n    # pay-notify-url: https://your-domain.com/api/wxpay/notify', 'bfba6998fcca1b4d656bd1fec261b0f0', '2010-05-05 00:00:00', '2026-03-08 18:33:32', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (2, 318, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n          \n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          max-active: 8\n          max-idle: 5\n          min-idle: 2\n          max-wait: 1000ms\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: http://localhost:8848\n  namespace: public\n  group: SEATA_GROUP\n  application: aioveu-seata-server\n  data-id: seataServer.properties\n  username: nacos\n  password: nacos\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000\n\n', 'f41e9e12894e9978adc3a0376ed28baf', '2010-05-05 00:00:00', '2026-03-08 18:35:18', 'aioveu', '172.18.0.1', 'U', '', '');
