INSERT INTO `his_config_info` VALUES (2, 320, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n          \n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          max-active: 8\n          max-idle: 5\n          min-idle: 2\n          max-wait: 1000ms\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: http://localhost:8848\n  namespace: public\n  group: SEATA_GROUP\n  application: aioveu-seata-server\n  data-id: seataServer.properties\n  username: nacos\n  password: nacos\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000\n\n', 'f41e9e12894e9978adc3a0376ed28baf', '2010-05-05 00:00:00', '2026-03-08 18:42:13', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (5, 321, 'aioveu-pms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: pms-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n  #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 商品服务\n    version: 3.0.0\n    description: 库存、分类、品牌、规格、参数等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', 'a0ff741bee4427c21f47602f4ff8a916', '2010-05-05 00:00:00', '2026-03-08 18:44:38', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (5, 322, 'aioveu-pms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: pms-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  # service:\n  #   # 事务分组映射，根据分组名称匹配到集群\n  #   vgroup-mapping:\n  #     # 事务分组名称：集群名称\n  #     # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n  #     default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n  #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 商品服务\n    version: 3.0.0\n    description: 库存、分类、品牌、规格、参数等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', 'b32a68902de01e31e63fcde0ceb62746', '2010-05-05 00:00:00', '2026-03-08 19:02:28', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (2, 323, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n          \n  data:\n    redis:\n      # database: ${redis.database}\n      # host: ${redis.host}\n      # port: ${redis.port}\n      # password: ${redis.password}\n      lettuce:\n        pool:\n          max-active: 8\n          max-idle: 5\n          min-idle: 2\n          max-wait: 1000ms\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: http://localhost:8848\n  namespace: public\n  group: SEATA_GROUP\n  application: aioveu-seata-server\n  data-id: seataServer.properties\n  username: nacos\n  password: nacos\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000\n\n', 'd7fc137d738c7c2c7e12f4bf50e7d794', '2010-05-05 00:00:00', '2026-03-08 19:02:46', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (2, 324, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n          \n  data:\n    redis:\n      # database: ${redis.database}\n      # host: ${redis.host}\n      # port: ${redis.port}\n      # password: ${redis.password}\n      lettuce:\n        pool:\n          max-active: 8\n          max-idle: 5\n          min-idle: 2\n          max-wait: 1000ms\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: http://localhost:8848\n  namespace: public\n  group: SEATA_GROUP\n  application: aioveu-seata-server\n  dataId: seataServer.properties\n  username: nacos\n  password: nacos\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000\n\n', '35638452a078eadaccd6d40b3b7de92b', '2010-05-05 00:00:00', '20