ent.rm.sagaBranchRegisterEnable=false\r\nclient.rm.sagaJsonParser=fastjson\r\nclient.rm.tccActionInterceptorOrder=-2147482648\r\nclient.tm.commitRetryCount=5\r\nclient.tm.rollbackRetryCount=5\r\nclient.tm.defaultGlobalTransactionTimeout=60000\r\nclient.tm.degradeCheck=false\r\nclient.tm.degradeCheckAllowTimes=10\r\nclient.tm.degradeCheckPeriod=2000\r\nclient.tm.interceptorOrder=-2147482648\r\nclient.undo.dataValidation=true\r\nclient.undo.logSerialization=jackson\r\nclient.undo.onlyCareUpdateColumns=true\r\nserver.undo.logSaveDays=7\r\nserver.undo.logDeletePeriod=86400000\r\nclient.undo.logTable=undo_log\r\nclient.undo.compress.enable=true\r\nclient.undo.compress.type=zip\r\nclient.undo.compress.threshold=64k\r\n#For TCC transaction mode\r\ntcc.fence.logTableName=tcc_fence_log\r\ntcc.fence.cleanPeriod=1h\r\n\r\n#Log rule configuration, for client and server\r\nlog.exceptionRate=100\r\n\r\n#Transaction storage configuration, only for the server. The file, db, and redis configuration values are optional.\r\nstore.mode=db\r\nstore.lock.mode=db\r\nstore.session.mode=db\r\n#Used for password encryption\r\n#store.publicKey=\r\n\r\n#If `store.mode,store.lock.mode,store.session.mode` are not equal to `file`, you can remove the configuration block.\r\nstore.file.dir=file_store/data\r\nstore.file.maxBranchSessionSize=16384\r\nstore.file.maxGlobalSessionSize=512\r\nstore.file.fileWriteBufferCacheSize=16384\r\nstore.file.flushDiskMode=async\r\nstore.file.sessionReloadReadSize=100\r\n\r\nlock.db.lockValueMaxLength=256\r\nlock.db.rowKeyMaxLength=256\r\n\r\n#These configurations are required if the `store mode` is `db`. If `store.mode,store.lock.mode,store.session.mode` are not equal to `db`, you can remove the configuration block.\r\nstore.db.datasource=druid\r\nstore.db.dbType=mysql\r\nstore.db.driverClassName=com.mysql.cj.jdbc.Driver\r\nstore.db.url=jdbc:mysql://mysql:3306/aioveu_seata?useUnicode=true&rewriteBatchedStatements=true\r\nstore.db.user=root\r\nstore.db.password=775825\r\nstore.db.minConn=5\r\nstore.db.maxConn=30\r\nstore.db.globalTable=global_table\r\nstore.db.branchTable=branch_table\r\nstore.db.distributedLockTable=distributed_lock\r\nstore.db.queryLimit=100\r\nstore.db.lockTable=lock_table\r\nstore.db.maxWait=5000\r\n\r\n#These configurations are required if the `store mode` is `redis`. If `store.mode,store.lock.mode,store.session.mode` are not equal to `redis`, you can remove the configuration block.\r\n#store.redis.mode=single\r\n#store.redis.single.host=127.0.0.1\r\n#store.redis.single.port=6379\r\n#store.redis.sentinel.masterName=\r\n#store.redis.sentinel.sentinelHosts=\r\n#store.redis.maxConn=10\r\n#store.redis.minConn=1\r\n#store.redis.maxTotal=100\r\n#store.redis.database=0\r\n#store.redis.password=\r\n#store.redis.queryLimit=100\r\n\r\n#Transaction rule configuration, only for the server\r\nserver.recovery.committingRetryPeriod=1000\r\nserver.recovery.asynCommittingRetryPeriod=1000\r\nserver.recovery.rollbackingRetryPeriod=1000\r\nserver.recovery.timeoutRetryPeriod=1000\r\nserver.maxCommitRetryTimeout=-1\r\nserver.maxRollbackRetryTimeout=-1\r\nserver.rollbackRetryTimeoutUnlockEnable=false\r\nserver.distributedLockExpireTime=10000\r\nserver.xaerNotaRetryTimeout=60000\r\nserver.session.branchAsyncQueueSize=5000\r\nserver.session.enableBranchAsyncRemove=false\r\nserver.enableParallelRequestHandle=false\r\n\r\n#Metrics configuration, only for the server\r\nmetrics.enabled=false\r\nmetrics.registryType=compact\r\nmetrics.exporterList=prometheus\r\nmetrics.exporterPrometheusPort=9898', 'bd6682d4c5343e05bc8f57d4d112ca1a', '2010-05-05 00:00:00', '2026-03-09 13:42:19', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (265, 361, 'seataServer.properties', 'SEATA_GROUP', '', '\n#seata.ip=192.168.1.5\n#seata.port=8091\n\n\n#For details about configuration items, see https://seata.io/zh-cn/docs/user/configurations.html\n#Transport configuration, for client and server\ntransport.type=TCP\ntransport.server=NIO\ntransport.heartbeat=true\ntransport.enableTmClientBatchSendRequest=false\ntransport.enableRmClientBatchSendRequest=true\ntransport.enableTcServerBatchSendResponse=false\ntransport.rpcRmRequestTimeout=30000\ntransport.rpcTmRequestTimeout=30000\ntransport.rpcTcRequestTimeout=30000\ntransport.threadFactory.bossThreadPrefix=NettyBoss\ntransport.threadFactory.workerThreadPrefix=NettyServerNIOWorker\ntransport.threadFactory.serverExecutorThreadPrefix=NettyServerBizHandler\ntransport.threadFactory.shareBossWorker=false\ntransport.threadFactory.clientSelectorThreadPrefix=NettyClientSelector\ntransport.threadFactory.clientSelectorThreadSize=1\ntransport.threadFactory.clientWorkerThreadPrefix=NettyClientWorkerThread\ntransport.threadFactory.bossThreadSize=1\ntransport.threadFactory.workerThreadSize=default\ntransport.shutdown.wait=3\ntransport.serialization=seata\ntransport.compressor=none\n\n#Transaction routing rules configuration, only for the client\nservice.vgroupMapping.default_tx_group=default\n#If you use a registry, you can ignore it\n#service.default.grouplist=aioveu-seata-server:8091\n#service.enableDegrade=false\n#service.disableGlobalTransaction=false\n\n#Transaction rule configuration, only for the client\nclient.rm.asyncCommitBufferLimit=10000\nclient.rm.lock.retryInterval=10\nclient.rm.lock.retryTimes=30\nclient.rm.lock.retryPolicyBranchRollbackOnConflict=true\nclient.rm.reportRetryCount=5\nclient.rm.tableMetaCheckEnable=true\nclient.rm.tableMetaCheckerInterval=60000\nclient.rm.sqlParserType=druid\nclient.rm.reportSuccessEnable=false\nclient.rm.sagaBranchRegisterEnable=false\nclient.rm.sagaJsonParser=fastjson\nclient.rm.tccActionInterceptorOrder=-2147482648\nclient.tm.commitRetryCount=5\nclient.tm.rollbackRetryCount=5\nclient.tm.defaultGlobalTransactionTimeout=60000\nclient.tm.degradeCheck=false\nclient.tm.degradeCheckAllowTimes=10\nclient.tm.degradeCheckPeriod=2000\nclient.tm.interceptorOrder=-2147482648\nclient.undo.dataValidation=true\nclient.undo.logSerialization=jackson\nclient.undo.onlyCareUpdateColumns=true\nserver.undo.logSaveDays=7\nserver.undo.logDeletePeriod=86400000\nclient.undo.logTable=undo_log\nclient.undo.compress.enable=true\nclient.undo.compress.type=zip\nclient.undo.compress.threshold=64k\n#For TCC transaction mode\ntcc.fence.logTableName=tcc_fence_log\ntcc.fence.cleanPeriod=1h\n\n#Log rule configuration, for client and server\nlog.exceptionRate=100\n\n#Transaction storage configuration, only for the server. The file, db, and redis configuration values are optional.\nstore.mode=db\nstore.lock.mode=db\nstore.session.mode=db\n#Used for password encryption\n#store.publicKey=\n\n#If `store.mode,store.lock.mode,store.session.mode` are not equal to `file`, you can remove the configuration block.\nstore.file.dir=file_store/data\nstore.file.maxBranchSessionSize=16384\nstore.file.maxGlobalSessionSize=512\nstore.file.fileWriteBufferCacheSize=16384\nstore.file.flushDiskMode=async\nstore.file.sessionReloadReadSize=100\n\nlock.db.lockValueMaxLength=256\nlock.db.rowKeyMaxLength=256\n\n#These configurations are required if the `store mode` is `db`. If `store.mode,store.lock.mode,store.session.mode` are not equal to `db`, you can remove the configuration block.\nstore.db.datasource=druid\nstore.db.dbType=mysql\nstore.db.driverClassName=com.mysql.cj.jdbc.Driver\nstore.db.url=jdbc:mysql://mysql:3306/aioveu_seata?useUnicode=true&rewriteBatchedStatements=true\nstore.db.user=root\nstore.db.password=775825\nstore.db.minConn=5\nstore.db.maxConn=30\nstore.db.globalTable=global_table\nstore.db.branchTable=branch_table\nstore.db.distributedLockTable=distributed_lock\nstore.db.queryLimit=100\nstore.db.lockTable=lock_table\nstore.db.maxWait=5000\n\n#These configurations are required if the `store mode` is `redis`. If `store.mode,store.lock.mode,store.session.mode` are not equal to `redis`, you can remove the configuration block.\n#store.redis.mode=single\n#store.redis.single.host=127.0.0.1\n#store.redis.single.port=6379\n#store.redis.sentinel.masterName=\n#store.redis.sentinel.sentinelHosts=\n#store.redis.maxConn=10\n#store.redis.minConn=1\n#store.redis.maxTotal=100\n#store.redis.database=0\n#store.redis.password=\n#store.redis.queryLimit=100\n\n#Transaction rule configuration, only for the server\nserver.recovery.committingRetryPeriod=1000\nserver.recovery.asynCommittingRetryPeriod=1000\nserver.recovery.rollbackingRetryPeriod=1000\nserver.recovery.timeoutRetryPeriod=1000\nserver.maxCommitRetryTimeout=-1\nserver.maxRollbackRetryTimeout=-1\nserver.rollbackRetryTimeoutUnlockEnable=false\nserver.distributedLockExpireTime=10000\nserver.xaerNotaRetryTimeout=60000\nserver.session.branchAsyncQueueSize=5000\nserver.session.enableBranchAsyncRemove=false\nserver.enableParallelRequestHandle=false\n\n#Metrics configuration, only for the server\nmetrics.enabled=false\nmetrics.registryType=compact\nmetrics.exporterList=prometheus\nmetrics.exporterPrometheusPort=9898', 'fd25288361998f7499fd2da0b4e84499', '2010-05-05 00:00:00', '2026-03-09 13:43:17', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (2, 362, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n          \n  data:\n    redis:\n      # database: ${redis.database}\n      # host: ${redis.host}\n      # port: ${redis.port}\n      # password: ${redis.password}\n      lettuce:\n        pool:\n          max-active: 8\n          max-idle: 5\n          min-idle: 2\n          max-wait: 1000ms\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: http://localhost:8848\n  namespace: public\n  group: AIOVEU_GROUP\n  application: aioveu-seata-server\n  data-id: seataServer.properties  # 使用短横线\n  username: nacos\n  password: nacos\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000\n\n', '15db44269a699148e378823f9bf3b5b0', '2010-05-05 00:00:00', '2026-03-09 13:43:40', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (266, 363, 'service.vgroupMapping.default_tx_group', 'SEATA_GROUP', '', 'default', 'c21f969b5f03d33d43e04f8f136e7682', '2010-05-05 00:00:00', '2026-03-09 13:45:59', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (2, 364, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n          \n  data:\n    redis:\n      # database: ${redis.database}\n      # host: ${redis.host}\n      # port: ${redis.port}\n      # password: ${redis.password}\n      lettuce:\n        pool:\n          max-active: 8\n          max-idle: 5\n          min-idle: 2\n          max-wait: 1000ms\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: http://localhost:8848\n  namespace: public\n  group: SEATA_GROUP\n  application: aioveu-seata-server\n  data-id: seataServer.properties  # 使用短横线\n  username: nacos\n  password: nacos\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000\n\n', '3fc7185046d6603c81343cd7717dbe1b', '2010-05-05 00:00:00', '2026-03-09 13:47:39', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (5, 365, 'aioveu-pms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: pms-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群  方式2：配置在客户端本地\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n      # 可选：如果不需要自动发现，可以直接指定地址\n    grouplist:\n      default: 127.0.0.1:8091\n# \n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application:aioveu-seata-server}\n      server-addr: ${nacos.server-addr}\n      namespace: public   #你的实际namespaceID  # ← 明确指定，不要用变量\n      group: SEATA_GROUP \n      username: ${nacos.username}\n      password: ${nacos.password}\n            # 可选，添加集群配置\n      cluster: default\n\n  #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: public   #你的实际namespaceID  # ← 明确指定，不要用变量\n      group: ${nacos.group}\n      data-id: seataServer.properties\n      username: ${nacos.username}\n      password: ${nacos.password}\n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 商品服务\n    version: 3.0.0\n    description: 库存、分类、品牌、规格、参数等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', '6ff3df503ad0614303232620f98be762', '2010-05-05 00:00:00', '2026-03-09 13:52:31', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (2, 366, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n          \n  data:\n    redis:\n      # database: ${redis.database}\n      # host: ${redis.host}\n      # port: ${redis.port}\n      # password: ${redis.password}\n      lettuce:\n        pool:\n          max-active: 8\n          max-idle: 5\n          min-idle: 2\n          max-wait: 1000ms\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: http://localhost:8848\n  namespace: public\n  group: SEATA_GROUP\n  application: aioveu-seata-server\n  data-id: seataServer.properties  # 使用短横线\n  username: nacos\n  password: nacos\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n\nlogging:\n  level:\n    io.seata: DEBUG\n    com.alibaba.nacos: DEBUG\n    \n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000\n\n', '9cea2d3c052dbb982a2b0ac7abfbc5a6', '2010-05-05 00:00:00', '2026-03-09 14:31:01', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (5, 367, 'aioveu-pms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: pms-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群  方式2：配置在客户端本地\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n      # 可选：如果不需要自动发现，可以直接指定地址\n    grouplist:\n      default: 127.0.0.1:8091\n# \n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application:aioveu-seata-server}\n      server-addr: ${nacos.server-addr}\n      namespace: public   #你的实际namespaceID  # ← 明确指定，不要用变量\n      group: SEATA_GROUP \n      username: nacos\n      password: nacos\n            # 可选，添加集群配置\n      cluster: default\n\n  #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: public   #你的实际namespaceID  # ← 明确指定，不要用变量\n      group: SEATA_GROUP\n      data-id: seataServer.properties\n      username: nacos\n      password: nacos\n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 商品服务\n    version: 3.0.0\n    description: 库存、分类、品牌、规格、参数等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', 'a18ccf9ecbdedd3df5409bf2779556b8', '2010-05-05 00:00:00', '2026-03-09 14:46:42', 'aioveu', '172.18.0.1', 'U', '', '');
INSERT INTO `his_config_info` VALUES (225, 368, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: redis\n  port: 6379\n  password: 775825\n  \nmysql:\n  host: mysql\n  port: 3306\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: rabbitmq\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n\n# 网关地址\ngateway:\n  endpoint: http://gateway:6666\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: nacos:8848\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n\n', '48d40d7813bb13fa9ff1cb7e4bb123c8', '2010-05-05 00:00:00', '2026-03-09 15:49:22', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (225, 369, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6379\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3306\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: localhost:8848\n  namespace: a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef\n  group: SEATA_GROUP\n  application: seata-server\n  data-id: seataServer.properties\n  username: nacos\n  password: 775825\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000', 'dab509ebee4185acc539394e92be894f', '2010-05-05 00:00:00', '2026-03-09 16:14:11', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (225, 370, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 15672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: localhost:8848\n  namespace: a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef\n  group: SEATA_GROUP\n  application: seata-server\n  data-id: seataServer.properties\n  username: nacos\n  password: 775825\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000', 'ae0743ad0065804a9a8b35f25c60648a', '2010-05-05 00:00:00', '2026-03-09 16:49:59', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (225, 371, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 15672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n\n  datasource:    \n    # 以下是新增的 Druid 连接池配置\n    druid:\n      # 1. 连接池基础配置  # 临时调大，缓解问题\n      initial-size: 20\n      min-idle: 20\n      max-active: 100\n      max-wait: 3000  # 3秒超时，避免请求堆积\n      \n      # 2. 连接有效性检测\n      validation-query: SELECT 1\n      test-while-idle: true\n      test-on-borrow: false\n      test-on-return: false\n      time-between-eviction-runs-millis: 60000\n      min-evictable-idle-time-millis: 300000\n      \n      # 3. 连接泄漏检测\n      remove-abandoned: true\n      remove-abandoned-timeout: 180\n      log-abandoned: true\n      \n      # 4. 监控统计\n      # 访问监控页面 ,如果配置了 stat-view-servlet，可以访问 http://你的IP:端口/druid/index.html\n      filters: stat,wall,slf4j\n      stat-view-servlet:\n        enabled: true\n        login-username: aioveu\n        login-password: 775825\n        url-pattern: /druid/*\n        reset-enable: false\n      \n      # 5. Web监控\n      web-stat-filter:\n        enabled: true\n        url-pattern: /*\n        exclusions: \"*.js,*.gif,*.jpg,*.png,*.css,*.ico,/druid/*\"\n      \n      # 6. Filter配置（关键修正点！）\n      # Druid 的 filter 配置是独立的，不是 spring 的子项\n      # 6. 慢SQL记录  开启慢SQL监控\n      filter:\n        stat:\n          enabled: true\n          log-slow-sql: true\n          slow-sql-millis: 2000   # 超过2秒的SQL记录\n          merge-sql: true\n        # SQL防火墙\n        wall:\n          enabled: true\n          config:\n            multi-statement-allow: true\n            none-base-statement-allow: false\n\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          max-active: 8\n          max-idle: 5\n          min-idle: 2\n          max-wait: 1000ms\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: localhost:8848\n  namespace: a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef\n  group: SEATA_GROUP\n  application: seata-server\n  data-id: seataServer.properties\n  username: nacos\n  password: 775825\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000', '0524e12b6f90dfe7a4a23a0c0ca067f8', '2010-05-05 00:00:00', '2026-03-09 17:01:38', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (208, 372, 'aioveu-auth.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_oauth2_server?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n \nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\n# 微信小程序\nwx:\n  miniapp:\n    appId: wx977b2949b7095b11\n    appSecret: 4bf78af93a8ce49f2de5384ede86be63\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.auth.controller\n  # Api文档信息\n  info:\n    title: 认证服务\n    version: 3.0.0\n    description: 认证、登出、验证码接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n# 验证码配置\ncaptcha:\n  # 验证码类型 circle-圆圈干扰验证码|gif-Gif验证码|line-干扰线验证码|shear-扭曲干扰验证码\n  type: circle\n  # 验证码宽度\n  width: 120\n  # 验证码高度\n  height: 40\n  # 验证码干扰元素个数\n  interfere-count: 2\n  # 文本透明度(0.0-1.0)\n  text-alpha: 0.8\n  # 验证码字符配置\n  code:\n    # 验证码字符类型 math-算术|random-随机字符\n    type: math\n    # 验证码字符长度，type=算术时，表示运算位数(1:个位数运算 2:十位数运算)；type=随机字符时，表示字符个数\n    length: 1\n  # 验证码字体\n  font:\n    # 字体名称 Dialog|DialogInput|Monospaced|Serif|SansSerif\n    name: SansSerif\n    # 字体样式 0-普通|1-粗体|2-斜体\n    weight: 1\n    # 字体大小\n    size: 24\n  # 验证码有效期(秒)\n  expire-seconds: 120\n\nsecurity:\n  whitelist-paths:\n    - /api/v1/auth/captcha\n    - /api/v1/auth/sms_code', '4fcbe5a5f5ab9d931c4911d50c76a152', '2010-05-05 00:00:00', '2026-03-09 17:16:14', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (211, 373, 'aioveu-lss.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_lss?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: minio\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint  #minio:9000 \n    endpoint:  minio.aioveu.com \n    # 访问凭据\n    access-key: minioadminlss\n    # 凭据密钥\n    secret-key: minioadminlss\n    # 存储桶名称\n    bucket-name: aioveu\n    # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    # 服务Endpoint\n    endpoint: oss-cn-hangzhou.aliyuncs.com\n    # 访问凭据\n    access-key-id: your-access-key-id\n    # 凭据密钥\n    access-key-secret: your-access-key-secret\n    # 存储桶名称\n    bucket-name: default\n\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\nmail:\n  host: smtp.qq.com\n  port: 587  #465 # 或587\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\n  properties:\n    mail:\n      smtp:\n        auth: true\n        ssl: true   # 465端口必开\n        starttls:\n          enable: true    # 587端口必开\n  # 邮件发送者\n  from: ambitiouschild@qq.com', '633e77e6d1fe41547cf9973f0e6a5f35', '2010-05-05 00:00:00', '2026-03-09 17:30:20', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (216, 374, 'aioveu-sms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_sms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\nmybatis-plus:\n  type-enums-package: com.aioveu.sms.common.enums\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: sms-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n #   grouplist:\n #     default: host.docker.internal:8091  \n      # 使用特殊主机名  #理论上Seata客户端应该通过Nacos获取服务端地址。但是，\n      #如果配置了service.grouplist，则会直接使用该地址，而忽略注册中心。如果希望使用注册中心，可以不配置service.grouplist，而是让客户端从注册中心获取服务端地址。\n  registry:\n    type: nacos\n    nacos:\n      application: aioveu-seata-prod\n      server-addr: ${nacos.server-addr}\n      namespace: a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef \n      group: SEATA_GROUP \n      \n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n      - /app-api/v1/adverts/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.sms.controller\n  # Api文档信息\n  info:\n    title: 营销服务\n    version: 3.0.0\n    description: 广告、优惠券等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', '382b56960d9ac0ee6f8279ac8fbae4c6', '2010-05-05 00:00:00', '2026-03-09 17:40:33', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (225, 375, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 15672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n\n  datasource:    \n    # 以下是新增的 Druid 连接池配置\n    druid:\n      # 1. 连接池基础配置  # 临时调大，缓解问题\n      initial-size: 20\n      min-idle: 20\n      max-active: 100\n      max-wait: 3000  # 3秒超时，避免请求堆积\n      \n      # 2. 连接有效性检测\n      validation-query: SELECT 1\n      test-while-idle: true\n      test-on-borrow: false\n      test-on-return: false\n      time-between-eviction-runs-millis: 60000\n      min-evictable-idle-time-millis: 300000\n      \n      # 3. 连接泄漏检测\n      remove-abandoned: true\n      remove-abandoned-timeout: 180\n      log-abandoned: true\n      \n      # 4. 监控统计\n      # 访问监控页面 ,如果配置了 stat-view-servlet，可以访问 http://你的IP:端口/druid/index.html\n      filters: stat,wall,slf4j\n      stat-view-servlet:\n        enabled: true\n        login-username: aioveu\n        login-password: 775825\n        url-pattern: /druid/*\n        reset-enable: false\n      \n      # 5. Web监控\n      web-stat-filter:\n        enabled: true\n        url-pattern: /*\n        exclusions: \"*.js,*.gif,*.jpg,*.png,*.css,*.ico,/druid/*\"\n      \n      # 6. Filter配置（关键修正点！）\n      # Druid 的 filter 配置是独立的，不是 spring 的子项\n      # 6. 慢SQL记录  开启慢SQL监控\n      filter:\n        stat:\n          enabled: true\n          log-slow-sql: true\n          slow-sql-millis: 2000   # 超过2秒的SQL记录\n          merge-sql: true\n        # SQL防火墙\n        wall:\n          enabled: true\n          config:\n            multi-statement-allow: true\n            none-base-statement-allow: false\n\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          max-active: 8\n          max-idle: 5\n          min-idle: 2\n          max-wait: 1000ms\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: localhost:8848\n  namespace: a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef\n  group: SEATA_GROUP\n  application: seata-server\n  data-id: seataServer.properties\n  username: nacos\n  password: 775825\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000', '0524e12b6f90dfe7a4a23a0c0ca067f8', '2010-05-05 00:00:00', '2026-03-09 17:56:17', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (212, 376, 'aioveu-oms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource: \n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_oms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: oms-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n #   grouplist:\n #     default: host.docker.internal:8091  \n      # 使用特殊主机名  #理论上Seata客户端应该通过Nacos获取服务端地址。但是，\n      #如果配置了service.grouplist，则会直接使用该地址，而忽略注册中心。如果希望使用注册中心，可以不配置service.grouplist，而是让客户端从注册中心获取服务端地址。\n  registry:\n    type: nacos\n    nacos:\n      application: aioveu-seata-prod\n      server-addr: ${nacos.server-addr}\n      namespace: a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef \n      group: SEATA_GROUP \n\n\n  # 添加网络超时参数\n  client:\n    tm:\n      queryTimeout: 3000\n      connectTimeout: 5000\n    rm:\n      asynCommitBufferLimit: 5000\n# 不配置grouplist，使用注册中心获取\n#Seata服务器容器IP是172.19.0.4，但OMS运行在宿主机上，宿主机无法直接访问容器的私有IP（172.19.0.4）\n#应该使用宿主机IP或host.docker.internal进行连接\n#OMS服务尝试直接连接Docker内部IP 172.19.0.4:8091，而OMS在宿主机运行，无法访问Docker网络。同时出现连接超时异常\n\n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false\n\n# 安全配置\nsecurity:\n  # 白名单路径\n  whitelist-path:\n      - /app-api/v1/carts\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.oms.controller\n  # Api文档信息\n  info:\n    title: 订单服务\n    version: 3.0.0\n    description: 订单、购物车等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true\n\n# 模拟支付配置\npay:\n  mock:\n    enabled: true           # 启用模拟支付\n    auto-success: true      # 自动成功\n    delay: 1000             # 模拟延迟1秒\n    success-rate: 100       # 成功率100%\n\nwx:\n  pay:\n    # 必需配置\n    app-id: wx1234567890abcdef      # 你的微信小程序AppId\n    mch-id: 1230000109               # 你的商户号\n    mch-key: your-mch-key-32-chars   # API密钥，32位\n    notify-url: https://your-domain.com/api/wxpay/notify\n    \n    # 可选配置\n    sign-type: MD5                   # 签名类型：MD5 或 RSA\n    sandbox-enabled: false           # 是否使用沙箱环境\n    \n    # 以下为可选证书配置（如果需要）\n    # key-path: classpath:/cert/apiclient_cert.p12\n    # private-key-path: classpath:/cert/apiclient_key.pem\n    # private-cert-path: classpath:/cert/apiclient_cert.pem\n    # api-v3-key: your-api-v3-key\n    # cert-serial-no: your-cert-serial-no\n    \n    # 兼容字段\n    # pay-notify-url: https://your-domain.com/api/wxpay/notify', 'e02ea69e9b516aaf7c0c443516d36278', '2010-05-05 00:00:00', '2026-03-09 18:06:19', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (218, 377, 'aioveu-ums.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_ums?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          min-idle: 1\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  application-id: ums-service\n  # 事务分组名称\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      default_tx_group: default\n  registry:\n    type: nacos\n    nacos:\n      application: aioveu-seata-prod\n      server-addr: ${nacos.server-addr}\n      namespace: a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef \n      group: SEATA_GROUP \n\n# Feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false\n\n# 安全配置\nsecurity:\n  # 白名单路径\n  whitelist-paths:\n      - /app-api/v1/members/openid/{openid}\n      - /app-api/v1/members/mobile/{mobile}\n      - /app-api/v1/members\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.ums.controller\n  # Api文档信息\n  info:\n    title: 会员服务\n    version: 3.0.0\n    description: 会员、地址等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能 # 设置为 true 表示开启增强功能\n  enable: true \n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', '0d81e7f7802a29d8fb87535796cfa6ab', '2010-05-05 00:00:00', '2026-03-09 18:08:17', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (225, 378, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n\n  datasource:    \n    # 以下是新增的 Druid 连接池配置\n    druid:\n      # 1. 连接池基础配置  # 临时调大，缓解问题\n      initial-size: 20\n      min-idle: 20\n      max-active: 100\n      max-wait: 3000  # 3秒超时，避免请求堆积\n      \n      # 2. 连接有效性检测\n      validation-query: SELECT 1\n      test-while-idle: true\n      test-on-borrow: false\n      test-on-return: false\n      time-between-eviction-runs-millis: 60000\n      min-evictable-idle-time-millis: 300000\n      \n      # 3. 连接泄漏检测\n      remove-abandoned: true\n      remove-abandoned-timeout: 180\n      log-abandoned: true\n      \n      # 4. 监控统计\n      # 访问监控页面 ,如果配置了 stat-view-servlet，可以访问 http://你的IP:端口/druid/index.html\n      filters: stat,wall,slf4j\n      stat-view-servlet:\n        enabled: true\n        login-username: aioveu\n        login-password: 775825\n        url-pattern: /druid/*\n        reset-enable: false\n      \n      # 5. Web监控\n      web-stat-filter:\n        enabled: true\n        url-pattern: /*\n        exclusions: \"*.js,*.gif,*.jpg,*.png,*.css,*.ico,/druid/*\"\n      \n      # 6. Filter配置（关键修正点！）\n      # Druid 的 filter 配置是独立的，不是 spring 的子项\n      # 6. 慢SQL记录  开启慢SQL监控\n      filter:\n        stat:\n          enabled: true\n          log-slow-sql: true\n          slow-sql-millis: 2000   # 超过2秒的SQL记录\n          merge-sql: true\n        # SQL防火墙\n        wall:\n          enabled: true\n          config:\n            multi-statement-allow: true\n            none-base-statement-allow: false\n\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          max-active: 8\n          max-idle: 5\n          min-idle: 2\n          max-wait: 1000ms\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: localhost:8848\n  namespace: a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef\n  group: SEATA_GROUP\n  application: seata-server\n  data-id: seataServer.properties\n  username: nacos\n  password: 775825\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000', 'e0acbb303eb4bda5c1c329e9b64c8f00', '2010-05-05 00:00:00', '2026-03-09 18:16:41', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (0, 379, 'aioveu-pay', 'AIOVEU_GROUP', '', '1', 'c4ca4238a0b923820dcc509a6f75849b', '2010-05-05 00:00:00', '2026-03-09 19:07:29', 'nacos', '172.18.0.1', 'I', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (267, 380, 'aioveu-pay', 'AIOVEU_GROUP', '', '1', 'c4ca4238a0b923820dcc509a6f75849b', '2010-05-05 00:00:00', '2026-03-09 19:19:34', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (267, 381, 'aioveu-pay', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pay?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n\n\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n        # 生产环境关闭 SQL 日志 : org.apache.ibatis.logging.nologging.NoLoggingImpl\n    # sql打印出来: org.apache.ibatis.logging.stdout.StdOutImpl\n    # 或者用 slf4j，但只记录错误  org.apache.ibatis.logging.slf4j.Slf4jImpl\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    # log-impl: org.apache.ibatis.logging.nologging.NoLoggingImpl\n    # SQL执行时间超过3秒记录警告\n    default-statement-timeout: 3000\n    # 缓存配置\n    cache-enabled: true\n    # 二级缓存实现\n    local-cache-scope: statement\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: pay-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n  #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n\n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 支付服务\n    version: 3.0.0\n    description: 支付等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true\n\n', '55ab3ad2b655ca40e4bfef15f75f4e33', '2010-05-05 00:00:00', '2026-03-09 19:21:10', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (0, 382, 'aioveu-WeChatPay.yaml', 'AIOVEU_PAY_GROUP', '', '1', 'c4ca4238a0b923820dcc509a6f75849b', '2010-05-05 00:00:00', '2026-03-09 19:29:05', 'nacos', '172.18.0.1', 'I', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (0, 383, 'aioveu-AliPay.yaml', 'AIOVEU_PAY_GROUP', '', '1', 'c4ca4238a0b923820dcc509a6f75849b', '2010-05-05 00:00:00', '2026-03-09 19:29:29', 'nacos', '172.18.0.1', 'I', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (0, 384, 'aioveu-MockPay.yaml', 'AIOVEU_PAY_GROUP', '', '1', 'c4ca4238a0b923820dcc509a6f75849b', '2010-05-05 00:00:00', '2026-03-09 19:29:42', 'nacos', '172.18.0.1', 'I', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (268, 385, 'aioveu-WeChatPay.yaml', 'AIOVEU_PAY_GROUP', '', '1', 'c4ca4238a0b923820dcc509a6f75849b', '2010-05-05 00:00:00', '2026-03-09 19:30:11', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (268, 386, 'aioveu-WeChatPay.yaml', 'AIOVEU_PAY_GROUP', '', '# application-WeChatPay.yml\n\n# ======================\n# 支付渠道通用配置\n# ======================\npayment:\n  channels:\n    # 微信支付渠道配置\n    wechat:\n      jsapi: WECHAT_JSAPI       # 微信公众号/小程序支付标识\n      app: WECHAT_APP           # APP支付标识\n      native: WECHAT_NATIVE     # 扫码支付标识\n      h5: WECHAT_H5             # H5支付标识\n    \n    # 支付宝支付渠道配置  \n    alipay:\n      app: ALIPAY_APP           # 支付宝APP支付标识\n      wap: ALIPAY_WAP           # 手机网站支付标识\n      page: ALIPAY_PAGE         # 电脑网站支付标识\n\n# ======================\n# 微信支付专用配置\n# ======================\npay:\n  wechat:\n    # 基础开关配置\n    enabled: false               # 是否启用微信支付功能\n    \n    # ================\n    # 基础认证信息\n    # ================\n    app-id: wx1234567890abcdef  # 微信应用ID(公众号/小程序/APP等)\n    mch-id: 1230000109          # 微信商户号(10位数字)\n    mch-key: ABCDEFGHIJKLMNOPQRSTUVWXYZ123456  # 商户API密钥(V2版API使用)\n    api-v3-key: ABCDEFGHIJKLMNOPQRSTUVWXYZ123456  # APIv3密钥(32位字符)\n    mch-serial-no: 1DDE55AD98ED7196  # 商户证书序列号\n    \n    # ================\n    # 私钥配置(二选一)\n    # ================\n    private-key-path: classpath:certs/apiclient_key.pem  # 私钥文件路径(classpath:表示从resources加载)\n    # 或者直接配置私钥内容(推荐用于生产环境)\n    private-key: |\n      -----BEGIN PRIVATE KEY-----\n      MIIEvQIBADANBgkqhkiG9w0BAQEFAASCBKcwggSjAgEAAoIBAQC3wN7c...\n      -----END PRIVATE KEY-----\n\n    # ================\n    # 回调地址配置\n    # ================\n    notify-url: https://your-domain.com/api/payment/wechat/notify          # 支付结果通知地址\n    refund-notify-url: https://your-domain.com/api/payment/wechat/refund/notify  # 退款结果通知地址\n\n    # ================\n    # 证书配置\n    # ================\n    platform-cert-path: classpath:certs/wechatpay_cert.pem  # 微信支付平台证书路径\n    cert-path: classpath:certs/apiclient_cert.p12           # PKCS12格式商户证书路径(V2接口使用)\n    cert-password: 123456                                  # PKCS12证书密码\n\n    # ================\n    # 网络连接配置\n    # ================\n    api-domain: https://api.mch.weixin.qq.com  # 微信支付API域名\n    connect-timeout: 10                        # 连接超时时间(秒)\n    read-timeout: 10                           # 读取超时时间(秒)\n\n    # ================\n    # 高级配置\n    # ================\n    sandbox: false              # 是否使用沙箱环境(测试环境)\n    sign-type: RSA               # 签名算法类型(RSA/RSA2)\n    cert-store-type: FILE        # 证书存储方式(FILE/CLASSPATH)\n    auto-download-cert: true     # 是否自动下载平台证书\n\n    # ================\n    # 支付方式详细配置\n    # ================\n    payment-methods:\n      # JSAPI支付(公众号/小程序)\n      jsapi:\n        app-id: wx1234567890abcdef  # 专用AppID(可覆盖全局配置)\n        enabled: true               # 是否启用该支付方式\n        \n      # APP支付\n      app:\n        app-id: wxd678efh567hg6787  # APP专用AppID\n        enabled: true\n        \n      # Native支付(扫码支付)\n      native:\n        app-id: wx1234567890abcdef\n        enabled: true\n        \n      # H5支付\n      h5:\n        app-id: wx1234567890abcdef\n        enabled: true', '607b0b62bc3fe4232980a8649d47807b', '2010-05-05 00:00:00', '2026-03-09 19:30:14', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
