ytee9BVW6t\n      Kdi+4BE0vnA+MDgHdUflDtbF\n      -----END PRIVATE KEY-----\n\n\n\n\n    # ================\n    # 回调地址配置\n    # ================\n    notify-url: https://aioveu.com/api/payment/wechat/notify          # 支付结果通知地址\n    refund-notify-url: https://aioveu.com/api/payment/wechat/refund/notify  # 退款结果通知地址\n\n    # ================\n    # 证书配置\n    # ================\n    platform-cert-path: classpath:certs/wechatpay_cert.pem  # 微信支付平台证书路径\n    cert-path: classpath:certs/apiclient_cert.p12           # PKCS12格式商户证书路径(V2接口使用)\n    cert-password: 123456                                  # PKCS12证书密码\n\n    # ================\n    # 网络连接配置\n    # ================\n    api-domain: https://api.mch.weixin.qq.com  # 微信支付API域名\n    connect-timeout: 10                        # 连接超时时间(秒)\n    read-timeout: 10                           # 读取超时时间(秒)\n\n    # ================\n    # 高级配置\n    # ================\n    sandbox: false              # 是否使用沙箱环境(测试环境)\n    sign-type: RSA               # 签名算法类型(RSA/RSA2)\n    cert-store-type: FILE        # 证书存储方式(FILE/CLASSPATH)\n    auto-download-cert: true     # 是否自动下载平台证书\n\n    # ================\n    # 支付方式详细配置\n    # ================\n    payment-methods:\n      # JSAPI支付(公众号/小程序)\n      jsapi:\n      # 专用AppID(可覆盖全局配置)\n        app-id: wxe510ad6d4d60bfa8  \n        # 是否启用该支付方式\n        enabled: true               \n        \n      # APP支付\n      app:\n       # APP专用AppID\n        app-id: wxe510ad6d4d60bfa8 \n        enabled: true\n        \n      # Native支付(扫码支付)\n      native:\n        app-id: wxe510ad6d4d60bfa8\n        enabled: true\n        \n      # H5支付\n      h5:\n        app-id: wxe510ad6d4d60bfa8\n        enabled: true', 'cb3651bb4245ce81eb1d251ba128b67d', '2010-05-05 00:00:00', '2026-03-09 21:45:48', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (267, 408, 'aioveu-pay', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pay?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n\n\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n        # 生产环境关闭 SQL 日志 : org.apache.ibatis.logging.nologging.NoLoggingImpl\n    # sql打印出来: org.apache.ibatis.logging.stdout.StdOutImpl\n    # 或者用 slf4j，但只记录错误  org.apache.ibatis.logging.slf4j.Slf4jImpl\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    # log-impl: org.apache.ibatis.logging.nologging.NoLoggingImpl\n    # SQL执行时间超过3秒记录警告\n    default-statement-timeout: 3000\n    # 缓存配置\n    cache-enabled: true\n    # 二级缓存实现\n    local-cache-scope: statement\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: pay-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n  #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n\n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 支付服务\n    version: 3.0.0\n    description: 支付等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true\n\n', '55ab3ad2b655ca40e4bfef15f75f4e33', '2010-05-05 00:00:00', '2026-03-09 21:46:26', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (267, 409, 'aioveu-pay', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pay?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n\n\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n        # 生产环境关闭 SQL 日志 : org.apache.ibatis.logging.nologging.NoLoggingImpl\n    # sql打印出来: org.apache.ibatis.logging.stdout.StdOutImpl\n    # 或者用 slf4j，但只记录错误  org.apache.ibatis.logging.slf4j.Slf4jImpl\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    # log-impl: org.apache.ibatis.logging.nologging.NoLoggingImpl\n    # SQL执行时间超过3秒记录警告\n    default-statement-timeout: 3000\n    # 缓存配置\n    cache-enabled: true\n    # 二级缓存实现\n    local-cache-scope: statement\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: pay-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n      cluster: default\n\n  #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n\n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 支付服务\n    version: 3.0.0\n    description: 支付等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true\n\n', '098217f71aaf615559c5957f7562f9f3', '2010-05-05 00:00:00', '2026-03-09 22:01:07', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (214, 410, 'aioveu-pms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: pms-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n    #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n  \n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 商品服务\n    version: 3.0.0\n    description: 库存、分类、品牌、规格、参数等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', 'f8bf904f0c32119674f6972bb2e53ea1', '2010-05-05 00:00:00', '2026-03-09 22:27:23', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (267, 411, 'aioveu-pay', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pay?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n\n\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n        # 生产环境关闭 SQL 日志 : org.apache.ibatis.logging.nologging.NoLoggingImpl\n    # sql打印出来: org.apache.ibatis.logging.stdout.StdOutImpl\n    # 或者用 slf4j，但只记录错误  org.apache.ibatis.logging.slf4j.Slf4jImpl\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    # log-impl: org.apache.ibatis.logging.nologging.NoLoggingImpl\n    # SQL执行时间超过3秒记录警告\n    default-statement-timeout: 3000\n    # 缓存配置\n    cache-enabled: true\n    # 二级缓存实现\n    local-cache-scope: statement\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: pay-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      application: ${nacos.application}\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace} \n      group: ${nacos.group}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n  #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n\n\n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 支付服务\n    version: 3.0.0\n    description: 支付等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true\n\n', '55ab3ad2b655ca40e4bfef15f75f4e33', '2010-05-05 00:00:00', '2026-03-09 22:38:45', 'nacos', '172.18.0.1', 'D', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (213, 412, 'aioveu-pay.yaml', 'AIOVEU_GROUP', '', 'spring:\r\n  datasource:\r\n    type: com.alibaba.druid.pool.DruidDataSource\r\n    driver-class-name: com.mysql.cj.jdbc.Driver \r\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pay?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\r\n    username: ${mysql.username}\r\n    password: ${mysql.password}\r\n  data:\r\n    redis:\r\n      database: ${redis.database}\r\n      host: ${redis.host}\r\n      port: ${redis.port}\r\n      password: ${redis.password}\r\n      lettuce:\r\n        pool:\r\n          min-idle: 1\r\n  # RabbitMQ 配置\r\n  rabbitmq:\r\n    host: ${rabbitmq.host}\r\n    port: ${rabbitmq.port}\r\n    username: ${rabbitmq.username}\r\n    password: ${rabbitmq.password}\r\n    virtual-host: /\r\n    listener:\r\n      simple:\r\n        acknowledge-mode: manual   \r\n  cache:\r\n    # 缓存类型 redis、none(不使用缓存) \r\n    type: redis\r\n    # 缓存时间(单位：ms)\r\n    redis:\r\n      time-to-live: 3600000\r\n      # 缓存null值，防止缓存穿透\r\n      cache-null-values: true\r\n  cloud:\r\n    sentinel:\r\n      enabled: false\r\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\r\n      transport:\r\n        client-ip: localhost\r\n        dashboard: localhost:8080\r\n      datasource:\r\n        # 限流规则，flow为key，随便定义\r\n        flow:\r\n          nacos:\r\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\r\n            dataId: ${spring.application.name}-flow-rules\r\n            groupId: SENTINEL_GROUP\r\n            data-type: json\r\n            rule-type: flow\r\n        # 降级规则\r\n        degrade:\r\n          nacos:\r\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\r\n            dataId: ${spring.application.name}-degrade-rules\r\n            groupId: SENTINEL_GROUP\r\n            data-type: json\r\n            rule-type: degrade\r\n                \r\nmybatis-plus:\r\n  configuration:\r\n    # 驼峰下划线转换\r\n    map-underscore-to-camel-case: true\r\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\r\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\r\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\r\n\r\n\r\n# Seata 配置\r\nseata: \r\n  # 开启 Seata\r\n  enabled: true\r\n  application-id: refund-service\r\n  # 事务分组名称\r\n  tx-service-group: default_tx_group\r\n  service:\r\n    # 事务分组映射，根据分组名称匹配到集群\r\n    vgroup-mapping:\r\n      # 事务分组名称：集群名称\r\n      default_tx_group: default\r\n  registry:\r\n    type: nacos\r\n    nacos:\r\n      application: aioveu-seata-server\r\n      server-addr: ${nacos.server-addr}\r\n      namespace:\r\n      group: SEATA_GROUP \r\n\r\n\r\n\r\n# feign 配置\r\nfeign:\r\n  httpclient:\r\n    enabled: true\r\n  okhttp:\r\n    enabled: false\r\n  sentinel:  # 开启feign对sentinel的支持\r\n    enabled: false \r\n\r\n# 安全配置\r\nsecurity:\r\n  # 允许无需认证的路径列表\r\n  whitelist-paths:\r\n    # 获取系统用户的认证信息用于账号密码判读\r\n    - /api/v1/users/{username}/authInfo\r\n    - /api/v1/users/{username}/UserAuthCredentials\r\n\r\n# springdoc-openapi项目配置\r\nspringdoc:\r\n  swagger-ui:\r\n    path: /swagger-ui.html\r\n    tags-sorter: alpha\r\n    operations-sorter: alpha\r\n  api-docs:\r\n    path: /v3/api-docs\r\n  group-configs:\r\n    - group: \'default\'\r\n      paths-to-match: \'/**\'\r\n      packages-to-scan: \r\n        - com.aioveu.system.controller\r\n        - com.aioveu.common.file.controller\r\n  # Api文档信息\r\n  info:\r\n    title: 支付服务\r\n    version: 3.0.0\r\n    description: 支付等接口\r\n    contact:\r\n      name: aioveu\r\n      url: https://www.aioveu.com\r\n      email: ambitiouschild@qq.com\r\n    license:\r\n      name: Apache 2.0\r\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\r\n\r\n# knife4j的增强配置，不需要增强可以不配\r\nknife4j:\r\n  enable: false\r\n  setting:\r\n    language: zh_cn\r\n\r\n\r\n\r\n# 文件存储\r\noss:\r\n  # OSS 类型 (目前支持aliyun、minio)\r\n  type: minio\r\n  # MinIO 对象存储服务\r\n  minio:\r\n    # 服务Endpoint\r\n    endpoint: http://localhost:9002 \r\n    # 访问凭据\r\n    access-key: minioadminlss\r\n    # 凭据密钥\r\n    secret-key: minioadminlss\r\n    # 存储桶名称\r\n    bucket-name: aioveu\r\n    # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\r\n    custom-domain:  http://localhost:9002\r\n  # 阿里云OSS对象存储服务\r\n  aliyun:\r\n    # 服务Endpoint\r\n    endpoint: oss-cn-hangzhou.aliyuncs.com\r\n    # 访问凭据\r\n    access-key-id: your-access-key-id\r\n    # 凭据密钥\r\n    access-key-secret: your-access-key-secret\r\n    # 存储桶名称\r\n    bucket-name: default\r\n', '3a0e14e492b752cee4de6db33f2845c2', '2010-05-05 00:00:00', '2026-03-09 22:39:55', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (214, 413, 'aioveu-pms.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_pms?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /        \n  cache:\n    # 缓存类型\n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n      # 允许使用缓存前缀，\n      use-key-prefix: true\n      # 缓存前缀，没有设置使用注解的缓存名称(value)作为前缀，和注解的key用双冒号::拼接组成完整缓存key\n      # key-prefix:\n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换 \n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n\n# Seata 配置\nseata: \n  # 开启 Seata\n  enabled: true\n  #第三步：pms 注册到 Seata Server ✅  pms的Seata客户端配置\n  # 这个ID是pms在Seata中的标识\n  application-id: pms-service\n  # 事务分组名称\n  # 这是pms所属的事务组，多个微服务可以用同一个分组\n  tx-service-group: default_tx_group\n  service:\n    # 事务分组映射，根据分组名称匹配到集群\n    vgroup-mapping:\n      # 事务分组名称：集群名称\n      # 告诉pms：default_tx_group分组对应的Seata集群是\"default\"\n      default_tx_group: default\n\n  #第一步：Seata Server 注册到 Nacos ✅\n  #容器创建时已经注册\n\n  # pms通过application.yaml注册进nacos\n  #registry 配置是读取注册配置，不是进行注册**\n  #第二步：pms 通过seata的注册信息从 Nacos 发现 Seata Server ✅ ，这里告诉pms要查找的seata服务名\n  registry:\n    type: nacos\n    nacos:\n      # ❌ 这里理解有误！\n      # 这个不是pms注册到Nacos，而是告诉pms：\n      # \"去Nacos里找名为\'aioveu-seata-server\'的服务\"（即Seata Server）\n      # application: ${nacos.application}\n      # server-addr: ${nacos.server-addr}\n      # namespace: ${nacos.namespace} \n      # group: ${nacos.group}\n      # username: ${nacos.username}\n      # password: ${nacos.password}\n\n      application: aioveu-seata-server\n      server-addr: localhost:8848\n      namespace: a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef\n      group: SEATA_GROUP\n      # 关键：不指定集群，或者用正确的集群名\n      # cluster: \"\"  # 空字符串\n      username: nacos\n      password: 775825\n\n    #config 配置是读取中心化配置，不是设置本地配置**\n    # 5. 如何获取Seata配置（从Nacos读取）  告诉 pms 去哪里读配置\n  config:\n    type: nacos\n    nacos:\n      server-addr: ${nacos.server-addr}\n      namespace: ${nacos.namespace}\n      group: ${nacos.group}\n      data-id: ${nacos.data-id}\n      username: ${nacos.username}\n      password: ${nacos.password}\n  \n      \n# feign 配置\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 白名单\n  whitelist-paths:\n      - /app-api/v1/categories\n      - /app-api/v1/spu/**\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.pms.controller\n  # Api文档信息\n  info:\n    title: 商品服务\n    version: 3.0.0\n    description: 库存、分类、品牌、规格、参数等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  # 是否开启 Knife4j 增强功能\n  enable: true  # 设置为 true 表示开启增强功能\n  # 生产环境配置\n  production: false  # 设置为 true 表示在生产环境中不显示文档，为 false 表示显示文档（通常在开发环境中使用）\n  setting:\n    # 基础配置-------------\n    language: zh_cn\n    enable-version: true\n    # ✅ 开启重载功能\n    enable-reload: true\n    enable-open-api: true\n\n    # 调试和缓存-------------\n    # 启用调试模式\n    enable-debug: true\n    # 启用请求缓存\n    enable-request-cache: true\n    # 自动添加认证头\n    enable-filter-multipart-apimethod: 4\n    # Token 自动管理\n    enable-after-script: true\n\n\n    #显示配置-------------\n    # ✅ 添加这个关键配置\n    enable-swagger-models: true\n    enable-group: true\n    enable-footer: true\n    enable-footer-custom-content: \"Aioveu 认证服务\"\n    # ✅ 开启文档管理\n    enable-document-manage: true\n\n    # 搜索和国际化-------------\n    enable-search: true\n    enable-i18n: true\n\n    #高级功能-------------\n    # 启用动态参数\n    enable-dynamic-params: true\n    # ✅ 开启文件上传处理\n    enable-filter-multipart-param: true\n\n    # 开启全局参数\n    enable-global-parameters: true', '35b6d7d611bb555b7a1097fc8838a3f8', '2010-05-05 00:00:00', '2026-03-09 22:40:39', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (268, 414, 'aioveu-WeChatPay.yaml', 'AIOVEU_PAY_GROUP', '', '# application-WeChatPay.yml\n\n# ======================\n# 支付渠道通用配置\n# ======================\npayment:\n  channels:\n    # 微信支付渠道配置\n    wechat:\n      jsapi: WECHAT_JSAPI       # 微信公众号/小程序支付标识\n      app: WECHAT_APP           # APP支付标识\n      native: WECHAT_NATIVE     # 扫码支付标识\n      h5: WECHAT_H5             # H5支付标识\n    \n    # 支付宝支付渠道配置  \n    alipay:\n      app: ALIPAY_APP           # 支付宝APP支付标识\n      wap: ALIPAY_WAP           # 手机网站支付标识\n      page: ALIPAY_PAGE         # 电脑网站支付标识\n\n# ======================\n# 微信支付专用配置\n# ======================\npay:\n  wechat:\n    # 基础开关配置 false\n    enabled: true               # 是否启用微信支付功能\n    \n    # ================\n    # 基础认证信息\n    # ================\n    # 微信应用ID(公众号/小程序/APP等)\n    app-id: wxe510ad6d4d60bfa8  \n    # 微信商户号(10位数字)\n    mch-id: 1107195457          \n    # 商户API密钥(V2版API使用)\n    # mch-key: ABCDEFGHIJKLMNOPQRSTUVWXYZ123456  \n    # APIv3密钥(32位字符)\n    api-v3-key: dCzmYhzYcCEyRyiHp9Z9MTVMRYoSYwVj  \n    # 商户证书序列号   3E9ED7E808B24BAB9E74C1414B57FEDB9D063DB1\n    mch-serial-no: 239431EB597A2C00B8356D7C3043E0FC8D04CEE8\n    \n        # 新增：微信支付公钥配置\n        # 从商户平台复制的公钥ID\n    wechatpay-public-key-id: PUB_KEY_ID_0111071954572026030800292321000401 \n    # wechatpay-public-key-path: classpath:certs/wechatpay_public_key.pem\n    wechatpay-public-key: |\n        -----BEGIN PUBLIC KEY-----\n        MIIBIjANBgkqhkiG9w0BAQEFAAOCAQ8AMIIBCgKCAQEAwzm4THV3l2aUkyl/dQln\n        vzs07PMP6iopZmcWXDvY2hu/N5iAlRwF5iYsKQQw0gRDeRMWlui+HkS7B7udE5T3\n        quK6i2XablINSRMSNVLtSbBebfvdj2JzmYmV4Z5D2t9DQrsYs22nwQTrojA61lYr\n        rdpukp0YH3p0IDxzRDzGIkmWT4/DhZ7eL87rB7o9Kvt0tzmg/ybdEsp80tv0h57R\n        5PGpbPyS28vGyNnqTK/3IgDMkf2AyiQxNqahjAj97pS8WI2uc1lTb076eEmJA4l+\n        VKmSHVGDOfQE8jReTE/jvjpTP5SxoFyvG/sp+tcLbk8BGjpVZnc6ynzO3AyHbFDp\n        LQIDAQAB\n        -----END PUBLIC KEY-----\n\n    # ================\n    # 私钥配置(二选一)\n    # ================\n    # 私钥文件路径(classpath:表示从resources加载)\n    # private-key-path: classpath:certs/apiclient_key.pem  \n    # 或者直接配置私钥内容(推荐用于生产环境)\n    private-key: |\n      -----BEGIN PRIVATE KEY-----\n      MIIEvgIBADANBgkqhkiG9w0BAQEFAASCBKgwggSkAgEAAoIBAQC31Edi9nwLNMwL\n      BibV+d3lypSXUqnA3S4jC3f75SyvyVmFu1EPS5H0lGfSg2rE8yriLdt25PKEseax\n      wOz7ARIkqo+pBVtyIaLfvrftUpRFUvxG/8AxQZ2rmeVm9RVRZtGzVdRuNXBwOnnV\n      /fOf0zRB168dE1K+jJa47wx39TB6f8AqDpm/bzfCnwMqUwFihxUoU5Od4QK1Y6cb\n      ZugB5VSpxOp2RDLXovj92Du9c/MwfipD/ZvObEfbPXcdpKQ5yBtzNmEjC4o5PrFK\n      LK2QMPw1JwCotj004TVxaoXSannAKG6ZtXahb1I4rx/DTZ3m12KqcDQQRn0wY5U9\n      5TqZSmEbAgMBAAECggEAbDleWaXRO2u24JqbjIfRGnLcbgYtiCzu95TN649tcoQw\n      3yl7PGz6HaqtQOM7nX2ndocW2HVLTdHKhkWVfuSPgOSlNRXBU3z3/Y+zitV+Ex4b\n      BdWVmaoOoDM3Ohj5lvXYaSMTsFpnurrCdbhPkH1wG39WSeDRavsr1O5vQcQo6USB\n      669iYR5LLhIRPELxQjSLPfDDKllu48rcS3j365inQPc2QTvbZ63LVKHAs1MQvPvA\n      dBohlxbvUMIB/5YlYnkgJwwVBONmBfbj6u+f/5Os2W5Z6A3L3+LuvhApNPlUTolo\n      1jvVpJkHAklowZ8q8AsOm36pfMnH5M+2pjGIRDoP+QKBgQDv8TwKQS/87MDDgmOt\n      BTzZKPZ2lGsfn+/3Ql7Z/ob6yfMrvOt6EhyG5tTa4TSpBdq9Ar2EphilaYszoKHv\n      PTBWL8xWA1Tfn0E/vc6j+Hxri6Fd76vJPP8U61KmH+s7/x/HpWEzVV2PYLkkk3k+\n      gA2P0RmkwvrcZ6bgOSjXNyvgBwKBgQDEIbKE+tr3NWeQx9CqYVNNL4pvzUG6NCrM\n      4x1v19okYpRowDF1PIzJ6JZURDoB/zBYe0UbzPO1gIRS/ZBK3JT+MpD4iF2IIv2z\n      /ilSjNv0XBVDIrnPpZcRNcvrr5ZbGgt56VSWvJNObfuuL9mY7QxvZ+dRE1K/5FW8\n      GUUo9ppJTQKBgQC2V1EVSey5/QGQkipFdlGDhkmmW6v84IJwGRQT/gV92LLfbjZV\n      EiZzrj/cBoEKYdSVBtwXTlI0gjyzA0OMl6eAF9rlEqsRNelUE15R5ahH4ljDFjwq\n      NhxzPVIVxPPzKDJyeg+f/yOWrh6E2T2ubYng3TrrpvEVRf/fLhEHXHoPSQKBgEXr\n      CVv0nYiRJjlrsgx7I5oZf415q5u4qyVdNYpAdciQx/1LvpXfnwT/gE/L/q3ljhOM\n      5kcR2jNy/DkloYG+fvLbjei7nDRC3RSEX7DI/ERxazcCsyC+FEuTVP3RG5WghETS\n      lFAkK5NDC/y9nCGzJ8KzVLgHXnF/8bxbedcvijLlAoGBANtrk99k2X1ZVxh3WLUM\n      i7+6d5dGTed6mYzD7qjC1yCgu6ATrLF/L1qgfVkdpEcwqOB5dZzZX3eAjvXytCtV\n      xR9s+OqECoujURHY1QlmD0wGuNKDkusmlAqqV1xDCZzsoCdtKgjk+Rytee9BVW6t\n      Kdi+4BE0vnA+MDgHdUflDtbF\n      -----END PRIVATE KEY-----\n\n\n\n\n    # ================\n    # 回调地址配置\n    # ================\n    notify-url: https://aioveu.com/api/payment/wechat/notify          # 支付结果通知地址\n    refund-notify-url: https://aioveu.com/api/payment/wechat/refund/notify  # 退款结果通知地址\n\n    # ================\n    # 证书配置\n    # ================\n    platform-cert-path: classpath:certs/wechatpay_cert.pem  # 微信支付平台证书路径\n    cert-path: classpath:certs/apiclient_cert.p12           # PKCS12格式商户证书路径(V2接口使用)\n    cert-password: 123456                                  # PKCS12证书密码\n\n    # ================\n    # 网络连接配置\n    # ================\n    api-domain: https://api.mch.weixin.qq.com  # 微信支付API域名\n    connect-timeout: 10                        # 连接超时时间(秒)\n    read-timeout: 10                           # 读取超时时间(秒)\n\n    # ================\n    # 高级配置\n    # ================\n    sandbox: false              # 是否使用沙箱环境(测试环境)\n    sign-type: RSA               # 签名算法类型(RSA/RSA2)\n    cert-store-type: FILE        # 证书存储方式(FILE/CLASSPATH)\n    auto-download-cert: true     # 是否自动下载平台证书\n\n    # ================\n    # 支付方式详细配置\n    # ================\n    payment-methods:\n      # JSAPI支付(公众号/小程序)\n      jsapi:\n      # 专用AppID(可覆盖全局配置)\n        app-id: wxe510ad6d4d60bfa8  \n        # 是否启用该支付方式\n        enabled: true               \n        \n      # APP支付\n      app:\n       # APP专用AppID\n        app-id: wxe510ad6d4d60bfa8 \n        enabled: true\n        \n      # Native支付(扫码支付)\n      native:\n        app-id: wxe510ad6d4d60bfa8\n        enabled: true\n        \n      # H5支付\n      h5:\n        app-id: wxe510ad6d4d60bfa8\n        enabled: true', 'cb3651bb4245ce81eb1d251ba128b67d', '2010-05-05 00:00:00', '2026-03-10 15:35:23', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (0, 415, 'aioveu-tenant.yaml', 'AIOVEU_GROUP', '', '1', 'c4ca4238a0b923820dcc509a6f75849b', '2010-05-05 00:00:00', '2026-03-10 19:21:47', 'aioveu', '172.18.0.1', 'I', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (271, 416, 'aioveu-tenant.yaml', 'AIOVEU_GROUP', '', '1', 'c4ca4238a0b923820dcc509a6f75849b', '2010-05-05 00:00:00', '2026-03-10 19:24:05', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (271, 417, 'aioveu-tenant.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_tenant?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: aliyun\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint  #minio:9000 \n    # endpoint:  minio.aioveu.com \n    # # 访问凭据\n    # access-key: minioadminlss\n    # # 凭据密钥\n    # secret-key: minioadminlss\n    # # 存储桶名称\n    # bucket-name: aioveu\n    # # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    # custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    tenant-id: 1001  # 添加到这里\n    # 服务Endpoint\n    endpoint: oss-cn-shanghai.aliyuncs.com\n    # 访问凭据\n    access-key-id: LTAI5tDVP4BURrY9VtAE66K2\n    # 凭据密钥\n    access-key-secret: cOpi8YlxjJKmxoPG7D8j2592fC2iSD\n    # 存储桶名称\n    bucket-name: aioveu\n    # 新增：加速域名配置  # 替换为您的实际加速域名\n    cdn-domain: cdn.aioveu.com \n    cdn-region: cn-shanghai \n\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\nmail:\n  host: smtp.qq.com\n  port: 587  #465 # 或587\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\n  properties:\n    mail:\n      smtp:\n        auth: true\n        ssl: true   # 465端口必开\n        starttls:\n          enable: true    # 587端口必开\n  # 邮件发送者\n  from: ambitiouschild@qq.com', '4b6cb3683104eae60b83ad4801fee964', '2010-05-05 00:00:00', '2026-03-10 19:47:08', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (271, 418, 'aioveu-tenant.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_tenant?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n    - /api/v1/users/tenants/{username}\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: aliyun\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint  #minio:9000 \n    # endpoint:  minio.aioveu.com \n    # # 访问凭据\n    # access-key: minioadminlss\n    # # 凭据密钥\n    # secret-key: minioadminlss\n    # # 存储桶名称\n    # bucket-name: aioveu\n    # # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    # custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    tenant-id: 1001  # 添加到这里\n    # 服务Endpoint\n    endpoint: oss-cn-shanghai.aliyuncs.com\n    # 访问凭据\n    access-key-id: LTAI5tDVP4BURrY9VtAE66K2\n    # 凭据密钥\n    access-key-secret: cOpi8YlxjJKmxoPG7D8j2592fC2iSD\n    # 存储桶名称\n    bucket-name: aioveu\n    # 新增：加速域名配置  # 替换为您的实际加速域名\n    cdn-domain: cdn.aioveu.com \n    cdn-region: cn-shanghai \n\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\nmail:\n  host: smtp.qq.com\n  port: 587  #465 # 或587\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\n  properties:\n    mail:\n      smtp:\n        auth: true\n        ssl: true   # 465端口必开\n        starttls:\n          enable: true    # 587端口必开\n  # 邮件发送者\n  from: ambitiouschild@qq.com', '2383e051b7441a7b562f8be109099abb', '2010-05-05 00:00:00', '2026-03-11 00:08:49', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (271, 419, 'aioveu-tenant.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_tenant?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n    #根据用户名获取可登录的租户列表\n    - /api/v1/users/tenants/{username}\n\n    #根据用户名和租户ID获取认证信息（用于多租户登录）\n    - /api/v1/users/{username}/{tenantId}/authInfo\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: aliyun\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint  #minio:9000 \n    # endpoint:  minio.aioveu.com \n    # # 访问凭据\n    # access-key: minioadminlss\n    # # 凭据密钥\n    # secret-key: minioadminlss\n    # # 存储桶名称\n    # bucket-name: aioveu\n    # # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    # custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    tenant-id: 1001  # 添加到这里\n    # 服务Endpoint\n    endpoint: oss-cn-shanghai.aliyuncs.com\n    # 访问凭据\n    access-key-id: LTAI5tDVP4BURrY9VtAE66K2\n    # 凭据密钥\n    access-key-secret: cOpi8YlxjJKmxoPG7D8j2592fC2iSD\n    # 存储桶名称\n    bucket-name: aioveu\n    # 新增：加速域名配置  # 替换为您的实际加速域名\n    cdn-domain: cdn.aioveu.com \n    cdn-region: cn-shanghai \n\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\nmail:\n  host: smtp.qq.com\n  port: 587  #465 # 或587\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\n  properties:\n    mail:\n      smtp:\n        auth: true\n        ssl: true   # 465端口必开\n        starttls:\n          enable: true    # 587端口必开\n  # 邮件发送者\n  from: ambitiouschild@qq.com', '5519e10f7c7f69295561ddf39436c736', '2010-05-05 00:00:00', '2026-03-11 00:10:46', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
