n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n    #根据用户名获取可登录的租户列表\n    - /api/v1/users/tenants/{username}\n\n    #根据用户名和租户ID获取认证信息（用于多租户登录）\n    - /api/v1/users/{username}/{tenantId}/authInfo\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: aliyun\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint  #minio:9000 \n    # endpoint:  minio.aioveu.com \n    # # 访问凭据\n    # access-key: minioadminlss\n    # # 凭据密钥\n    # secret-key: minioadminlss\n    # # 存储桶名称\n    # bucket-name: aioveu\n    # # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    # custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    tenant-id: 1001  # 添加到这里\n    # 服务Endpoint\n    endpoint: oss-cn-shanghai.aliyuncs.com\n    # 访问凭据\n    access-key-id: LTAI5tDVP4BURrY9VtAE66K2\n    # 凭据密钥\n    access-key-secret: cOpi8YlxjJKmxoPG7D8j2592fC2iSD\n    # 存储桶名称\n    bucket-name: aioveu\n    # 新增：加速域名配置  # 替换为您的实际加速域名\n    cdn-domain: cdn.aioveu.com \n    cdn-region: cn-shanghai \n\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\nmail:\n  host: smtp.qq.com\n  port: 587  #465 # 或587\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\n  properties:\n    mail:\n      smtp:\n        auth: true\n        ssl: true   # 465端口必开\n        starttls:\n          enable: true    # 587端口必开\n  # 邮件发送者\n  from: ambitiouschild@qq.com', '5519e10f7c7f69295561ddf39436c736', '2010-05-05 00:00:00', '2026-03-12 17:03:10', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (271, 421, 'aioveu-tenant.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_tenant?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  mapper-locations: classpath*:/mapper/**/*.xml\n  global-config:\n  db-config:\n    # 主键ID类型\n    id-type: none\n    # 逻辑删除对应的全局属性名（注意：须是对象属性名，不能是表字段名，如 isDeleted 而非 is_deleted，否则逻辑删除失效）\n    logic-delete-field: isDeleted\n    # 逻辑删除-删除值\n    logic-delete-value: 1\n    # 逻辑删除-未删除值\n    logic-not-delete-value: 0\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n    #根据用户名获取可登录的租户列表\n    - /api/v1/users/tenants/{username}\n\n    #根据用户名和租户ID获取认证信息（用于多租户登录）\n    - /api/v1/users/{username}/{tenantId}/authInfo\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: aliyun\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint  #minio:9000 \n    # endpoint:  minio.aioveu.com \n    # # 访问凭据\n    # access-key: minioadminlss\n    # # 凭据密钥\n    # secret-key: minioadminlss\n    # # 存储桶名称\n    # bucket-name: aioveu\n    # # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    # custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    tenant-id: 1001  # 添加到这里\n    # 服务Endpoint\n    endpoint: oss-cn-shanghai.aliyuncs.com\n    # 访问凭据\n    access-key-id: LTAI5tDVP4BURrY9VtAE66K2\n    # 凭据密钥\n    access-key-secret: cOpi8YlxjJKmxoPG7D8j2592fC2iSD\n    # 存储桶名称\n    bucket-name: aioveu\n    # 新增：加速域名配置  # 替换为您的实际加速域名\n    cdn-domain: cdn.aioveu.com \n    cdn-region: cn-shanghai \n\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\nmail:\n  host: smtp.qq.com\n  port: 587  #465 # 或587\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\n  properties:\n    mail:\n      smtp:\n        auth: true\n        ssl: true   # 465端口必开\n        starttls:\n          enable: true    # 587端口必开\n  # 邮件发送者\n  from: ambitiouschild@qq.com', '14727c473b9b90e635333a2e2011666e', '2010-05-05 00:00:00', '2026-03-12 17:06:10', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (271, 422, 'aioveu-tenant.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_tenant?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n  # RabbitMQ 配置\n  rabbitmq:\n    host: ${rabbitmq.host}\n    port: ${rabbitmq.port}\n    username: ${rabbitmq.username}\n    password: ${rabbitmq.password}\n    virtual-host: /\n    listener:\n      simple:\n        acknowledge-mode: manual   \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n  cloud:\n    sentinel:\n      enabled: false\n      eager: true # 取消控制台懒加载，项目启动即连接Sentinel\n      transport:\n        client-ip: localhost\n        dashboard: localhost:8080\n      datasource:\n        # 限流规则，flow为key，随便定义\n        flow:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-flow-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: flow\n        # 降级规则\n        degrade:\n          nacos:\n            server-addr: ${spring.cloud.nacos.discovery.server-addr}\n            dataId: ${spring.application.name}-degrade-rules\n            groupId: SENTINEL_GROUP\n            data-type: json\n            rule-type: degrade\n                \nmybatis-plus:\n  mapper-locations: classpath*:/mapper/**/*.xml\n  global-config:\n    db-config:\n      # 主键ID类型\n      id-type: none\n      # 逻辑删除对应的全局属性名（注意：须是对象属性名，不能是表字段名，如 isDeleted 而非 is_deleted，否则逻辑删除失效）\n      logic-delete-field: isDeleted\n      # 逻辑删除-删除值\n      logic-delete-value: 1\n      # 逻辑删除-未删除值\n      logic-not-delete-value: 0\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\n# 安全配置\nsecurity:\n  # 允许无需认证的路径列表\n  whitelist-paths:\n    # 获取系统用户的认证信息用于账号密码判读\n    - /api/v1/users/{username}/authInfo\n    - /api/v1/users/{username}/UserAuthCredentials\n\n    #根据用户名获取可登录的租户列表\n    - /api/v1/users/tenants/{username}\n\n    #根据用户名和租户ID获取认证信息（用于多租户登录）\n    - /api/v1/users/{username}/{tenantId}/authInfo\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: \n        - com.aioveu.system.controller\n        - com.aioveu.common.file.controller\n  # Api文档信息\n  info:\n    title: 系统服务\n    version: 3.0.0\n    description: 用户、部门、角色、菜单、字典等接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n\n\n# 文件存储\noss:\n  # OSS 类型 (目前支持aliyun、minio)\n  type: aliyun\n  # MinIO 对象存储服务\n  minio:\n    # 服务Endpoint  #minio:9000 \n    # endpoint:  minio.aioveu.com \n    # # 访问凭据\n    # access-key: minioadminlss\n    # # 凭据密钥\n    # secret-key: minioadminlss\n    # # 存储桶名称\n    # bucket-name: aioveu\n    # # (可选)自定义域名，如果配置了域名，生成的文件URL是域名格式，未配置则URL则是IP格式 (eg: https://oss.aioveu.tech)\n    # custom-domain:  https://minio.aioveu.com\n  # 阿里云OSS对象存储服务\n  aliyun:\n    tenant-id: 1001  # 添加到这里\n    # 服务Endpoint\n    endpoint: oss-cn-shanghai.aliyuncs.com\n    # 访问凭据\n    access-key-id: LTAI5tDVP4BURrY9VtAE66K2\n    # 凭据密钥\n    access-key-secret: cOpi8YlxjJKmxoPG7D8j2592fC2iSD\n    # 存储桶名称\n    bucket-name: aioveu\n    # 新增：加速域名配置  # 替换为您的实际加速域名\n    cdn-domain: cdn.aioveu.com \n    cdn-region: cn-shanghai \n\n# 邮件配置 邮件配置应该在 spring.mail下，而不是在 oss.mail下！\nmail:\n  host: smtp.qq.com\n  port: 587  #465 # 或587\n  username: ambitiouschild@qq.com   #腾讯邮箱默认关闭 SMTP 服务，腾讯邮箱要求 SMTP 必须使用授权码（非登录密码）：pwjbkmmfmuspdgjh\n  password: pwjbkmmfmuspdgjh   # 替换为生成的授权码\n  properties:\n    mail:\n      smtp:\n        auth: true\n        ssl: true   # 465端口必开\n        starttls:\n          enable: true    # 587端口必开\n  # 邮件发送者\n  from: ambitiouschild@qq.com', '8ec8cba7cc52b8a5b026fbccd2d10576', '2010-05-05 00:00:00', '2026-03-12 17:09:06', 'aioveu', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (208, 423, 'aioveu-auth.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_oauth2_server?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n \nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\n# 微信小程序\nwx:\n  miniapp:\n    # appId: wx977b2949b7095b11\n    # appSecret: 4bf78af93a8ce49f2de5384ede86be63\n    appId: wxe510ad6d4d60bfa8\n    appSecret: 1839111563bcf001bae776543c31829f\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.auth.controller\n  # Api文档信息\n  info:\n    title: 认证服务\n    version: 3.0.0\n    description: 认证、登出、验证码接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n# 验证码配置\ncaptcha:\n  # 验证码类型 circle-圆圈干扰验证码|gif-Gif验证码|line-干扰线验证码|shear-扭曲干扰验证码\n  type: circle\n  # 验证码宽度\n  width: 120\n  # 验证码高度\n  height: 40\n  # 验证码干扰元素个数\n  interfere-count: 2\n  # 文本透明度(0.0-1.0)\n  text-alpha: 0.8\n  # 验证码字符配置\n  code:\n    # 验证码字符类型 math-算术|random-随机字符\n    type: math\n    # 验证码字符长度，type=算术时，表示运算位数(1:个位数运算 2:十位数运算)；type=随机字符时，表示字符个数\n    length: 1\n  # 验证码字体\n  font:\n    # 字体名称 Dialog|DialogInput|Monospaced|Serif|SansSerif\n    name: SansSerif\n    # 字体样式 0-普通|1-粗体|2-斜体\n    weight: 1\n    # 字体大小\n    size: 24\n  # 验证码有效期(秒)\n  expire-seconds: 120\n\nsecurity:\n  whitelist-paths:\n    - /api/v1/auth/captcha\n    - /api/v1/auth/sms_code', '6345576e49f8955d4336d5901e3b1180', '2010-05-05 00:00:00', '2026-03-14 22:58:39', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (208, 424, 'aioveu-auth.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_oauth2_server?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n \nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\n# 微信小程序\nwx:\n  miniapp:\n    # appId: wx977b2949b7095b11\n    # appSecret: 4bf78af93a8ce49f2de5384ede86be63\n    appId: wxe510ad6d4d60bfa8\n    appSecret: 1839111563bcf001bae776543c31829f\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.auth.controller\n  # Api文档信息\n  info:\n    title: 认证服务\n    version: 3.0.0\n    description: 认证、登出、验证码接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n# 验证码配置\ncaptcha:\n  # 验证码类型 circle-圆圈干扰验证码|gif-Gif验证码|line-干扰线验证码|shear-扭曲干扰验证码\n  type: circle\n  # 验证码宽度\n  width: 120\n  # 验证码高度\n  height: 40\n  # 验证码干扰元素个数\n  interfere-count: 2\n  # 文本透明度(0.0-1.0)\n  text-alpha: 0.8\n  # 验证码字符配置\n  code:\n    # 验证码字符类型 math-算术|random-随机字符\n    type: math\n    # 验证码字符长度，type=算术时，表示运算位数(1:个位数运算 2:十位数运算)；type=随机字符时，表示字符个数\n    length: 1\n  # 验证码字体\n  font:\n    # 字体名称 Dialog|DialogInput|Monospaced|Serif|SansSerif\n    name: SansSerif\n    # 字体样式 0-普通|1-粗体|2-斜体\n    weight: 1\n    # 字体大小\n    size: 24\n  # 验证码有效期(秒)\n  expire-seconds: 120\n\nsecurity:\n  whitelist-paths:\n    - /api/v1/auth/captcha\n    - /api/v1/auth/sms_code\n# 安全配置\n  session:\n    type: jwt # 会话方式 jwt/redis-token\n    access-token-time-to-live: 7200 # 访问令牌 有效期(单位：秒)，默认 2 小时，-1 表示永不过期\n    refresh-token-time-to-live: 604800 # 刷新令牌有效期(单位：秒)，默认 7 天，-1 表示永不过期\n    jwt:\n      secret-key: SecretKey012345678901234567890123456789012345678901234567890123456789 # JWT密钥(HS256算法至少32字符)\n    redis-token:\n      allow-multi-login: true # 是否允许多设备登录', '2eaec28a4da384a273c9dd85acaa0ed1', '2010-05-05 00:00:00', '2026-03-14 23:01:26', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (208, 425, 'aioveu-auth.yaml', 'AIOVEU_GROUP', '', 'spring:\n  datasource:\n    type: com.alibaba.druid.pool.DruidDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver \n    url: jdbc:mysql://${mysql.host}:${mysql.port}/aioveu_oauth2_server?zeroDateTimeBehavior=convertToNull&useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&autoReconnect=true\n    username: ${mysql.username}\n    password: ${mysql.password}\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n\n \n  cache:\n    # 缓存类型 redis、none(不使用缓存) \n    type: redis\n    # 缓存时间(单位：ms)\n    redis:\n      time-to-live: 3600000\n      # 缓存null值，防止缓存穿透\n      cache-null-values: true\n \nfeign:\n  httpclient:\n    enabled: true\n  okhttp:\n    enabled: false\n  sentinel:  # 开启feign对sentinel的支持\n    enabled: false \n\nmybatis-plus:\n  configuration:\n    # 驼峰下划线转换\n    map-underscore-to-camel-case: true\n    # 这个配置会将执行的sql打印出来，在开发或测试的时候可以用\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n    default-enum-type-handler: org.apache.ibatis.type.EnumOrdinalTypeHandler\n\n# 微信小程序\nwx:\n  miniapp:\n    # appId: wx977b2949b7095b11\n    # appSecret: 4bf78af93a8ce49f2de5384ede86be63\n    appId: wxe510ad6d4d60bfa8\n    appSecret: 1839111563bcf001bae776543c31829f\n\n# springdoc-openapi项目配置\nspringdoc:\n  swagger-ui:\n    path: /swagger-ui.html\n    tags-sorter: alpha\n    operations-sorter: alpha\n  api-docs:\n    path: /v3/api-docs\n  group-configs:\n    - group: \'default\'\n      paths-to-match: \'/**\'\n      packages-to-scan: com.aioveu.auth.controller\n  # Api文档信息\n  info:\n    title: 认证服务\n    version: 3.0.0\n    description: 认证、登出、验证码接口\n    contact:\n      name: aioveu\n      url: https://www.aioveu.com\n      email: ambitiouschild@qq.com\n    license:\n      name: Apache 2.0\n      url: https://www.apache.org/licenses/LICENSE-2.0.html\n\n# knife4j的增强配置，不需要增强可以不配\nknife4j:\n  enable: false\n  setting:\n    language: zh_cn\n\n# 验证码配置\ncaptcha:\n  # 验证码类型 circle-圆圈干扰验证码|gif-Gif验证码|line-干扰线验证码|shear-扭曲干扰验证码\n  type: circle\n  # 验证码宽度\n  width: 120\n  # 验证码高度\n  height: 40\n  # 验证码干扰元素个数\n  interfere-count: 2\n  # 文本透明度(0.0-1.0)\n  text-alpha: 0.8\n  # 验证码字符配置\n  code:\n    # 验证码字符类型 math-算术|random-随机字符\n    type: math\n    # 验证码字符长度，type=算术时，表示运算位数(1:个位数运算 2:十位数运算)；type=随机字符时，表示字符个数\n    length: 1\n  # 验证码字体\n  font:\n    # 字体名称 Dialog|DialogInput|Monospaced|Serif|SansSerif\n    name: SansSerif\n    # 字体样式 0-普通|1-粗体|2-斜体\n    weight: 1\n    # 字体大小\n    size: 24\n  # 验证码有效期(秒)\n  expire-seconds: 120\n\nsecurity:\n  whitelist-paths:\n    - /api/v1/auth/captcha\n    - /api/v1/auth/sms_code\n# 安全配置\n  session:\n    type: jwt # 会话方式 jwt/redis-token\n    access-token-time-to-live: 7200 # 访问令牌 有效期(单位：秒)，默认 2 小时，-1 表示永不过期\n    refresh-token-time-to-live: 604800 # 刷新令牌有效期(单位：秒)，默认 7 天，-1 表示永不过期\n    jwt:\n      secret-key: SecretKey012345678901234567890123456789012345678901234567890123456789 # JWT密钥(HS256算法至少32字符)\n    redis-token:\n      allow-multi-login: true # 是否允许多设备登录', '2eaec28a4da384a273c9dd85acaa0ed1', '2010-05-05 00:00:00', '2026-03-15 16:56:47', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');
INSERT INTO `his_config_info` VALUES (225, 426, 'aioveu-common.yaml', 'AIOVEU_GROUP', '', 'redis:\n  database: 0\n  host: localhost\n  port: 6380\n  password: 775825\n  \nmysql:\n  host: localhost\n  port: 3308\n  username: root\n  password: 775825\n\nrabbitmq:\n  host: localhost\n  port: 5672\n  username: adminlss\n  password: adminlss\n\n\n# 验签公钥地址\nspring:\n  security:\n    oauth2:\n      authorizationserver:\n        token-uri: ${gateway.endpoint}/aioveu-auth/oauth2/token\n      resourceserver:\n        jwt: \n          jwk-set-uri: ${gateway.endpoint}/aioveu-auth/oauth2/jwks\n\n  datasource:    \n    # 以下是新增的 Druid 连接池配置\n    druid:\n      # 1. 连接池基础配置  # 临时调大，缓解问题\n      initial-size: 20\n      min-idle: 20\n      max-active: 100\n      max-wait: 3000  # 3秒超时，避免请求堆积\n      \n      # 2. 连接有效性检测\n      validation-query: SELECT 1\n      test-while-idle: true\n      test-on-borrow: false\n      test-on-return: false\n      time-between-eviction-runs-millis: 60000\n      min-evictable-idle-time-millis: 300000\n      \n      # 3. 连接泄漏检测\n      remove-abandoned: true\n      remove-abandoned-timeout: 180\n      log-abandoned: true\n      \n      # 4. 监控统计\n      # 访问监控页面 ,如果配置了 stat-view-servlet，可以访问 http://你的IP:端口/druid/index.html\n      filters: stat,wall,slf4j\n      stat-view-servlet:\n        enabled: true\n        login-username: aioveu\n        login-password: 775825\n        url-pattern: /druid/*\n        reset-enable: false\n      \n      # 5. Web监控\n      web-stat-filter:\n        enabled: true\n        url-pattern: /*\n        exclusions: \"*.js,*.gif,*.jpg,*.png,*.css,*.ico,/druid/*\"\n      \n      # 6. Filter配置（关键修正点！）\n      # Druid 的 filter 配置是独立的，不是 spring 的子项\n      # 6. 慢SQL记录  开启慢SQL监控\n      filter:\n        stat:\n          enabled: true\n          log-slow-sql: true\n          slow-sql-millis: 2000   # 超过2秒的SQL记录\n          merge-sql: true\n        # SQL防火墙\n        wall:\n          enabled: true\n          config:\n            multi-statement-allow: true\n            none-base-statement-allow: false\n\n  data:\n    redis:\n      database: ${redis.database}\n      host: ${redis.host}\n      port: ${redis.port}\n      password: ${redis.password}\n      lettuce:\n        pool:\n          max-active: 8\n          max-idle: 5\n          min-idle: 2\n          max-wait: 1000ms\n\n# 网关地址\ngateway:\n  endpoint: http://localhost:6699\n\n# Nacos 配置中心地址(Seata RM、TM 注册)\nnacos:\n  server-addr: localhost:8848\n  namespace: a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef\n  group: SEATA_GROUP\n  application: aioveu-seata-server\n  data-id: seataServer.properties\n  username: nacos\n  password: 775825\n\n# 短信配置\nsms:\n  # 阿里云短信\n  aliyun:\n    accessKeyId: LTAI5tSMgfxxxxxxdiBJLyR\n    accessKeySecret: SoOWRqpjtS7xxxxxxZ2PZiMTJOVC\n    domain: dysmsapi.aliyuncs.com \n    regionId: cn-shanghai\n    signName: 可我不敌可爱\n    templateCodes: \n      register: SMS_22xxx771\n      login: SMS_22xxx770\n\n\n# logging:\n#   level:\n#     # 全局设置为WARN，关闭所有INFO\n#     root: WARN\n    \n#     # 按包名精细控制\n#     com.aioveu: WARN      # 你的业务代码\n#     com.baomidou.mybatisplus: ERROR\n#     org.springframework: WARN\n#     org.springframework.jdbc: ERROR\n#     org.hibernate: ERROR\n#     com.alibaba.druid: WARN\n    \n#     # 特别注意：关闭这些详细日志\n#     org.apache.ibatis: ERROR\n#     org.mybatis: ERROR\n    \n#   # 异步日志（减少阻塞）\n#   async:\n#     enabled: true\n#     queue-size: 10000', '6f7a94696bfffe8af1988307cae0cdbb', '2010-05-05 00:00:00', '2026-03-15 16:57:59', 'nacos', '172.18.0.1', 'U', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', '');

-- ----------------------------
-- Table structure for permissions
-- ----------------------------
DROP TABLE IF EXISTS `permissions`;
CREATE TABLE `permissions`  (
  `role` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL,
  `resource` varchar(512) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL,
  `action` varchar(8) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL,
  UNIQUE INDEX `uk_role_permission`(`role` ASC, `resource` ASC, `action` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_bin ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of permissions
-- ----------------------------
INSERT INTO `permissions` VALUES ('ROLE_AIOVEU', ':*:*', 'rw');
INSERT INTO `permissions` VALUES ('ROLE_AIOVEU', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef:*:*', 'rw');

-- ----------------------------
-- Table structure for roles
-- ----------------------------
DROP TABLE IF EXISTS `roles`;
CREATE TABLE `roles`  (
  `username` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL,
  `role` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL,
  UNIQUE INDEX `uk_username_role`(`username` ASC, `role` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_bin ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of roles
-- ----------------------------
INSERT INTO `roles` VALUES ('aioveu', 'ROLE_AIOVEU');
INSERT INTO `roles` VALUES ('nacos', 'ROLE_ADMIN');

-- ----------------------------
-- Table structure for tenant_capacity
-- ----------------------------
DROP TABLE IF EXISTS `tenant_capacity`;
CREATE TABLE `tenant_capacity`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `tenant_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL DEFAULT '' COMMENT 'Tenant ID',
  `quota` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '配额，0表示使用默认值',
  `usage` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '使用量',
  `max_size` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '单个配置大小上限，单位为字节，0表示使用默认值',
  `max_aggr_count` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '聚合子配置最大个数',
  `max_aggr_size` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '单个聚合数据的子配置大小上限，单位为字节，0表示使用默认值',
  `max_history_count` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '最大变更历史数量',
  `gmt_create` datetime NOT NULL DEFAULT '2010-05-05 00:00:00' COMMENT '创建时间',
  `gmt_modified` datetime NOT NULL DEFAULT '2010-05-05 00:00:00' COMMENT '修改时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_tenant_id`(`tenant_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = '租户容量信息表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of tenant_capacity
-- ----------------------------

-- ----------------------------
-- Table structure for tenant_info
-- ----------------------------
DROP TABLE IF EXISTS `tenant_info`;
CREATE TABLE `tenant_info`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `kp` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'kp',
  `tenant_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT '' COMMENT 'tenant_id',
  `tenant_name` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT '' COMMENT 'tenant_name',
  `tenant_desc` varchar(256) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'tenant_desc',
  `create_source` varchar(32) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'create_source',
  `gmt_create` bigint NOT NULL COMMENT '创建时间',
  `gmt_modified` bigint NOT NULL COMMENT '修改时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_tenant_info_kptenantid`(`kp` ASC, `tenant_id` ASC) USING BTREE,
  INDEX `idx_tenant_id`(`tenant_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = 'tenant_info' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of tenant_info
-- ----------------------------
INSERT INTO `tenant_info` VALUES (1, '1', 'a0e9ab31-f2c7-4c10-94a4-9f2f53e5a5ef', 'aioveu-prod', '生产环境命名空间', 'nacos', 1770120525499, 1770120525499);

